INSERT INTO company_profile (id, interest_areas, company_fields, past_tender_categories, triage_dimensions, tender_filters, action_plan_text, action_plan_embedding, updated_at) VALUES (1, '["Inteligencia artificial, machine learning y procesamiento del lenguaje natural aplicados a industria y servicios", "Computación cuántica: simulación, algoritmos de optimización y criptografía cuántica", "Internet de las Cosas (IoT) y territorios inteligentes: smart villages, agricultura de precisión, redes de sensores", "Espacios de datos, gobernanza del dato y data marketplaces (GAIA-X, DataHub)", "Salud digital, teleasistencia, envejecimiento activo y soluciones de atención domiciliaria", "Energía: comunidades energéticas locales, micro-redes, respuesta a la demanda y blockchain energético", "Estándares web, accesibilidad (WCAG), Web of Things y portales de datos abiertos", "Ciberseguridad, ENS y cumplimiento normativo (RGPD)", "Transformación digital de administraciones públicas y PYMES", "Desarrollo de plataformas digitales, microservicios e integración de sistemas", "Realidad aumentada y mixta (WebXR) para formación, salud y turismo", "Inteligencia territorial: sistemas GIS, análisis climático y laboratorios vivientes (living labs)"]', '["Tecnologías de la información y las comunicaciones (TIC)", "Investigación, Desarrollo e Innovación (I+D+i)", "Inteligencia artificial y computación avanzada", "Internet de las Cosas (IoT) y sistemas embebidos", "Consultoría y asesoramiento tecnológico", "Formación y capacitación tecnológica", "Transferencia de conocimiento y tecnología", "Salud digital y tecnologías para el bienestar", "Energía inteligente y sostenibilidad", "Estándares web y accesibilidad (W3C)"]', '["Desarrollo y mantenimiento de plataformas digitales para administraciones públicas", "Consultoría e implantación de soluciones de inteligencia artificial", "Proyectos de investigación europeos (Horizonte Europa, H2020)", "Servicios de ciberseguridad y auditoría ENS", "Formación en competencias digitales para empleados públicos", "Diseño y desarrollo de portales web accesibles", "Análisis de datos y cuadros de mando para AAPP", "Proyectos IoT y despliegue de redes de sensores para territorios inteligentes", "Soluciones de salud digital y telemonitorización de pacientes", "Pilotos de comunidades energéticas locales y gestión de micro-redes", "Espacios de datos federados y plataformas de interoperabilidad", "Simulación y experimentación con computación cuántica"]', '[{"name": "Alineación temática", "weight": 2.0, "description": "En qué medida el objeto y alcance de la licitación encajan con las áreas de interés estratégico de la empresa (IA, IoT, transformación digital, computación cuántica, salud digital, energía inteligente, etc.)."}, {"name": "Encaje de ámbito", "weight": 1.0, "description": "Si el dominio de la licitación pertenece a uno o más campos de negocio declarados por la empresa (TIC, I+D+i, consultoría tecnológica, formación digital, estándares web, etc.)."}, {"name": "Condiciones de ejecución", "weight": 1.0, "description": "Idoneidad global del contrato para la empresa. Considera el lugar de ejecución (penaliza fuera de Asturias), el plazo (penaliza menos de 2 meses), la carga de mantenimiento (penaliza más de 1 año o asistencia técnica pura), y la viabilidad técnica: si los perfiles y certificaciones requeridos (ISO, ENS, PMI u otros) coinciden con las capacidades internas habituales de la empresa."}, {"name": "Criterios de valoración", "weight": 1.0, "description": "Si los criterios de adjudicación favorecen la calidad técnica sobre el precio. Penaliza cuando el peso del precio supera el 50 % de la puntuación total, lo que reduce el margen de diferenciación técnica."}]', '{"contract_type_code": "2", "contract_subtype_codes": ["11", "12", "20", "23", "24", "25", "27", "5", "7", "8", "9"], "cpv_it_services_prefix": "72", "contract_folder_statuses": ["PRE", "PUB"]}', '### Relevant Themes:
1. **Intelligence Artificial (IA)**:
   - IA predictiva y de simulación
   - IA generativa y modelos fundacionales
   - IA adaptativa, cognitiva
   - IA agéntica
   - Tecnologías del Lenguaje Natural (PLN)
   - IA para detección de amenazas y anomalías
   - Explicabilidad y transparencia algorítmica
   - Protección frente a ataques adversarios en modelos de IA
   - Quantum Machine Learning

2. **Internet of Things (IoT)**:
   - Internet de las Cosas (IoT) y sistemas embebidos
   - Edge Computing con IA
   - Datos satelitales
   - Sensorización avanzada
   - Seguridad en dispositivos IoT (firmware seguro, autenticación robusta)
   - Protección de datos en entornos Edge
   - Criptografía post-cuántica

3. **Comunicación de Datos**:
   - Redes LoRaWAN
   - Conectividad 5G/6G y M2M
   - Comunicaciones satelitales (constelaciones satélites órbita baja)
   - Protocolos seguros de comunicación
   - Gestión de identidades y autenticación de redes
   - Redes privadas de comunicaciones en entornos industriales y corporativos
   - Comunicaciones cuánticas

4. **Arquitecturas Avanzadas**:
   - Cloud Computing
   - Arquitecturas distribuidas y descentralizadas (blockchain, DLT, …)
   - Ecosistemas de datos federados y espacios de datos
   - Arquitecturas de computación cuántica y tecnologías emergentes
   - Seguridad en entornos Cloud

5. **Analítica y Visualización**:
   - Ciencia de datos y analítica avanzada
   - Tecnologías para la interoperabilidad y estandarización de datos
   - Computación espacial inteligente y gemelos digitales de territorio
   - Sistemas de información geográfica (GIS) y entornos 3D interactivos
   - Realidad extendida (AR/VR/MR) y plataformas inmersivas
   - Protección de datos sensibles en análisis masivo
   - Seguridad en plataformas de visualización inmersivas

6. **Factor Humano**:
   - IA confiable: explicabilidad y transparencia algorítmica
   - Ética, privacidad y seguridad
   - Interacción humano-máquina (HMI) y humano-robot (HRI) centrada en la persona
   - Reducción de la brecha digital
   - Toma de conciencia en ciberseguridad para usuarios y desarrolladores
   - Diseño ético y seguro de interfaces
   - Políticas de protección de datos y gestión de riesgos

7. **Competencias Técnicas Transversales**:
   - Gestión de proyectos tecnológicos (Scrum, Kanban, PMP)
   - DevOps y MLOps: integración y despliegue continuo
   - Arquitecturas orientadas a datos (Data Lakes, Data Mesh, plataformas seguras de integración)
   - Cumplimiento normativo y estándares internacionales
   - Computación de alto rendimiento (HPC) para simulaciones complejas
   - Automatización y robótica en entornos industriales

### Keywords:
Inteligencia Artificial, Internet de las Cosas, Cloud Computing, Blockchain,
Computación Cuántica, Ciencia de Datos, Realidad Aumentada, Realidad Virtual,
Realidad Mixta, Gemelos Digitales, Computación Espacial Inteligente, Sistemas
de Información Geográfica, Interoperabilidad de Datos, Seguridad en Dispositivos
IoT, Criptografía Post-cuántica, Comunicaciones Satelitales, Redes LoRaWAN,
Conectividad 5G/6G, Gestión de Identidades, Autenticación de Redes, Comunicaciones
Cuánticas, Explicabilidad Algorítmica, Transparencia Algorítmica, Protección de
Datos Sensibles, Diseño Ético de Interfaces, Políticas de Protección de Datos,
Gestión de Riesgos, Scrum, Kanban, PMP, DevOps, MLOps, Data Lakes, Data Mesh,
Cumplimiento Normativo, Computación de Alto Rendimiento, Automatización, Robótica Industrial

### Types of Projects:
1. Research and Development (R&D): new technologies and methodologies in AI, IoT,
   Cloud, Blockchain, Quantum Computing, Data Science, AR/VR/MR, Digital Twins,
   GIS, IoT Security, Post-Quantum Cryptography, Satellite Communications,
   LoRaWAN, 5G/6G, Identity Management, Quantum Communications, DevOps, MLOps,
   Data Lakes, Data Mesh, HPC, Automation, Industrial Robotics.
2. Innovation: applying existing technologies to healthcare, agriculture, energy,
   smart cities.
3. Collaborative Projects: partnerships with universities, research centres,
   private companies.
4. Pilot Projects: small-scale validation before full deployment.
5. Consulting and Advisory: expert guidance on technology adoption.
6. Training and Education: programs, workshops, and materials for tech professionals.
7. Standardization and Certification: standards and certifications for quality and
   interoperability.
8. Community and Social Impact: technology for social and environmental challenges.
9. Infrastructure and Equipment: supporting infrastructure for R&D activities.
10. Policy and Regulatory: influencing frameworks for technology adoption.', '[-0.005774885,-0.004649454,0.023873106,0.044694923,-0.08032194,0.011635722,-0.004182091,-0.002319355,-0.037023727,-0.01953254,0.023980547,-0.027031833,0.05479426,0.049078465,0.05939268,0.037066706,0.012613423,0.06128362,-0.037926223,-0.018243264,-0.0030539741,0.024431793,-0.08767081,-0.005052353,-0.018640792,-0.013236574,0.033456728,-0.00768194,0.02466816,0.028987236,-0.00058789673,-0.030921152,0.028514503,0.001355755,0.015041561,-0.07035153,0.052645463,-0.03597082,-0.183593,0.017834993,-0.041428756,-0.016663902,0.022411926,-0.061971232,0.073961504,-0.01536388,-0.067300245,-0.079161584,0.01677134,-0.008063351,-0.005046981,-0.011743162,-0.04048329,-0.050969403,-0.027010346,0.0047273478,-0.075852446,-0.047488358,-0.00614018,0.07039451,-0.06128362,-0.020520987,0.046156105,-0.038012173,0.028192183,-0.052774392,-0.03732456,-0.009970406,-0.003518651,0.021842496,0.028815333,0.059048872,-0.054923184,0.036980752,-0.06476466,-0.008756338,-0.05947863,-0.018243264,0.005065783,0.07598137,-0.070265576,-0.046156105,0.03981716,0.01866228,-0.025355775,-0.031329423,-0.043018866,0.06313158,0.074176386,-0.0386783,-0.027418617,-0.01154977,0.046585865,-0.060080294,-0.01006173,0.032253403,-0.029868243,0.012860535,-0.044780876,0.06884737,0.022519365,0.034015417,-0.021391248,-0.015954798,0.0037012985,-0.009965034,0.043126304,-0.0048401593,-0.06012327,0.01752342,0.009819991,-0.04389987,0.017598627,0.071382955,0.016792828,-0.04903549,0.044866826,0.050453693,0.005065783,-0.029868243,0.011420842,0.024324354,0.050410718,-0.010722484,0.0290517,-0.06407705,0.010136938,0.039151035,0.07262925,0.005401532,-0.055997584,-0.019575518,0.042331252,-0.016212653,0.039881624,-0.037152655,-0.042051908,-0.021949936,0.047488358,-0.0023851618,0.03296251,-0.009352628,-0.025978925,-0.039279964,0.04774621,0.032683164,0.0067848186,-0.057458762,-0.08522119,-0.002318012,-0.03848491,-0.042266786,-0.009680319,0.053290103,-0.028664919,0.0149663