INSERT INTO tenders (id, link, title, party_name, tax_exclusive_amount, estimated_overall_contract_amount, enrichment, summary, summary_embedding, triage, triage_score, execution_period, pcap_url, ppt_url, submission_deadline, created_at, updated_at) VALUES ('19656230', 'https://contrataciondelestado.es/wps/poc?uri=deeplink:detalle_licitacion&idEvl=OYof0YEX1S6Izo3LHNPGcQ%3D%3D', 'Servicio de consultoría en la gestión del Proyecto Europeo JETSKIR del Programa INTERREG EUROPE', 'Alcaldía del Ayuntamiento de Avilés', '24000', '24000', '{"summary": "El contrato busca servicios de consultoría para la gestión del proyecto europeo JETSKIR del programa INTERREG Europe, enfocado en cooperación territorial. Se requieren perfiles con experiencia en proyectos similares, al menos cuatro relacionados con INTERREG Europe. El presupuesto no está especificado, pero la evaluación considera memoria técnica (45 puntos), oferta económica (40 puntos) y ampliación de personal (15 puntos).", "packages": [{"label": "Servicio de consultoría en la gestión del Proyecto Europeo JETSKIR del Programa INTERREG Europe", "pages": null, "budget": null, "description": "El objeto de este contrato lo constituye el desarrollo de labores de consultoría relacionadas con la gestión del proyecto europeo JETSKIR, del programa INTERREG Europe, que incluye las prestaciones relacionadas en la cláusula 1 del Pliego de Prescripciones Técnicas"}], "outsourcing": {"notes": "Se estará a lo previsto en los artículos 215 y siguientes de la LCSP. A efectos de controlar el cumplimiento de la legislación vigente, el contratista deberá poner en conocimiento del órgano de contratación tras la adjudicación del contrato o a más tardar cuando se inicie la ejecución de éste, la parte del contrato que tengan previsto subcontratar, junto con los importes (sin considerar la baja ofertada) subcontratados en cada caso, nombre o perfil empresarial de la empresa subcontratista y las condiciones de capacidad y solvencia, en su caso, de los subcontratistas.", "pages": [19], "exists": true, "percentage": null}, "discard_review": {"summary": "El contrato se ajustará al contenido del presente pliego, cuyas cláusulas se entenderán parte integrante de aquél. En caso de discrepancia entre el presente pliego y el resto de documentación que reviste carácter contractual, prevalecerá el presente pliego.", "summary_pages": [9], "criteria_flags": {"ens_certification_required": {"applies": false, "evidence": "No se menciona en el documento."}, "iso_certification_required": {"applies": false, "evidence": "No se menciona en el documento."}, "maintenance_longer_than_1_year": {"applies": false, "evidence": "No se menciona en el documento."}, "pmi_certified_profile_required": {"applies": false, "evidence": "No se menciona en el documento."}, "execution_period_under_2_months": {"pages": [9], "applies": false, "evidence": "El plazo total de ejecución del contrato, y, en su caso, los parciales figuran en el apartado 15 del Cuadro de Características del Contrato, en el que se señala, en su caso, su posibilidad de prórroga, sin perjuicio del plazo total que determine la oferta presentada por el licitador que resulte adjudicatario."}, "place_of_execution_not_asturias": {"pages": [9], "applies": false, "evidence": "El contrato se ajustará al contenido del presente pliego, cuyas cláusulas se entenderán parte integrante de aquél."}, "asks_technical_assistance_service": {"applies": false, "evidence": "No se menciona en el documento."}, "economic_offer_weight_over_70_points": {"pages": [3, 4], "applies": false, "evidence": "La ponderación de la oferta económica es de 40 puntos sobre un total de 100 puntos."}}, "potential_discard": false, "reasons_for_manual_review": []}, "execution_period": "2 meses", "economic_solvency": "Medio: Volumen anual de negocios referido al mejor ejercicio dentro de los tres últimos al licitador, referido al año de mayor volumen de negocio de los tres últimos concluidos, que deberá ser igual o superior al valor estimado del contrato.", "required_profiles": "Relación de ocho servicios de consultoría en proyectos de cooperación territorial, calificados como tal por la Unión europea en los últimos 10 años, indicando importe, fechas, destinatario, público o privado de los mismos, al menos cuatro de ellos deberán estar relacionados con convocatorias del programa INTERREG EUROPE.", "scope_of_the_work": "El objeto del contrato al que se refiere el presente pliego es el servicio descrito en el apartado 2 del Cuadro de Características del Contrato y definido en el Pliego de Prescripciones Técnicas Particulares, en el que se especifican los factores de todo orden a tener en cuenta. En el mismo apartado se hace referencia igualmente a las necesidades administrativas a satisfacer mediante el contrato.", "assessment_criteria": "Para la adjudicación del contrato se tendrán en cuenta los criterios objetivos y subjetivos que se indican a continuación, todos ellos relacionados con el objeto y alcance del servicio. Memoria Técnica de los Trabajos a Ejecutar: Hasta 45 puntos. La redacción de una memoria descriptiva técnica de los trabajos a ejecutar tiene por objeto la evaluación del grado de conocimiento del objeto del contrato, el enfoque metodológico de la evaluación para la prestación del servicio de evaluación y la planificación de las dos fases de ejecución del contrato. Oferta Económica: Hasta 40 puntos. Se valorará la oferta económica más ventajosa asignando 40 puntos a la misma, y clasificando las ofertas según la siguiente fórmula: Pi = 40 * (Om / Oi). Amplación Número de Profesionales Asignados al Contrato: Hasta 15 puntos. Se valorará la ampliación de personal al equipo de trabajo mínimo exigido en el Pliego de Prescripciones Técnicas con la incorporación de hasta dos consultores técnicos extra que reúnan los mismos requisitos exigidos en punto 2 de la cláusula tercera del Pliego de Prescripciones Técnicas.", "execution_period_pages": [10], "object_of_the_contract": "El objeto de este contrato lo constituye el desarrollo de labores de consultoría relacionadas con la gestión del proyecto europeo JETSKIR, del programa INTERREG Europe, que incluye las prestaciones relacionadas en la cláusula 1 del Pliego de Prescripciones Técnicas", "economic_solvency_pages": [2], "required_profiles_pages": [2], "scope_of_the_work_pages": [1], "assessment_criteria_pages": [3, 4], "_iman_total_pages_processed": 47, "object_of_the_contract_pages": [1]}', 'El contrato busca servicios de consultoría para la gestión del proyecto europeo JETSKIR del programa INTERREG Europe, enfocado en cooperación territorial. Se requieren perfiles con experiencia en proyectos similares, al menos cuatro relacionados con INTERREG Europe. El presupuesto no está especificado, pero la evaluación considera memoria técnica (45 puntos), oferta económica (40 puntos) y ampliación de personal (15 puntos).', '[-0.045379866,0.0353843,0.0066820355,-0.045219935,-0.014113738,0.049777914,0.010955139,-0.045739707,-0.002828745,0.025788559,0.07880504,-0.011205029,0.014103742,0.022929827,0.0072767716,0.014643503,0.027827654,0.0011557372,0.047658857,0.07788544,0.027747689,0.00426061,-0.004210632,-0.053136423,-0.009705693,-0.0053676185,0.033585098,0.0027462814,0.07348739,0.02121059,0.02336963,-0.023149729,0.022749906,-0.02155044,0.017212363,-0.0139738,0.042541124,-0.052256815,-0.091399446,0.08820087,-0.03624392,-0.06529103,-0.027287893,-0.05605513,0.025968479,0.051017366,0.02422925,-0.0042406186,-0.0074317027,0.008851073,-0.087401226,0.029806776,0.0058823903,-0.088680655,-0.011694811,0.019891175,-0.038043123,0.01167482,-0.006527104,0.01839184,-0.00229898,-0.053336337,-0.005632501,0.004712909,0.048658412,-0.059693515,0.00027878257,0.023289667,-0.014903388,0.004942807,-0.070328794,0.006232235,-0.0028912174,0.04246116,-0.010885171,0.0074167093,-0.053656194,-0.09091966,0.014843415,0.034724593,-0.023669498,0.028307442,-0.048698395,0.11906717,-0.0043605655,0.07160823,-0.04206134,-0.0023489578,0.0