INSERT INTO tenders (id, link, title, party_name, tax_exclusive_amount, estimated_overall_contract_amount, enrichment, summary, summary_embedding, triage, triage_score, execution_period, pcap_url, ppt_url, submission_deadline, created_at, updated_at) VALUES ('19242844', 'https://contrataciondelestado.es/wps/poc?uri=deeplink:detalle_licitacion&idEvl=6NBf29EpLOTpxJFXpLZ%2B2A%3D%3D', 'Servicios de Ciberseguridad de la Autoridad Portuaria de Barcelona', 'Presidencia del Consejo de Administración de la Autoridad Portuaria de Barcelona (PORT DE BARCELONA)', '1068833.62', '2132913.22', '{"summary": "La Autoridad Portuaria de Barcelona busca servicios especializados en ciberseguridad para renovar, mejorar y evolucionar sus capacidades, incluyendo servicios profesionales, suministro y soporte de licencias SaaS. El contrato mixto abarca licencias de software SaaS y proyectos de implantación, con un presupuesto total de 2.132.913,22 €. Se requieren perfiles como gestores de ciberseguridad, analistas de seguridad, arquitectos cloud, ingenieros DevSecOps y equipos SOC. La evaluación considera un 60% calidad técnica y 40% oferta económica.", "packages": [{"label": "Licencias de software en modo SaaS (Software como servicio mediante pago anual) y el servicio recurrente de operación de dicho software", "pages": [2], "budget": "575.969,05 €", "description": null}, {"label": "Proyectos de implantación, que incluyen el despliegue y configuración de soluciones, pruebas, auditorías y formación", "pages": [2], "budget": "1.556.944,17 €", "description": null}], "outsourcing": {"notes": "El contratista se compromete a ejecutar el contrato con criterios de equidad y transparencia fiscal, por lo que los ingresos o beneficios procedentes del presente contrato público serán íntegramente declarados y tributados conforme a la legislación fiscal vigente, prohibiéndose expresamente la utilización de domicilios y su consiguiente tributación en algún país de la lista de paraísos fiscales establecida por la OCDE, bien sea de forma directa o a través de empresas filiales.", "pages": [11], "exists": true, "percentage": null}, "discard_review": {"summary": "El contrato no es susceptible de su división en lotes, dado que el servicio a prestar debe efectuarse de forma unificada. La ejecución de éste debe hacerse de forma homogénea por la misma empresa, en aras de conseguir una mayor eficacia.", "summary_pages": [11], "criteria_flags": {"ens_certification_required": {"pages": [4], "applies": true, "evidence": "La empresa deberá disponer, como mínimo, de las siguientes certificaciones y acreditaciones vigentes: Esquema Nacional de Seguridad (ENS): Certificación en nivel medio o alto."}, "iso_certification_required": {"pages": [4], "applies": true, "evidence": "La empresa deberá disponer, como mínimo, de las siguientes certificaciones y acreditaciones vigentes: ISO/IEC 27001: Gestión de la seguridad de la información."}, "maintenance_longer_than_1_year": {"applies": false, "evidence": "No se menciona explícitamente en el documento."}, "pmi_certified_profile_required": {"applies": false, "evidence": "No se menciona explícitamente en el documento."}, "execution_period_under_2_months": {"pages": [3], "applies": false, "evidence": "El contrato previsto tendrá una duración inicial de dos (2) años, con la posibilidad de 2 prórrogas anuales adicionales, opcionales para la Autoridad Portuaria de Barcelona y obligatorias para el contratista."}, "place_of_execution_not_asturias": {"applies": false, "evidence": "El lugar de ejecución del contrato se especifica en el Pliego de Prescripciones Técnicas."}, "asks_technical_assistance_service": {"pages": [1], "applies": true, "evidence": "El objeto del contrato incluye prestaciones propias del contrato de servicios y del contrato de suministro, por lo que se trata de un contrato mixto."}, "economic_offer_weight_over_70_points": {"pages": [8], "applies": false, "evidence": "Según Anejo núm. 7 del Pliego de Cláusulas Administrativas Particulares, siendo los valores X% (calidad técnica) igual a 60 e Y% (oferta económica) igual a 40."}}, "potential_discard": false, "reasons_for_manual_review": []}, "execution_period": "2 años", "economic_solvency": "El licitador deberá disponer de un volumen anual de negocios en el ejercicio de mayor facturación, dentro de los tres últimos cerrados, igual o superior a 600.000 € (seiscientos mil euros), de conformidad con lo establecido en el artículo 87.1 a) de la LCSP.", "required_profiles": "El adjudicatario del servicio deberá disponer de personal con los siguientes requisitos: Gestor del Servicio de Ciberseguridad (Service Manager), Recursos gestionados de analista de Seguridad y Especialistas en GRC, Arquitecto de Seguridad Cloud, Ingeniero DevSecOps, Equipo del SOC (Centro de Operaciones de Seguridad).", "scope_of_the_work": "El contrato incluye prestaciones propias del contrato de servicios y del contrato de suministro, por lo que se trata de un contrato mixto, de conformidad con lo dispuesto en el art. 18 de la Ley 9/2017, de 8 de noviembre, de Contratos del Sector Público. El régimen jurídico aplicable del contrato de servicios, por ser la prestación principal del contrato, al tener un mayor valor estimado en esta parte (art. 18.1.a), tal como se desglosa en el apartado B del presente Cuadro Resumen de Características.", "assessment_criteria": "Según Anejo núm. 7 del Pliego de Cláusulas Administrativas Particulares, siendo los valores X% (calidad técnica) igual a 60 e Y% (oferta económica) igual a 40.", "execution_period_pages": [3], "object_of_the_contract": "Prestación de servicios especializados para la renovación, mejora y evolución de las capacidades de ciberseguridad de la Autoridad Portuaria de Barcelona, incluyendo servicios profesionales de la Oficina Técnica de Seguridad TIC y suministro y soporte de licencias SaaS necesarias para la plataforma de gestión de ciberseguridad y demás componentes asociados.", "economic_solvency_pages": [4], "required_profiles_pages": [4, 5], "scope_of_the_work_pages": [1], "assessment_criteria_pages": [8], "_iman_total_pages_processed": 88, "object_of_the_contract_pages": [1]}', 'La Autoridad Portuaria de Barcelona busca servicios especializados en ciberseguridad para renovar, mejorar y evolucionar sus capacidades, incluyendo servicios profesionales, suministro y soporte de licencias SaaS. El contrato mixto abarca licencias de software SaaS y proyectos de implantación, con un presupuesto total de 2.132.913,22 €. Se requieren perfiles como gestores de ciberseguridad, analistas de seguridad, arquitectos cloud, ingenieros DevSecOps y equipos SOC. La evaluación considera un 60% calidad técnica y 40% oferta económica.', '[-0.034916874,-0.02967124,0.025904108,-0.045691684,-0.0018278699,0.025458531,0.017620463,-0.024000287,0.025438279,0.07603129,0.059058934,-0.007934272,0.021509118,0.0039721993,0.06213745,0.042127084,0.07112996,-0.06400076,0.038785275,0.015969811,0.050390474,0.0049418313,-0.093894795,-0.023980033,0.055210788,-0.010278604,0.060071602,0.016233105,0.078016125,0.037205506,0.02533701,-0.040770106,0.0077165477,-0.04125619,0.02054708,-0.04941831,0.020516701,-0.036213093,-0.080527544,-0.011676089,-0.02282559,-0.038035896,-0.019483777,-0.055251293,-0.002670918,0.020354673,0.018167306,-0.027969955,-0.08781877,0.00057057646,0.023736993,-0.003825362,0.01753945,-0.05201075,0.08376809,-0.00551399,0.022217987,0.049134765,0.020698981,0.034694087,-0.022866096,-0.045732193,0.023716738,-0.010035563,0.019088836,-0.08259339,0.03977769,-0.024364848,-0.011767229,0.012719139,-0.013488769,0.024547128,-0.018876174,-0.0013607758,-0.051565174,-0.096406214,-0.05452217,-0.096325204,-0.022582548,0.0051747453,-0.033458628,-0.021428104,-0.026612977,0.059058934,-0.10151007,-0.016567286,-0.027726913,0.04196506,0.020567335,0.040446054,0.009584924,0.07121098,-0.009929232,-0.029509213,-0.028050968,-0.008567191,-0.062056437,0.029225666,0.004394989,0.066269144,0.0122128045,-0.06270455,0.045934726,-0.05310443