INSERT INTO tenders (id, link, title, party_name, tax_exclusive_amount, estimated_overall_contract_amount, enrichment, summary, summary_embedding, triage, triage_score, execution_period, pcap_url, ppt_url, submission_deadline, created_at, updated_at) VALUES ('19663549', 'https://contrataciondelestado.es/wps/poc?uri=deeplink:detalle_licitacion&idEvl=KzzefmdK5zU4NavIWzMcHA%3D%3D', 'Servicio de implantación de un ecosistema tecnológico de realidad aumentada, contenidos digitales y señalética accesible
para el centro de interpretación paleontológico Sierra de Quibas (Abanilla).', 'Junta del Ayuntamiento de Abanilla', '26528.93', '26528.93', '{"summary": "El contrato busca la implantación de un ecosistema tecnológico de realidad aumentada, contenidos digitales y señalética accesible para el centro de interpretación paleontológico Sierra de Quibas en Abanilla. Incluye el desarrollo de soluciones digitales móviles, diseño de señalización con códigos QR, creación de escenas 3D y de realidad aumentada, implementación de accesibilidad universal y suministro de hardware. El presupuesto total asciende a 22.549,58 €, con perfiles profesionales requeridos como Project Manager, Experto en UX/UI, Director Técnico, Artista de CGI, Programador 3D y Especialista en Storytelling.", "packages": [{"label": "Actuación 1", "pages": [4], "budget": "8.843,95 €", "description": "Implantación de solución digital móvil para la interpretación del patrimonio."}, {"label": "Actuación 2", "pages": [5], "budget": "4.421,97 €", "description": "Diseño e instalación de señalización física con códigos QR."}, {"label": "Actuación 3", "pages": [5], "budget": "4.421,97 €", "description": "Desarrollo de escenas virtuales 3D y de realidad aumentada."}, {"label": "Actuación 4", "pages": [5], "budget": "3.538,03 €", "description": "Implementación de criterios de accesibilidad universal."}, {"label": "Actuación 5", "pages": [5], "budget": "1.323,66 €", "description": "Suministro de hardware para la digitalización de las rutas guiadas."}], "outsourcing": {"notes": "The document mentions subcontracting regulations but does not specify a maximum percentage.", "pages": [21], "exists": true, "percentage": null}, "discard_review": {"summary": "No se encontraron indicios claros de descarte basados en los criterios especificados.", "criteria_flags": {"ens_certification_required": {"pages": [10], "applies": true, "evidence": "Se requiere certificado Esquema Nacional de Seguridad (ENS) categoría media."}, "iso_certification_required": {"pages": [10], "applies": true, "evidence": "Se requiere certificado de calidad ISO 9001 o equivalente."}, "maintenance_longer_than_1_year": {"applies": false, "evidence": "There is no mention of maintenance or warranty obligations beyond 1 year in the provided pages."}, "pmi_certified_profile_required": {"applies": false, "evidence": "There is no mention of a PMI-certified profile being required in the provided pages."}, "execution_period_under_2_months": {"pages": [3], "applies": false, "evidence": "El contrato tiene una duración de 5 meses, que no es menor a 2 meses."}, "place_of_execution_not_asturias": {"applies": false, "evidence": "The contract is for the implementation of a technological ecosystem in the paleontological interpretation center in Abanilla, which is not in Asturias."}, "asks_technical_assistance_service": {"applies": false, "evidence": "The contract focuses on the implementation of a digital ecosystem and related services, but does not explicitly mention a technical assistance service."}, "economic_offer_weight_over_70_points": {"pages": [16], "applies": false, "evidence": "El peso de la oferta económica es de 20 puntos sobre 100."}}, "reasons_for_manual_review": []}, "execution_period": "5 meses", "economic_solvency": "No se exige constitución de garantía provisional por las empresas interesadas.", "required_profiles": "El equipo de trabajo propuesto deberá estar integrado, al menos, por los siguientes perfiles, cuya experiencia y cualificación se acreditarán mediante contrato de trabajo, CV y relación de trabajos realizados: Project Manager, Experto en UX/UI, Director Técnico, Artista de CGI o equivalente, Programador 3D y Especialista en Storytelling.", "scope_of_the_work": "El contrato comprende la implantación de una solución digital móvil para la interpretación del patrimonio, diseño e instalación de señalización física con códigos QR, desarrollo de escenas virtuales 3D y de realidad aumentada, implementación de criterios de accesibilidad universal y suministro de hardware para la digitalización de las rutas guiadas.", "assessment_criteria": "La valoración de las proposiciones y la determinación de la mejor oferta se atenderá a varios criterios directamente vinculados al objeto del contrato, de conformidad con lo establecido en el artículo 145 de la LCSP. La puntuación máxima a otorgar son 100 puntos. Criterios de adjudicación evaluables mediante la aplicación de fórmulas o porcentajes: 1. Menor precio: Hasta 20 puntos. 2. Mejoras objetivas: Hasta 80 puntos.", "execution_period_pages": [3], "object_of_the_contract": "Servicio de implantación de un ecosistema tecnológico de realidad aumentada, contenidos digitales y señalética accesible para el centro de interpretación paleontológico Sierra de Quibas (Abanilla).", "economic_solvency_pages": [10], "required_profiles_pages": [11, 12], "scope_of_the_work_pages": [4, 5], "assessment_criteria_pages": [16, 17, 18], "_iman_total_pages_processed": 30, "object_of_the_contract_pages": [1]}', 'El contrato busca la implantación de un ecosistema tecnológico de realidad aumentada, contenidos digitales y señalética accesible para el centro de interpretación paleontológico Sierra de Quibas en Abanilla. Incluye el desarrollo de soluciones digitales móviles, diseño de señalización con códigos QR, creación de escenas 3D y de realidad aumentada, implementación de accesibilidad universal y suministro de hardware. El presupuesto total asciende a 22.549,58 €, con perfiles profesionales requeridos como Project Manager, Experto en UX/UI, Director Técnico, Artista de CGI, Programador 3D y Especialista en Storytelling.', '[-0.049301066,0.0014028235,-0.039139934,-0.013901994,0.0021873226,0.0007078526,-0.010413613,0.02384671,-0.020621117,-0.06768591,0.07296228,0.031369656,0.029411629,0.03349257,0.08450433,0.033018522,0.1019823,-0.069334775,0.05713317,-0.00032800177,-0.05329956,-0.021517688,0.008027911,-0.026402451,0.0019155174,0.041489568,0.006286298,-0.021