15,0.010429071,-0.0027721543,0.00044603087,0.014767648,-0.03299791,0.022795558,0.014283293,-0.017240945,-0.007440503,0.009419141,-0.0049929693,0.022527618,-0.013726802,-0.041201014,-0.011315336,0.011459612,0.0324002,-0.005121787,0.077249326,-0.023393271,0.05709195,0.017982934,-0.05940036,0.00545156,0.093655534,-0.001480114,0.00939853,-0.015385971]', '{"dimensions": [{"name": "Alineación temática", "score": 2, "reasoning": "Cosine similarity with action plan: 0.326"}, {"name": "Encaje de ámbito", "score": 4, "reasoning": "La licitación se alinea con áreas de interés como realidad aumentada y accesibilidad, pero no es central en el perfil de la empresa."}, {"name": "Condiciones de ejecución", "score": 3, "reasoning": "El lugar de ejecución no es Asturias, pero el plazo y las certificaciones requeridas son manejables."}, {"name": "Criterios de valoración", "score": 5, "reasoning": "Los criterios de valoración favorecen claramente la calidad técnica sobre el precio."}], "human_summary": "La licitación ofrece una buena oportunidad en realidad aumentada y accesibilidad, aunque fuera de Asturias.", "overall_score": 3.2}', 3.2, '5 meses', 'https://contrataciondelestado.es/FileSystem/servlet/GetDocumentByIdServlet?cifrado=QUC1GjXXSiLkydRHJBmbpw%3D%3D&DocumentIdParam=8YDbHYFrwvM7/fQSAxIgoVAY%2BWTNyRKtji3yyoa4YcO5a1%2Bgwq757pdT/1q%2Bz5YotPYLXBKdRwGXC7/NYqGDJShJ2w21T2vzIA327vX6Q6u1aXEvq3KHa/AEHgtDrQw0', 'https://contrataciondelestado.es/FileSystem/servlet/GetDocumentByIdServlet?cifrado=QUC1GjXXSiLkydRHJBmbpw%3D%3D&DocumentIdParam=N0NeduyZ/nhkP473HXJIYYPq06g0COEtwTB1B6mFoAGefmNHxLB3CRvP7i5N3hzon9Yk90JOn7CSdin8SKY%2BS8NQ4fOvRbDSh8lipqb7WMLVTD3T98KC0nSgQFM0q%2B5s', '2026-05-29T19:00:00', '2026-05-13 06:29:49.152530+00:00', '2026-05-13 07:42:48.542925+00:00')
  ON CONFLICT (id) DO UPDATE SET link = EXCLUDED.link, title = EXCLUDED.title, party_name = EXCLUDED.party_name, tax_exclusive_amount = EXCLUDED.tax_exclusive_amount, estimated_overall_contract_amount = EXCLUDED.estimated_overall_contract_amount, enrichment = EXCLUDED.enrichment, summary = EXCLUDED.summary, summary_embedding = EXCLUDED.summary_embedding, triage = EXCLUDED.triage, triage_score = EXCLUDED.triage_score, execution_period = EXCLUDED.execution_period, pcap_url = EXCLUDED.pcap_url, ppt_url = EXCLUDED.ppt_url, submission_deadline = EXCLUDED.submission_deadline, created_at = EXCLUDED.created_at, updated_at = EXCLUDED.updated_at;
INSERT INTO tenders (id, link, title, party_name, tax_exclusive_amount, estimated_overall_contract_amount, enrichment, summary, summary_embedding, triage, triage_score, execution_period, pcap_url, ppt_url, submission_deadline, created_at, updated_at) VALUES ('19672395', 'https://contrataciondelestado.es/wps/poc?uri=deeplink:detalle_licitacion&idEvl=zog2lyHI9s87%2B9FIQYNjeQ%3D%3D', 'El contrato tendrá por objeto la prestación de servicios técnicos especializados en materia de protección de datos de carácter personal, derechos digitales, sistema interno de información y seguridad informática, requeridos por la AIReF, de acuerdo con la definición y planificación de actividades recogidas en el Pliego de Prescripciones Técnicas Particulares.', 'Presidencia de la Autoridad Independiente de Responsabilidad Fiscal', '59100', '59100', '{"summary": "El contrato busca servicios técnicos especializados en protección de datos, derechos digitales, sistemas de información y seguridad informática, con un enfoque en asesoramiento, consultoría, verificación, control, simulacros de ataques y concienciación. Se requieren perfiles como consultores en derecho con certificación de Delegado de Protección de Datos, ingenieros informáticos con certificaciones CISA o ISO 27001, y técnicos en seguridad informática. El presupuesto total asciende a 71.511,00 €, distribuido en dos lotes: 38.841,00 € para el Lote 1 y 32.670,00 € para el Lote 2.", "packages": [{"label": "Lote 1", "pages": [2], "budget": "38.841,00 €", "description": "Servicios de asesoramiento y consultoría, servicios de verificación y control"}, {"label": "Lote 2", "pages": [2], "budget": "32.670,00 €", "description": "Servicios de simulacros de ataques informáticos y concienciación sobre protección de datos y seguridad informática"}], "outsourcing": {"notes": "El contratista podrá concertar con terceros la realización parcial de la prestación objeto del contrato, conforme a los artículos 215 y 216 de la LCSP y cláusula 23 de este pliego.", "pages": [10], "exists": true, "percentage": null}, "discard_review": {"summary": "El contrato no establece un plazo de garantía del servicio una vez agotado su plazo de ejecución. La ejecución del contrato se realizará en Madrid, en las dependencias de la empresa adjudicataria, sin perjuicio de las actividades que deban realizarse en la sede de la AIReF. El contrato no menciona la necesidad de un servicio de asistencia técnica, pero sí requiere la certificación en el Esquema Nacional de Seguridad, como mínimo, de nivel Medio. No se menciona la certificación ISO ni la certificación ENS como requisitos obligatorios. No se menciona la necesidad de un perfil certificado PMI. El peso de la oferta económica en los criterios de evaluación no supera el 70% de los puntos.", "summary_pages": [9, 10], "criteria_flags": {"ens_certification_required": {"applies": false, "evidence": "No se menciona la certificación ENS como requisito obligatorio."}, "iso_certification_required": {"applies": false, "evidence": "No se menciona la certificación ISO como requisito obligatorio."}, "maintenance_longer_than_1_year": {"pages": [9], "applies": false, "evidence": "No se establece plazo de garantía del servicio una vez agotado su plazo de ejecución."}, "pmi_certified_profile_required": {"applies": false, "evidence": "No se menciona la necesidad de un perfil certificado PMI."}, "execution_period_under_2_months": {"pages": [9], "applies": false, "evidence": "La duración del contrato será de 36 meses."}, "place_of_execution_not_asturias": {"pages": [9], "applies": true, "evidence": "La ejecución del contrato se realizará en Madrid, en las dependencias de la empresa adjudicataria, sin perjuicio de las actividades que deban realizarse en la sede de la AIReF."}, "asks_technical_assistance_service": {"applies": false, "evidence": "No se menciona la necesidad de un servicio de asistencia técnica."}, "economic_offer_weight_over_70_points": {"pages": [9], "applies": false, "evidence": "El peso de la oferta económica en los criterios de evaluación no supera el 70% de los puntos."}}, "potential_discard": false, "reasons_for_manual_review": ["El contrato no menciona la necesidad de un servicio de asistencia técnica."]}, "execution_period": "36", "economic_solvency": "El volumen anual de negocios del licitador en el ámbito de actividades correspondientes al objeto del contrato, referido al año de mayor volumen de negocio de los tres últimos concluidos, deberá ser, al menos, igual o superior al valor estimado del lote o lotes respecto del que presente oferta (IVA excluido). Para el lote 1: 32.100,00 €. Para el lote 2: 27.000,00 €.", "required_profiles": "Para el lote 1: un coordinador o responsable de la ejecución del contrato que actúe como interlocutor ante los órganos de gestión y dirección de la AIReF y un equipo de, al menos, 2 técnicos: un consultor licenciado en Derecho con experiencia mínima acreditada de 5 años y Certificado de conformidad con el esquema de certificación de Delegado de Protección de Datos, y un consultor con titulación de Ingeniería Informática con experiencia mínima de 5 años y acreditaciones como Auditor de Sistemas de Información con certificación CISA o Lead Auditor ISO 27001. Para el lote 2: un coordinador o responsable de la ejecución del contrato que actúe como interlocutor ante los órganos de gestión y dirección de la AIReF y un técnico con experiencia mínima acreditada de 5 años y certificaciones como Consultor o auditor en entornos tecnológicos o Auditor de Sistemas de Información con certificación CISA.", "scope_of_the_work": "Servicios de asesoramiento y consultoría, servicios de verificación y control, servicios de simulacros de ataques informáticos y concienciación sobre protección de datos y seguridad informática.", "assessment_criteria": "Criterios no evaluables mediante fórmulas: hasta 25 puntos. Criterios evaluables mediante fórmulas: hasta 75 puntos. Se apreciará la existencia de ofertas anormalmente bajas por parte del órgano de contratación conforme a lo previsto en la cláusula 17 de este pliego.", "execution_period_pages": [9], "object_of_the_contract": "La prestación de servicios técnicos especializados en materia de protección de datos de carácter personal, derechos digitales, sistema interno de información (SIINF) y seguridad informática.", "economic_solvency_pages": [7], "required_profiles_pages": [7], "scope_of_the_work_pages": [1], "assessment_criteria_pages": [9], "_iman_total_pages_processed": 51, "object_of_the_contract_pages": [1]}', 'El contrato busca servicios técnicos especializados en protección de datos, derechos digitales, sistemas de información y seguridad informática, con un enfoque en asesoramiento, consultoría, verificación, control, simulacros de ataques y concienciación. Se requieren perfiles como consultores en derecho con certificación de Delegado de Protección de Datos, ingenieros informáticos con certificaciones CISA o ISO 27001, y técnicos en seguridad informática. El presupuesto total asciende a 71.511,00 €, distribuido en dos lotes: 38.841,00 € para el Lote 1 y 32.670,00 € para el Lote 2.', '[-0.06344084,-0.008331759,-0.028383594,-0.029722443,-0.051494185,0.033182852,0.03586055,-0.051041037,0.026982952,-0.008620126,0.071144365,0.015736623,-0.02576769,0.0016001818,0.05532535,0.048734095,0.052194506,-0.05701436,0.02442884,-0.0028012837,0.05446025,-0.02062857,-0.03145265,-0.027662676,-0.007332772,-0.02099933,0.033697795,0.0013607338,0.106531166,0.023501946,0.0053347973,-0.06385279,0.05355395,-0.047745407,0.029372282,-0.0018138826,0.056602407,-0.07551107,-0.08197874,0.0020507558,0.024717208,-0.028898535,-0.038455855,-0.050505497,0.04407902,0.034192137,-0.011884858,-0.10488336,-0.020669766,-0.009696355,0.016725311,-0.012255616,0.044944122,-0.06389398,0.05322439,-0.010690193,0.025232151,-0.015334968,0.0060866126,0.054501444,0.022554453,-0.03001081,-0.0038569144,-0.0009552171,0.058662176,-0.08716936,0.026859367,-0.019372111,0.017034275,0.0541306