INSERT INTO tenders (id, link, title, party_name, tax_exclusive_amount, estimated_overall_contract_amount, enrichment, summary, summary_embedding, triage, triage_score, execution_period, pcap_url, ppt_url, submission_deadline, created_at, updated_at) VALUES ('19672577', 'https://contrataciondelestado.es/wps/poc?uri=deeplink:detalle_licitacion&idEvl=vZ1XNAEEiEaGCFcHcNGIlQ%3D%3D', 'Contratación del servicio de consultoría y asistencia técnica para la gestión y optimización de la facturación energética del Ayuntamiento de Siero y sus Organismos Autónomos.', 'Alcaldía del Ayuntamiento de Siero', '15000', '60000', '{"summary": "El Ayuntamiento de Siero busca contratar un servicio de consultoría y asistencia técnica para la gestión y optimización de la facturación energética, incluyendo la gestión de puntos de suministro, importación de facturas, informes de seguimiento y validación de facturas. Se requiere experiencia acreditada y al menos un técnico con titulación en Ingeniería Industrial. El presupuesto no está especificado, pero los criterios de adjudicación incluyen 49 puntos para la baja respecto al PBL y 51 puntos para el criterio de calidad.", "packages": [{"label": "Oferta Ayuntamiento (IVA excluido)", "pages": null, "budget": null, "description": null}, {"label": "Oferta PDM (IVA excluido)", "pages": null, "budget": null, "description": null}, {"label": "Oferta FMC (IVA excluido)", "pages": null, "budget": null, "description": null}, {"label": "IVA (total 3 organismos)", "pages": null, "budget": null, "description": null}, {"label": "OFERTA TOTAL (IVA INCLUIDO)", "pages": null, "budget": null, "description": null}], "outsourcing": {"notes": "El contratista podrá concertar con terceros la realización parcial del mismo siempre que se cumplan los requisitos establecidos en el apartado 2 del artículo 215 de la LCSP. La infracción de las condiciones establecidas en el citado apartado para proceder a la subcontratación, así como la falta de acreditación de la aptitud del subcontratista o de las circunstancias determinantes de la situación de emergencia o de las que hacen urgente la subcontratación, tendrán las siguientes consecuencias: a) Las legalmente previstas en la LCSP y b) La imposición al contratista de una penalidad de hasta un 50% del importe del subcontrato.", "pages": [26], "exists": true, "percentage": null}, "discard_review": {"summary": "El contrato se ejecutará en el Principado de Asturias, específicamente en el Ayuntamiento de Siero. La duración del contrato es de 1 año con posibilidad de prórroga, lo que no implica mantenimiento más allá de 1 año. El contrato no solicita un servicio de asistencia técnica continuo, sino un servicio de consultoría y optimización. No se menciona la necesidad de certificaciones ISO, ENS o perfiles certificados PMI. El peso de la oferta económica es del 49%, lo que no supera el 70% del total de la puntuación.", "summary_pages": [3, 20], "criteria_flags": {"ens_certification_required": {"applies": false, "evidence": "No se menciona la necesidad de certificaciones ENS en el documento."}, "iso_certification_required": {"applies": false, "evidence": "No se menciona la necesidad de certificaciones ISO en el documento."}, "maintenance_longer_than_1_year": {"pages": [20], "applies": false, "evidence": "El contrato no implica mantenimiento más allá de 1 año."}, "pmi_certified_profile_required": {"applies": false, "evidence": "No se menciona la necesidad de perfiles certificados PMI en el documento."}, "execution_period_under_2_months": {"pages": [20], "applies": false, "evidence": "La duración del contrato es de 1 año con posibilidad de prórroga."}, "place_of_execution_not_asturias": {"pages": [3, 20], "applies": false, "evidence": "El contrato se ejecutará en el Principado de Asturias, específicamente en el Ayuntamiento de Siero."}, "asks_technical_assistance_service": {"pages": [3], "applies": false, "evidence": "El contrato solicita un servicio de consultoría y optimización, no un servicio de asistencia técnica continuo."}, "economic_offer_weight_over_70_points": {"pages": [14, 15, 16, 17], "applies": false, "evidence": "El peso de la oferta económica es del 49%, lo que no supera el 70% del total de la puntuación."}}, "potential_discard": false, "reasons_for_manual_review": []}, "execution_period": "12 meses", "economic_solvency": "La aportación de la documentación a la que se refiere el presente Anexo I, podrá ser sustituida por: Debida cumplimentación del formulario del Documento Europeo Único de Contratación (DEUC), cuyas instrucciones figuran en el anexo V de estos pliegos. No obstante lo anterior, el órgano de contratación podrá recabar, en cualquier momento anterior a la adopción de la propuesta de adjudicación, que los licitadores aporten la documentación acreditativa del cumplimiento de las condiciones establecidas para ser adjudicatario del contrato. Todo ello sin perjuicio de que el licitador a cuyo favor recaiga la propuesta de adjudicación, deberá acreditar ante el órgano de contratación, previamente a la adjudicación del contrato, la posesión y validez de los documentos exigidos. Se recuerda que la no acreditación por el propuesto adjudicatario de la documentación a la que hace referencia el presente Anexo I, puede ser declarado en prohibición para contratar (artículo 71.2.a). Las circunstancias relativas a la capacidad, solvencia y ausencia de prohibiciones de contratación deberán concurrir a la fecha final de presentación de ofertas y subsistir en el momento de perfeccionar el contrato.", "required_profiles": "Se exige acreditar, en el año de mayor ejecución de los tres (3) últimos años citados, un importe anual acumulado de 30.000€, importe correspondiente al 50 % del valor estimado del contrato -sin IVA; mediante certificados de buena ejecución. Se deberá tener en plantilla al menos un técnico con titulación: Ingeniero Industrial o Ingeniero Técnico Industrial y se aportará documentación justificativa acreditativa de los títulos académicos y profesionales aparte de su Curriculum. Cuando el contratista sea una empresa de nueva creación; se eximirá a la misma de acreditar lo relacionado con la experiencia de la empresa.", "scope_of_the_work": "El servicio incluye la gestión de puntos de suministro, importación de facturas, informes de seguimiento, validación de facturas y un informe de situación con objetivos de optimización.", "assessment_criteria": "Los criterios de adjudicación evaluables mediante fórmulas matemáticas y su baremación de puntuación a aplicar para valorar las distintas ofertas presentadas y proceder a la adjudicación será el siguiente: 100 puntos en total. 49 puntos para la baja respecto al PBL, 51 puntos para el criterio de calidad, que incluye mejoras valorables, históricos y adquisición y envío de datos.", "execution_period_pages": [20], "object_of_the_contract": "Servicio de consultoría y asistencia técnica para la gestión y optimización de la facturación energética del Ayuntamiento de Siero y sus Organismos Autónomos.", "economic_solvency_pages": [31, 32, 33, 34], "required_profiles_pages": [33, 34], "scope_of_the_work_pages": [3], "assessment_criteria_pages": [14, 15, 16, 17], "_iman_total_pages_processed": 52, "object_of_the_contract_pages": [3]}', 'El Ayuntamiento de Siero busca contratar un servicio de consultoría y asistencia técnica para la gestión y optimización de la facturación energética, incluyendo la gestión de puntos de suministro, importación de facturas, informes de seguimiento y validación de facturas. Se requiere experiencia acreditada y al menos un técnico con titulación en Ingeniería Industrial. El presupuesto no está especificado, pero los criterios de adjudicación incluyen 49 puntos para la baja respecto al PBL y 51 puntos para el criterio de calidad.', '[-0.042572174,0.07151499,0.06199793,0.038361955,0.0048221704,-0.056279868,0.0124642085,-0.008856148,-0.010545132,0.044687077,0.09916536,-0.022891846,0.008087538,0.018887242,0.047076132,0.03166477,0.025