-0.013942681,0.0484469,-0.0035101483,0.006423033,0.006246791,0.015284076,-0.03209558,0.0022923667,-0.03450422,-0.043081317,0.025907539,-0.011759241,0.021442747,-0.021403583,-0.0142853735,0.007872132,0.009982137,0.006099923,-0.05921723,-0.016038,-0.028864482,0.010280769,-0.047076132,0.00013248729,0.023361824,0.0067755166,-0.0013438434,-0.06908677,-0.028179098,-0.019337637,-0.06344703,0.026690835,-0.07186747,0.01896557,-0.02357723,0.041044746,-0.039341077,-0.014941384,-0.0055809887,0.029275713,-0.011161977,0.004268967,0.029451955]', '{"dimensions": [{"name": "Alineación temática", "score": 1, "reasoning": "Cosine similarity with action plan: 0.263"}, {"name": "Encaje de ámbito", "score": 4, "reasoning": "La licitación se alinea con los campos de negocio de consultoría tecnológica y energía inteligente."}, {"name": "Condiciones de ejecución", "score": 5, "reasoning": "El contrato se ejecuta en Asturias, tiene una duración adecuada y no requiere certificaciones específicas."}, {"name": "Criterios de valoración", "score": 4, "reasoning": "El peso del precio es del 49%, lo que permite una buena diferenciación técnica."}], "human_summary": "La licitación encaja bien con la experiencia en consultoría tecnológica y energía, y se ejecuta en Asturias con criterios de valoración favorables.", "overall_score": 3.0}', 3.0, '12 meses', 'https://contrataciondelestado.es/FileSystem/servlet/GetDocumentByIdServlet?cifrado=QUC1GjXXSiLkydRHJBmbpw%3D%3D&DocumentIdParam=RaPICmiMWqI90/g0I%2BlzWfR5BVxOvyfkYG5FH4e/Yw0yuw/ysnUrCJx9W6gFoi1Yq/%2BKFaKUafLfknwKfTfF64KdDpNq/zLT8/4zjjMq5tNt/o8fNevwsujgRzaBbugn', 'https://contrataciondelestado.es/FileSystem/servlet/GetDocumentByIdServlet?cifrado=QUC1GjXXSiLkydRHJBmbpw%3D%3D&DocumentIdParam=2Zyw2FTOWij2EcaCb0l16AjGI24IZfcP1YaKKVxAcwaCNWtGiDQIu5AdMSjSt7lj8vk0JU/GAq0EPt5DWPVOiDF9ArMIcEfrxcKvXqgXUppt/o8fNevwsujgRzaBbugn', '2026-05-28T14:00:00', '2026-05-14 06:12:35.135825+00:00', '2026-05-14 07:15:26.559574+00:00')
  ON CONFLICT (id) DO UPDATE SET link = EXCLUDED.link, title = EXCLUDED.title, party_name = EXCLUDED.party_name, tax_exclusive_amount = EXCLUDED.tax_exclusive_amount, estimated_overall_contract_amount = EXCLUDED.estimated_overall_contract_amount, enrichment = EXCLUDED.enrichment, summary = EXCLUDED.summary, summary_embedding = EXCLUDED.summary_embedding, triage = EXCLUDED.triage, triage_score = EXCLUDED.triage_score, execution_period = EXCLUDED.execution_period, pcap_url = EXCLUDED.pcap_url, ppt_url = EXCLUDED.ppt_url, submission_deadline = EXCLUDED.submission_deadline, created_at = EXCLUDED.created_at, updated_at = EXCLUDED.updated_at;
INSERT INTO tenders (id, link, title, party_name, tax_exclusive_amount, estimated_overall_contract_amount, enrichment, summary, summary_embedding, triage, triage_score, execution_period, pcap_url, ppt_url, submission_deadline, created_at, updated_at) VALUES ('19617509', 'https://contrataciondelestado.es/wps/poc?uri=deeplink:detalle_licitacion&idEvl=OiAPJ8wectyLAncw3qdZkA%3D%3D', 'Servicios y suministros para la implantación del Proyecto Turismo Inteligente y Patrimonio Cultural de Jaraicejo', 'Alcaldía del Ayuntamiento de Jaraicejo', '21209', '21209', '{"summary": "El contrato busca servicios y suministros para implementar el Proyecto Turismo Inteligente y Patrimonio Cultural de Jaraicejo, incluyendo una Oficina de Turismo Inteligente con plataforma digital, contenidos accesibles y panelería. Los perfiles requeridos incluyen desarrollo de software, producción audiovisual, y equipamiento de señalización, con un presupuesto total de 21.199,00 €. Se valorarán criterios como oferta económica, reducción de plazos, mejoras técnicas, gestión medioambiental, metodología, calidad técnica, y accesibilidad.", "packages": [{"label": "Servicios", "pages": [4], "budget": "18.985,00 €", "description": "Servicios de desarrollo de software, producción audiovisual, producción de audioguías y equipamiento de señalización."}, {"label": "Suministro", "pages": [4], "budget": "2.214,00 €", "description": "Equipamiento de señalización y otros suministros relacionados."}], "outsourcing": {"notes": "El contratista podrá subcontratar hasta un máximo del 50% del importe de adjudicación del contrato, sin que pueda subcontratarse la totalidad de las prestaciones objeto del contrato.", "pages": [19], "exists": true, "percentage": "máximo 50%"}, "discard_review": {"summary": "El contrato no se descartará por los criterios de lugar de ejecución, período de ejecución, mantenimiento, asistencia técnica, certificaciones ISO y ENS, perfil certificado PMI, y peso de la oferta económica.", "summary_pages": [3, 4, 7, 8, 9, 10, 12, 13, 19], "criteria_flags": {"ens_certification_required": {"pages": [7, 8, 9, 10], "applies": false, "evidence": "No se exige explícitamente la certificación ENS en los requisitos del contrato."}, "iso_certification_required": {"pages": [7, 8, 9, 10], "applies": false, "evidence": "No se exige explícitamente la certificación ISO en los requisitos del contrato."}, "maintenance_longer_than_1_year": {"pages": [3, 20], "applies": true, "evidence": "El plazo de garantía es de dos años para servicios y suministros."}, "pmi_certified_profile_required": {"pages": [7, 8, 9, 10], "applies": false, "evidence": "No se exige explícitamente un perfil certificado PMI en los requisitos del contrato."}, "execution_period_under_2_months": {"pages": [3], "applies": false, "evidence": "El plazo de ejecución es de tres meses, que no es menor a dos meses."}, "place_of_execution_not_asturias": {"pages": [3], "applies": false, "evidence": "El lugar de ejecución es Jaraicejo, que no está en Asturias."}, "asks_technical_assistance_service": {"pages": [2, 4], "applies": false, "evidence": "No se menciona explícitamente la prestación de un servicio de asistencia técnica."}, "economic_offer_weight_over_70_points": {"pages": [12, 13], "applies": false, "evidence": "El peso de la oferta económica es de 45 puntos sobre un total de 100 puntos."}}, "potential_discard": false, "reasons_for_manual_review": []}, "execution_period": "3 meses", "economic_solvency": "La solvencia económica y financiera del empresario deberá acreditarse por uno o varios de los medios siguientes: volumen anual de negocios en el ámbito al que se refiera el contrato, justificante de la existencia de un seguro de responsabilidad civil por riesgos profesionales, relación de los principales servicios y/o suministros realizados de igual o similar naturaleza, muestras, descripciones y fotografías de los elementos a suministrar, indicación del personal técnico o de las unidades técnicas, descripción de las instalaciones técnicas, declaración indicando la maquinaria, material y equipo técnico del que se disponrá para la ejecución de los trabajos o prestaciones, y otros documentos que acrediten la capacidad y solvencia económica, financiera, técnica y profesional exigida para este contrato.", "required_profiles": "Podrán presentar proposiciones las personas naturales o jurídicas, españolas o extranjeras, que tengan plena capacidad de obrar, no estén incursas en prohibiciones de contratar, y acrediten su solvencia económica, financiera y técnica o profesional. La capacidad de obrar de los empresarios y la no concurrencia de prohibiciones de contratar se acreditará mediante la inscripción en el Registro Oficial de Licitadores y Empresas Clasificadas del Sector Público. La solvencia técnica de los empresarios deberá acreditarse por uno o varios de los medios siguientes: relación de los principales servicios y/o suministros realizados de igual o similar naturaleza, muestras, descripciones y fotografías de los elementos a suministrar, indicación del personal técnico o de las unidades técnicas, descripción de las instalaciones técnicas, declaración indicando la maquinaria, material y equipo técnico del que se disponrá para la ejecución de los trabajos o prestaciones.", "scope_of_the_work": "La ejecución del proyecto “Turismo Inteligente y Patrimonio Cultural de Jaraicejo”, que incluye la implantación de una Oficina de Turismo Inteligente, incluyendo plataforma digital, contenidos accesibles y panelería.", "assessment_criteria": "Para la valoración de las proposiciones y la determinación de la mejor oferta se atenderá a una pluralidad de criterios de adjudicación con base en la mejor relación calidad-precio. A) CRITERIOS EVALUABLES MEDIANTE FÓRMULAS (75 PUNTOS): 1. Oferta económica (hasta 45 puntos): El precio ofertado no podrá ser superior al previsto en el presente Pliego. Se asignará el máximo de puntuación (45 puntos) a la oferta de precio inferior con respecto al presupuesto base de licitación, asignándose la puntuación al resto de las ofertas presentadas mediante la regla de proporcionalidad inversa. 2. Reducción del plazo de ejecución (hasta 10 puntos): Se valorará la reducción del plazo de ejecución sobre el máximo establecido (tres meses), conforme a la siguiente escala: 2 puntos por cada semana de reducción del plazo, hasta un máximo de 10 puntos. 3. Mejoras técnicas cuantificables (hasta 15 puntos): Se valorarán las mejoras adicionales sin coste para la Administración, conforme a los siguientes criterios: incorporación de idiomas adicionales (mínimo 1): 5 puntos, incremento del número de recursos turísticos (mínimo 5 adicionales): 5 puntos. 4. Mejora en gestión medioambiental (hasta 5 puntos): Se valorará la implantación de sistemas de gestión medioambiental en la empresa licitadora: certificación ISO 14001 o EMAS: 5 puntos, sistemas equivalentes debidamente acreditados: 5 puntos, no acreditación: 0 puntos. B) CRITERIOS EVALUABLES MEDIANTE JUICIO DE VALOR (25 PUNTOS): 1. Metodología y plan de trabajo (hasta 10 puntos): Se valorará: claridad y coherencia de la metodología propuesta, adecuación al objeto del contrato, organización de fases y cronograma. 2. Calidad técnica de la solución (hasta 10 puntos): Se valorará: arquitectura tecnológica propuesta, usabilidad de la plataforma, integración entre APP, web y sistemas físicos. 3. Accesibilidad e inclusión (hasta 5 puntos): Se valorará: nivel de cumplimiento de estándares de accesibilidad (WCAG 2.1), calidad de los contenidos accesibles (lectura fácil, lengua de signos), enfoque inclusivo de la solución.", "execution_period_pages": [3], "object_of_the_contract": "Servicios y suministros para la implantación del Proyecto Turismo Inteligente y Patrimonio Cultural de Jaraicejo, para la implantación de una Oficina de Turismo Inteligente, incluyendo plataforma digital, contenidos accesibles y panelería.", "economic_solvency_pages": [7, 8, 9, 10], "required_profiles_pages": [7, 8, 9, 10], "scope_of_the_work_pages": [2, 4], "assessment_criteria_pages": [12, 13], "_iman_total_pages_processed": 26, "object_of_the_contract_pages": [2, 4]}', 'El contrato busca servicios y suministros para implementar el Proyecto Turismo Inteligente y Patrimonio Cultural de Jaraicejo, incluyendo una Oficina de Turismo Inteligente con plataforma digital, contenidos accesibles y panelería. Los perfiles requeridos incluyen desarrollo de software, producción audiovisual, y equipamiento de señalización, con un presupuesto total de 21.199,00 €. Se valorarán criterios como oferta económica, reducción de plazos, mejoras técnicas, gestión medioambiental, metodología, calidad técnica, y accesibilidad.', '[-0.025821526,0.054546993,0.015618491,-0.0012618897,0.013754475,-0.0036470944,-0.018385082,-0.039144333,-0.034965012,-0.06282715,0.04987714,-0.01654069,0.0024501998,0.015147582,0.05725472,0.08790307,0.07977988,0.03261047,0.032080695,0.021858038,0.089158826,-0.013734854,0.0020700388,-0.04163623,-0.01335224,-0.011448982,0.0295888,-0.007411916,0.12133762,0.026312057,-0.01929747,-0.052820325,0.0014715915,-0.0019351428,-0.04195017,-0.07511003,0.048699867,-0.027293118,-0.07263776,0.029098269,0.015657734,0.023270767,-0.035102364,-0.018954098,-0.0009730899,-0.01751194,-0.053251993,0.003853117,-0.027371602,0.006048241,-0.018708833,0.017610045,0.070322454,-0.014686483,0.00530754,-0.03667206,-0.057529416,0.019856675,-0.008147712,0.08327246,-0.050465778,-0.07483533,0.01222402,0.009295553,0.041400775,-0.03779047,-0.021210538,0.023015691,-0.021190917,0.033061754,-0.04948472,-0.0087314425,-0.006210116,0.053251993,-0.0007983384,-0.04147926,-0.10360004,-0.040125396,-0.0014262174,0.016256182,-0.028529255,-0.01737459,-0.044108503,0.07338336,-0.009226879,-0.02411448,-0.02107319,0.024094857,0.03520047,-0.029353345,-0.026567131,0.0030780789,0.034180164,0.0063425596,-0.046776988,-0.004235731,-0.015628302,-0.061885327,-0.009045382,0.027587436,0.045442745,-0.07020473,0.024487283,0.017659098,0.0279602