INSERT INTO eu_items (reference, kind, url, identifier, title, status, start_date, deadline_date, metadata, embed_text, embedding, triage, triage_score, framework_programme, programme_period, programme_division, programme_part, mission_group, created_at, updated_at) VALUES ('50142710TOPICSen', 'horizon-topic', 'https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL3-2027-02-CS-ECCC-01', '50142710', 'Artificial Intelligence for Cybersecurity applications', 'Forthcoming', '2027-03-02T00:00:00.000+0000', '2027-09-15T00:00:00.000+0000', '{"url": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL3-2027-02-CS-ECCC-01", "tags": ["AI Act", "AI-based  cybersecurity applications", "AI-driven  cyber threat intelligence", "AI-enhanced SOC frameworks", "Security Operation Centres/Cyber Hubs", "adaptive AI systems", "adaptive cyber defence", "automated threat detection", "generative AI", "trustworthy AI"], "title": "Artificial Intelligence for Cybersecurity applications", "ccm2Id": "50142710", "status": "31094501", "esST_URL": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL3-2027-02-CS-ECCC-01", "keywords": ["HORIZON-CL3-2027-02-CS-ECCC-01", "HORIZON-CL3-2027-02-CS-ECCC", "Artificial Intelligence & Decision support", "Artificial intelligence", "Artificial intelligence, intelligent systems, multi agent systems", "Cybersecurity Domains", "Security Management and Governance", "Threats and vulnerabilities modelling"], "language": "en", "REFERENCE": "50142710TOPICSen", "callTitle": "Indirectly Managed Action by the ECCC (2027)", "startDate": "2027-03-02T00:00:00.000+0000", "DATASOURCE": "SEDIA", "callccm2Id": "50222270", "identifier": "HORIZON-CL3-2027-02-CS-ECCC-01", "es_SortDate": "2027-03-02T00:00:00.000+0000", "deadlineDate": "2027-09-15T00:00:00.000+0000", "deadlineModel": "single-stage", "typesOfAction": "HORIZON  Research and Innovation Actions", "budgetOverview": "{\"budgetYearsColumns\":[\"2027\"],\"budgetTopicActionMap\":{\"113425\":[{\"action\":\"HORIZON-CL3-2027-02-CS-ECCC-03 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":3,\"minContribution\":3000000,\"maxContribution\":4000000,\"budgetYearMap\":{\"2027\":\"19000000\"},\"plannedOpeningDate\":\"2027-03-02\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-09-15\"]}],\"113424\":[{\"action\":\"HORIZON-CL3-2027-02-CS-ECCC-02 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":5,\"minContribution\":3000000,\"maxContribution\":4000000,\"budgetYearMap\":{\"2027\":\"24000000\"},\"plannedOpeningDate\":\"2027-03-02\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-09-15\"]}],\"113423\":[{\"action\":\"HORIZON-CL3-2027-02-CS-ECCC-01 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":5,\"minContribution\":4000000,\"maxContribution\":5000000,\"budgetYearMap\":{\"2027\":\"24800000\"},\"plannedOpeningDate\":\"2027-03-02\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-09-15\"]}],\"113422\":[{\"action\":\"HORIZON-CL3-2027-02-CS-ECCC-04 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":1,\"minContribution\":4000000,\"maxContribution\":4000000,\"budgetYearMap\":{\"2027\":\"4000000\"},\"plannedOpeningDate\":\"2027-03-02\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-09-15\"]}]}}", "es_ContentType": "text/plain", "descriptionByte": "Expected Outcome: Proposals are expected to contribute to one or more of the following: AI-driven solutions for real-time cyber threat detection; Advanced adaptive AI systems that evolve with dynamic cybersecurity challenges; Contribute to drastically reduce reaction time for the recovery of systems. Scope: Artificial Intelligence is increasingly utilised in cybersecurity for threat detection, incident response, and adaptive defence mechanisms. However, AI-driven systems themselves are susceptible to adversarial manipulation and bias. This topic aims to advance AI-based cybersecurity applications while ensuring that AI-driven solutions remain resilient, transparent, and compliant with regulatory frameworks such as the AI Act. In this context, the topic explores the role of all types of AI, including generative AI, in cybersecurity applications, including automated threat detection, adaptive cyber defence, and AI-driven cyber threat intelligence. Proposals should develop solutions for trustworthy AI in cybersecurity contexts including addressing adversarial AI risks, in compliance with the provisions of the AI Act. The topic is expected to: Develop AI-driven solutions and tools for real-time cyber threat detection. Investigating novel machine learning techniques to detect anomalies, malicious activity, and AI-powered cyber threats in real time, improving situational awareness and response times. Develop adaptive AI systems capable of evolving with dynamic cybersecurity challenges. Exploring AI techniques that continuously learn from new cyber threats, adapting to emerging attack patterns, while maintaining robustness and explainability. Support the future enhancements of Security Operation Centres/Cyber Hubs. Developing AI-enhanced SOC frameworks that integrate predictive analytics, automation, and threat intelligence to strengthen proactive defence measures.", "programmePeriod": "2021 - 2027", "programmeDivision": ["43108390", "43108541", "43118971", "43120185"], "frameworkProgramme": "43108390"}', 'Expected Outcome: Proposals are expected to contribute to one or more of the following: AI-driven solutions for real-time cyber threat detection; Advanced adaptive AI systems that evolve with dynamic cybersecurity challenges; Contribute to drastically reduce reaction time for the recovery of systems. Scope: Artificial Intelligence is increasingly utilised in cybersecurity for threat detection, incident response, and adaptive defence mechanisms. However, AI-driven systems themselves are susceptible to adversarial manipulation and bias. This topic aims to advance AI-based cybersecurity applications while ensuring that AI-driven solutions remain resilient, transparent, and compliant with regulatory frameworks such as the AI Act. In this context, the topic explores the role of all types of AI, including generative AI, in cybersecurity applications, including automated threat detection, adaptive cyber defence, and AI-driven cyber threat intelligence. Proposals should develop solutions for trustworthy AI in cybersecurity contexts including addressing adversarial AI risks, in compliance with the provisions of the AI Act. The topic is expected to: Develop AI-driven solutions and tools for real-time cyber threat detection. Investigating novel machine learning techniques to detect anomalies, malicious activity, and AI-powered cyber threats in real time, improving situational awareness and response times. Develop adaptive AI systems capable of evolving with dynamic cybersecurity challenges. Exploring AI techniques that continuously learn from new cyber threats, adapting to emerging attack patterns, while maintaining robustness and explainability. Support the future enhancements of Security Operation Centres/Cyber Hubs. Developing AI-enhanced SOC frameworks that integrate predictive analytics, automation, and threat intelligence to strengthen proactive defence measures.', '[-0.016686488,-0.020321866,0.05031122,0.023201972,-0.09151889,-0.02616264,0.017884852,0.0014803341,-0.010130722,0.05538665,0.017169861,-0.06529582,-0.0010567522,0.011268666,0.031580463,0.05309062,0.06239558,0.00073198497,0.021631004,-0.09530532,0.0503515,0.049143065,-0.060945455,-0.0142696155,-0.01910336,0.014037998,0.04592057,-0.011973587,0.030996384,0.09965569,0.036051676,-0.04833744,-0.008227435,0.025719546,0.04934447,-0.038106017,0.029344855,-0.0054127863,-0.062315017,0.050875157,-0.009209289,-0.038790796,0.050875157,-0.0292240