INSERT INTO eu_items (reference, kind, url, identifier, title, status, start_date, deadline_date, metadata, embed_text, embedding, triage, triage_score, framework_programme, programme_period, programme_division, programme_part, mission_group, created_at, updated_at) VALUES ('50142752TOPICSen', 'horizon-topic', 'https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL3-2027-02-CS-ECCC-03', '50142752', 'Secure PQC implementations, Cryptanalysis and Post-quantum Digital Trust', 'Forthcoming', '2027-03-02T00:00:00.000+0000', '2027-09-15T00:00:00.000+0000', '{"url": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL3-2027-02-CS-ECCC-03", "tags": null, "title": "Secure PQC implementations, Cryptanalysis and Post-quantum Digital Trust", "ccm2Id": "50142752", "status": "31094501", "esST_URL": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL3-2027-02-CS-ECCC-03", "keywords": ["HORIZON-CL3-2027-02-CS-ECCC-03", "HORIZON-CL3-2027-02-CS-ECCC"], "language": "en", "REFERENCE": "50142752TOPICSen", "callTitle": "Indirectly Managed Action by the ECCC (2027)", "startDate": "2027-03-02T00:00:00.000+0000", "DATASOURCE": "SEDIA", "callccm2Id": "50222270", "identifier": "HORIZON-CL3-2027-02-CS-ECCC-03", "es_SortDate": "2027-03-02T00:00:00.000+0000", "deadlineDate": "2027-09-15T00:00:00.000+0000", "deadlineModel": "single-stage", "typesOfAction": "HORIZON  Research and Innovation Actions", "budgetOverview": "{\"budgetYearsColumns\":[\"2027\"],\"budgetTopicActionMap\":{\"113425\":[{\"action\":\"HORIZON-CL3-2027-02-CS-ECCC-03 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":3,\"minContribution\":3000000,\"maxContribution\":4000000,\"budgetYearMap\":{\"2027\":\"19000000\"},\"plannedOpeningDate\":\"2027-03-02\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-09-15\"]}],\"113424\":[{\"action\":\"HORIZON-CL3-2027-02-CS-ECCC-02 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":5,\"minContribution\":3000000,\"maxContribution\":4000000,\"budgetYearMap\":{\"2027\":\"24000000\"},\"plannedOpeningDate\":\"2027-03-02\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-09-15\"]}],\"113423\":[{\"action\":\"HORIZON-CL3-2027-02-CS-ECCC-01 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":5,\"minContribution\":4000000,\"maxContribution\":5000000,\"budgetYearMap\":{\"2027\":\"24800000\"},\"plannedOpeningDate\":\"2027-03-02\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-09-15\"]}],\"113422\":[{\"action\":\"HORIZON-CL3-2027-02-CS-ECCC-04 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":1,\"minContribution\":4000000,\"maxContribution\":4000000,\"budgetYearMap\":{\"2027\":\"4000000\"},\"plannedOpeningDate\":\"2027-03-02\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-09-15\"]}]}}", "es_ContentType": "text/plain", "descriptionByte": "Expected Outcome: Proposals are expected to contribute one or more of the following: Practical robust implementations of PQC schemes that can withstand implementation attacks including side-channel attacks, fault attacks and combined attacks, and design of automated tools for evaluating the security of PQC implementations. Comprehensive guidelines for implementing countermeasures against a wide range of attacks; Advances in understanding the quantum hardness of mathematical problem classes; new quantum algorithms and improvements in quantum programming and implementation; security validation methods; design of post-quantum schemes with improved security against quantum and AI-based attacks; Post-quantum schemes and protocols to support privacy-friendly applications and services, ncluding the secure and private use of electronic identities. Design of new digital signatures, key encapsulation mechanisms, and other schemes or use of existing ones to build new verification protocols. Scope: Securing PQC algorithm implementations is vital to protect against implementation attacks, such as side channel attacks, fault attacks and combinations of these, which may be amplified by deep learning. Current countermeasures incur significant overhead, and new approaches are needed to balance security and performance. Formal verification tools and methodologies can help achieve this goal and provide machine-readable evidence. Furthermore, to boost confidence in PQC systems, their security should be assessed, including the potential impact of new quantum algorithms or new optimizations of existing ones, also combined with AI. Another key research area is digital trust in the post-quantum era, which requires transforming various areas, such as secure identities, data protection, access to essential services, and applications such as backup recovery, browser extensions and others into trusted and reliable solutions, via new post-quantum schemes and advanced building blocks for privacy-enhancing protocols. Proposals should address one of the following technology areas: Development of solutions to prevent implementation attacks, balancing security, performance and cost; research in new attacks, including AI-powered ones, and/or combination of attacks, to inform secure design; creation of testing frameworks for automated security evaluations; improvement of formal verification methodologies. Quantum hardness analysis, via the study of the impact of new quantum algorithms or improvement of existing quantum algorithm implementations as well as the impact of AI-supported quantum attacks; analysis of cryptanalysis results; design of new post-quantum schemes using the information of the advances achieved/ fine-tuning of parameters sets. Design of quantum-resistant schemes and protocols supporting the field of privacy-friendly applications and services, including electronic identities, verification protocols and pseudonymous access options, protocols for attestation and anonymous attestation, for real world scenarios, via the design of new digital signature schemes and key encapsulation mechanisms, design of advanced cryptographic schemes, and usage of existing schemes in new protocols, for post-quantum digital identity and digital trust systems.", "programmePeriod": "2021 - 2027", "programmeDivision": ["43108390", "43108541", "43118971", "43120185"], "frameworkProgramme": "43108390"}', 'Expected Outcome: Proposals are expected to contribute one or more of the following: Practical robust implementations of PQC schemes that can withstand implementation attacks including side-channel attacks, fault attacks and combined attacks, and design of automated tools for evaluating the security of PQC implementations. Comprehensive guidelines for implementing countermeasures against a wide range of attacks; Advances in understanding the quantum hardness of mathematical problem classes; new quantum algorithms and improvements in quantum programming and implementation; security validation methods; design of post-quantum schemes with improved security against quantum and AI-based attacks; Post-quantum schemes and protocols to support privacy-friendly applications and services, ncluding the secure and private use of electronic identities. Design of new digital signatures, key encapsulation mechanisms, and other schemes or use of existing ones to build new verification protocols. Scope: Securing PQC algorithm implementations is vital to protect against implementation attacks, such as side channel attacks, fault attacks and combinations of these, which may be amplified by deep learning. Current countermeasures incur significant overhead, and new approaches are needed to balance security and performance. Formal verification tools and methodologies can help achieve this goal and provide machine-readable evidence. Furthermore, to boost confidence in PQC systems, their security should be assessed, including the potential impact of new quantum algorithms or new optimizations of existing ones, also combined with AI. Another key research area is digital trust in the post-quantum era, which requires transforming various areas, such as secure identities, data protection, access to essential services, and applications such as backup recovery, browser extensions and others into trusted and reliable solutions, via new post-quantum schemes and advanced building blocks for privacy-enhancing protocols. Proposals should address one of the following technology areas: Development of solutions to prevent implementation attacks, balancing security, performance and cost; research in new attacks, including AI-powered ones, and/or combination of attacks, to inform secure design; creation of testing frameworks for automated security evaluations; improvement of formal verification methodologies. Quantum hardness analysis, via the study of the impact of new quantum algorithms or improvement of existing quantum algorithm implementations as well as the impact of AI-supported quantum attacks; analysis of cryptanalysis results; design of new post-quantum schemes using the information of the advances achieved/ fine-tuning of parameters sets. Design of quantum-resistant schemes and protocols supporting the field of privacy-friendly applications and services, including electronic identities, verification protocols and pseudonymous access options, protocols for attestation and anonymous attestation, for real world scenarios, via the design of new digital signature schemes and key encapsulation mechanisms, design of advanced cryptographic schemes, and usage of existing schemes in new protocols, for post-quantum digital identity and digital trust systems.', '[0.002347889,0.038552046,0.039181296,0.042495348,-0.079201594,0.063512295,0.091367096,-0.0013987701,-0.034734596,-0.009512162,0.083816096,-0.025925098,0.0042788996,-0.010990899,-0.011704049,0.027330423,0.0661132,0.017545586,-0.024289047,-0.06