INSERT INTO eu_items (reference, kind, url, identifier, title, status, start_date, deadline_date, metadata, embed_text, embedding, triage, triage_score, framework_programme, programme_period, programme_division, programme_part, mission_group, created_at, updated_at) VALUES ('50147283TOPICSen', 'horizon-topic', 'https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL3-2026-02-CS-ECCC-02', '50147283', 'Enhancing the Security, Privacy and Robustness of AI Models and Systems (SecureAI)', 'Open', '2026-03-03T00:00:00.000+0000', '2026-09-15T00:00:00.000+0000', '{"url": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL3-2026-02-CS-ECCC-02", "tags": ["AI Act", "AI transparency", "Private AI", "adversarial  training", "adversarial attacks", "anomaly  detection", "automated data validation", "federated learning techniques", "privacy-preserving environment", "provenance tracking", "quantum-safe homomorphic encryption", "real-time anomaly detection", "resilience of AI systems", "secure aggregation", "security and robustness of AI systems"], "title": "Enhancing the Security, Privacy and Robustness of AI Models and Systems (SecureAI)", "ccm2Id": "50147283", "status": "31094502", "esST_URL": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL3-2026-02-CS-ECCC-02", "keywords": ["HORIZON-CL3-2026-02-CS-ECCC-02", "HORIZON-CL3-2026-02-CS-ECCC", "Artificial Intelligence & Decision support", "Artificial intelligence", "Artificial intelligence, intelligent systems, multi agent systems", "Cybersecurity", "Cybersecurity Domains", "Data Security and Privacy", "Security Management and Governance", "Security support in programming environments"], "language": "en", "REFERENCE": "50147283TOPICSen", "callTitle": "Indirectly Managed Action by the ECCC (2026)", "startDate": "2026-03-03T00:00:00.000+0000", "DATASOURCE": "SEDIA", "callccm2Id": "50147368", "identifier": "HORIZON-CL3-2026-02-CS-ECCC-02", "es_SortDate": "2026-03-03T00:00:00.000+0000", "deadlineDate": "2026-09-15T00:00:00.000+0000", "deadlineModel": "single-stage", "typesOfAction": "HORIZON Innovation Actions", "budgetOverview": "{\"budgetYearsColumns\":[\"2026\"],\"budgetTopicActionMap\":{\"113179\":[{\"action\":\"HORIZON-CL3-2026-02-CS-ECCC-03 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":4,\"minContribution\":2000000,\"maxContribution\":3000000,\"budgetYearMap\":{\"2026\":\"15000000\"},\"plannedOpeningDate\":\"2026-03-03\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2026-09-15\"]}],\"113178\":[{\"action\":\"HORIZON-CL3-2026-02-CS-ECCC-01 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":5,\"minContribution\":3000000,\"maxContribution\":4000000,\"budgetYearMap\":{\"2026\":\"20000000\"},\"plannedOpeningDate\":\"2026-03-03\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2026-09-15\"]}],\"113180\":[{\"action\":\"HORIZON-CL3-2026-02-CS-ECCC-02 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":5,\"minContribution\":3000000,\"maxContribution\":4000000,\"budgetYearMap\":{\"2026\":\"21200000\"},\"plannedOpeningDate\":\"2026-03-03\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2026-09-15\"]}]}}", "es_ContentType": "text/plain", "descriptionByte": "Expected Outcome: Proposals are expected to contribute to one or more of the following: Robust AI models and systems capable of resisting different classes of adversarial manipulation; Innovative defence mechanisms for AI models and systems against new attack families; Methodologies for detecting and mitigating attacks, such as data poisoning, backdoor exploitation and misclassification; AI systems leveraging privacy-enhancing technologies that maintain data confidentiality and regulatory compliance, enabling trusted in-house AI deployments (e.g., for governments and enterprises). Scope: The increasing reliance on AI in cybersecurity, critical infrastructure, and decision-making processes raises concerns about the security and robustness of AI systems. As AI systems become more prevalent, they are increasingly targeted by adversarial attacks that manipulate inputs, compromise training data, or introduce hidden vulnerabilities. This topic aims to strengthen the resilience of AI systems and algorithms against various threats and attacks, such as enhancing their resilience against adversarial attacks, backdoor injections, and data poisoning. Proposals should develop real-time anomaly detection, mitigation techniques to defend against adversarial attacks and robust federated learning techniques, in synergies with leading efforts on AI transparency, and in compliance with the AI Act. The topic is expected to: Develop robust AI models resistant to adversarial attacks. Exploring techniques to harden AI models and systems against adversarial perturbations, such as adversarial training, robust optimisation, and defence mechanisms that enhance the trustworthiness of AI. Improve detection of manipulated or poisoned training data. Advancing methodologies to identify and mitigate compromised datasets, leveraging techniques such as anomaly detection, provenance tracking, and automated data validation mechanisms. Address the concept of Private AI by developing mechanisms that enable AI models to be trained, deployed and operated in privacy-preserving environments, particularly for sensitive use cases, as for example for government and enterprise settings. This includes ensuring AI computations and data remain within trusted execution boundaries (e.g. on-premise or regulated cloud environments), and leveraging existing and emerging privacy-enhancing techniques such as federated learning, secure aggregation, computing on encrypted data, quantum-safe homomorphic encryption and secure inference in deep learning to safeguard the protection of personal and other sensitive data throughout the AI lifecycle.", "programmePeriod": "2021 - 2027", "programmeDivision": ["43108390", "43108541", "43118971", "43120185"], "frameworkProgramme": "43108390"}', 'Expected Outcome: Proposals are expected to contribute to one or more of the following: Robust AI models and systems capable of resisting different classes of adversarial manipulation; Innovative defence mechanisms for AI models and systems against new attack families; Methodologies for detecting and mitigating attacks, such as data poisoning, backdoor exploitation and misclassification; AI systems leveraging privacy-enhancing technologies that maintain data confidentiality and regulatory compliance, enabling trusted in-house AI deployments (e.g., for governments and enterprises). Scope: The increasing reliance on AI in cybersecurity, critical infrastructure, and decision-making processes raises concerns about the security and robustness of AI systems. As AI systems become more prevalent, they are increasingly targeted by adversarial attacks that manipulate inputs, compromise training data, or introduce hidden vulnerabilities. This topic aims to strengthen the resilience of AI systems and algorithms against various threats and attacks, such as enhancing their resilience against adversarial attacks, backdoor injections, and data poisoning. Proposals should develop real-time anomaly detection, mitigation techniques to defend against adversarial attacks and robust federated learning techniques, in synergies with leading efforts on AI transparency, and in compliance with the AI Act. The topic is expected to: Develop robust AI models resistant to adversarial attacks. Exploring techniques to harden AI models and systems against adversarial perturbations, such as adversarial training, robust optimisation, and defence mechanisms that enhance the trustworthiness of AI. Improve detection of manipulated or poisoned training data. Advancing methodologies to identify and mitigate compromised datasets, leveraging techniques such as anomaly detection, provenance tracking, and automated data validation mechanisms. Address the concept of Private AI by developing mechanisms that enable AI models to be trained, deployed and operated in privacy-preserving environments, particularly for sensitive use cases, as for example for government and enterprise settings. This includes ensuring AI computations and data remain within trusted execution boundaries (e.g. on-premise or regulated cloud environments), and leveraging existing and emerging privacy-enhancing techniques such as federated learning, secure aggregation, computing on encrypted data, quantum-safe homomorphic encryption and secure inference in deep learning to safeguard the protection of personal and other sensitive data throughout the AI lifecycle.', '[0.022629956,-0.017024852,0.07601989,0.04609806,-0.0880892,0.007978108,0.08368893,0.001517831,-0.021184154,0.054647155,-0.00595084,-0.047397185,0.017223911,-0.03419638,0.03570504,0.02780551,0.06369913,0.002252519,-0.076732315,-0.09789552,-0.030005647,0.075014114,-0.060011294,-0.04358362,-0.038512833,0.008680055,0.028496983,0.015359036,0.009497248,0.07396643,0.04266166,-0.022210883,-0.008889591,0.03015232,0.032184828,-0.06587832,0.084736615,-0.02242042,-0.09144179,-0.002450269,-0.011933112,0.010445401,-0.010461116,-0.07002714,0.046349503,-0.023237612,-0.014971392,-0.055904374,0.034908805,-0.0060032248,0.024264343,0.053850915,-0.03597744,-0.003716656,0.056197725,-0.012865549,0.022839494,0.050246883,-0.000938986,0.060011294,0.034280192,-0.024725324,-0.0013076395,-0.06931472,0.04672667,-0.07241586,-0.015296174,-0.0011616187,0.034280192,-0.037842315,0.034175426,0.01167119,-0.058670256,0.04781626,-0.08725105,0.026192078,-0.09873366,0.04672667,-0.009151513,-0.006626596,-0.060095105,-0.020545067,0.043960787,-0.041823514,0.0039681,-0.05473097,0.0070770998,0.017003898,0.02304903,0.0024856282,-0.009890129,-0.018365886,0.053850915,-0.040461525,0.007532842,0.011084488,0.009486771,-0.00