INSERT INTO eu_items (reference, kind, url, identifier, title, status, start_date, deadline_date, metadata, embed_text, embedding, triage, triage_score, framework_programme, programme_period, programme_division, programme_part, mission_group, created_at, updated_at) VALUES ('51121692TOPICSen', 'non-horizon-topic', 'https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/DIGITAL-2026-AI-DATA-10-COMPLIANCE', '51121692', 'Digital solutions for regulatory compliance  through data', 'Open', '2026-04-21T00:00:00.000+0000', '2026-10-01T00:00:00.000+0000', '{"url": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/DIGITAL-2026-AI-DATA-10-COMPLIANCE", "tags": ["advanced digital technologies", "cloud storage", "data capturing technologies", "data security", "digital solutions", "regulatory compliance through data", "regulatory reporting requirements", "reporting process"], "title": "Digital solutions for regulatory compliance  through data", "ccm2Id": "51121692", "status": "31094502", "esST_URL": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/DIGITAL-2026-AI-DATA-10-COMPLIANCE", "keywords": ["DIGITAL-2026-AI-DATA-10-COMPLIANCE", "DIGITAL-2026-AI-DATA-10", "Artificial intelligence", "Cloud, Edge and Virtualisation", "Digital Services and Platforms"], "language": "en", "REFERENCE": "51121692TOPICSen", "callTitle": "AI Continent", "startDate": "2026-04-21T00:00:00.000+0000", "DATASOURCE": "SEDIA", "callccm2Id": "51121715", "identifier": "DIGITAL-2026-AI-DATA-10-COMPLIANCE", "es_SortDate": "2026-04-21T00:00:00.000+0000", "deadlineDate": "2026-10-01T00:00:00.000+0000", "deadlineModel": "single-stage", "typesOfAction": "DIGITAL Lump Sum Grants", "budgetOverview": "{\"budgetYearsColumns\":[\"2027\"],\"budgetTopicActionMap\":{\"114323\":[{\"action\":\"DIGITAL-2026-AI-DATA-10-COMPLIANCE - DIGITAL-LS DIGITAL Lump Sum Grants\",\"expectedGrants\":2,\"minContribution\":0,\"maxContribution\":0,\"budgetYearMap\":{\"2027\":\"8500000\"},\"plannedOpeningDate\":\"2026-04-21\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2026-10-01\"]}]}}", "es_ContentType": "text/plain", "descriptionByte": "Expected Impact: The objective is to deliver three to four projects that demonstrate the streamlining of regulatory reporting through automated and trusted sharing of compliance data. Each project will address the governance, technical, legal, and processing aspects of the solution. Objective: Specific Objective 2 of the Digital Europe Programme aims to reinforce the EU’s core Artificial Intelligence (AI) capacities as a crucial driver for the digital transformation of the public and private sectors. The vision is to make Europe an AI continent, thriving on the development, integration and adoption of AI. As one of the financial instruments of the upcoming Apply AI Strategy, SO2 will support the development of world class AI models in the EU and foster the integration of AI technologies into EU’s most strategic sectors, including healthcare, energy and research. It will stimulate new industrial uses of AI and improve the delivery of various public services. In addition, it will support the deployment of new digital solutions for regulatory compliance through data. The objective is to reduce the administrative burden of enterprises by applying advanced digital technologies to automatise the reporting process. Objectives This objective will support projects testing digital solutions for transmitting information relevant for compliance with EU legislation (e.g. regulations on environmental issues) and automate the compliance process for a number of pilot use cases. These projects will target regulatory reporting requirements, from aggregate data (e.g., company balance sheets) to detailed data (e.g., transactions, events, and product registrations). The aim is to leverage advanced technologies, including data capturing technologies, automatic transmission, analysis, cloud storage, and encryption, to ensure data security, confidentiality, and regulatory compliance. The strong focus should be given to privacy-preserving technologies to ensure trust between the reporting entity and regulatory authorities, safeguarding data confidentiality while enabling secure and efficient compliance processes. Additionally, the projects will identify burdensome administrative challenges in the selected sectors that could be addressed by automated data-driven solutions, while close collaboration with reporting entities will be essential to enable direct communication with regulatory agencies for automated updates and ensure compliance with evolving regulations. The approach will prioritize access controls and audit trails to enhance transparency and reduce the risk of non-compliance and penalties. Furthermore, the projects could incorporate the European Digital Identity Wallet, when available, to securely identify individuals and legal entities in data spaces, alongside trust services like electronic seals and ledgers. Scope: The activities funded under this initiative will focus on the following aspects: Technical aspects: Utilize advanced technologies such as privacy-preserving technologies, data capturing technologies, automatic transmission and analysis, cloud storage and encryption for data security and compliance with regulations. Implement comprehensive APIs to enable real-time compliance and self-compliance checks. Employ machine learning algorithms for automated monitoring and reporting. Where possible, use precisely defined concepts available in the data catalogue entries of Common European Data Spaces enabling deterministic data collection. Establish direct communication channels with regulatory authorities for automated updates and reporting, keeping the system updated with changing regulations (e.g. by expressing the reporting requirements in machine readable and executable way). Ensure robust access control and maintain audit trails for transparency and accountability. Minimize the risk of non-compliance and potential penalties through these technological and procedural safeguards. Integrate the European Digital Identity Wallet for secure identification of individuals and legal entities, when available. Collaborate with providers of data space services and technology, with a particular emphasis on open-source solutions, such as the European Commission''s Simpl programme. All systems must incorporate robust data privacy and security measures. Proposers must ensure that the systems developed are open source, interoperable with existing government data systems and adhere to European data standards and specifications. The system must be scalable to handle large volumes of data and high transaction rates. The system must be designed with end-users in mind, ensuring ease of use and accessibility. A comprehensive data governance framework must be established. This should include policies for data quality management, data stewardship, and data lifecycle management. Proposals should target legislations that have clear, quantifiable compliance metrics that can be automatically assessed using data analytics and they should ensure no overlaps with ongoing initiatives (e.g. Digital Product Passport, Customs reform). This call aims to explore sectors with significant administrative burden such as agriculture, environment, manufacturing, healthcare and energy.", "programmePeriod": "2021 - 2027", "programmeDivision": "43152869", "frameworkProgramme": "43152860"}', 'Expected Impact: The objective is to deliver three to four projects that demonstrate the streamlining of regulatory reporting through automated and trusted sharing of compliance data. Each project will address the governance, technical, legal, and processing aspects of the solution. Objective: Specific Objective 2 of the Digital Europe Programme aims to reinforce the EU’s core Artificial Intelligence (AI) capacities as a crucial driver for the digital transformation of the public and private sectors. The vision is to make Europe an AI continent, thriving on the development, integration and adoption of AI. As one of the financial instruments of the upcoming Apply AI Strategy, SO2 will support the development of world class AI models in the EU and foster the integration of AI technologies into EU’s most strategic sectors, including healthcare, energy and research. It will stimulate new industrial uses of AI and improve the delivery of various public services. In addition, it will support the deployment of new digital solutions for regulatory compliance through data. The objective is to reduce the administrative burden of enterprises by applying advanced digital technologies to automatise the reporting process. Objectives This objective will support projects testing digital solutions for transmitting information relevant for compliance with EU legislation (e.g. regulations on environmental issues) and automate the compliance process for a number of pilot use cases. These projects will target regulatory reporting requirements, from aggregate data (e.g., company balance sheets) to detailed data (e.g., transactions, events, and product registrations). The aim is to leverage advanced technologies, including data capturing technologies, automatic transmission, analysis, cloud storage, and encryption, to ensure data security, confidentiality, and regulatory compliance. The strong focus should be given to privacy-preserving technologies to ensure trust between the reporting entity and regulatory authorities, safeguarding data confidentiality while enabling secure and efficient compliance processes. Additionally, the projects will identify burdensome administrative challenges in the selected sectors that could be addressed by automated data-driven solutions, while close collaboration with reporting entities will be essential to enable direct communication with regulatory agencies for automated updates and ensure compliance with evolving regulations. The approach will prioritize access controls and audit trails to enhance transparency and reduce the risk of non-compliance and penalties. Furthermore, the projects could incorporate the European Digital Identity Wallet, when available, to securely identify individuals and legal entities in data spaces, alongside trust services like electronic seals and ledgers. Scope: The activities funded under this initiative will focus on the following aspects: Technical aspects: Utilize advanced technologies such as privacy-preserving technologies, data capturing technologies, automatic transmission and analysis, cloud storage and encryption for data security and compliance with regulations. Implement comprehensive APIs to enable real-time compliance and self-compliance checks. Employ machine learning algorithms for automated monitoring and reporting. Where possible, use precisely defined concepts available in the data catalogue entries of Common European Data Spaces enabling deterministic data collection. Establish direct communication channels with regulatory authorities for automated updates and reporting, keeping the system updated with changing regulations (e.g. by expressing the reporting requirements in machine readable and executable way). Ensure robust access control and maintain audit trails for transparency and accountability. Minimize the risk of non-compliance and potential penalties through these technological and procedural safeguards. Integrate the European Digital Identity Wallet for secure identification of individuals and legal entities, when available. Collaborate with providers of data space services and technology, with a particular emphasis on open-source solutions, such as the European Commission''s Simpl programme. All systems must incorporate robust data privacy and security measures. Proposers must ensure that the systems developed are open source, interoperable with existing government data systems and adhere to European data standards and specifications. The system must be scalable to handle large volumes of data and high transaction rates. The system must be designed with end-users in mind, ensuring ease of use and accessibility. A comprehensive data governance framework must be established. This should include policies for data quality management, data stewardship, and data lifecycle management. Proposals should target legislations that have clear, quantifiable compliance metrics that can be automatically assessed using data analytics and they should ensure no overlaps with ongoing initiatives (e.g. Digital Product Passport, Customs reform). This call aims to explore sectors with significant administrative burden such as agriculture, environment, manufacturing, healthcare and energy.', '[-0.023662604,-0.06721119,0.02622303,0.035035163,-0.09482111,0.050013658,-0.011329886,-0.0046967817,-0.07540455,0.0376596,0.06379728,-0.03672078,0.05739622,-0.003259209,0.019181859,0.028548751,0.02109151,0.027332548,-0.008817468,-0.048861466,0.021208864,0.037744947,-0.009340221,-0.051677935,-0.06716851,0.021059504,0.009148189,-0.03881179,0.07467909,0.05607333,-0.05743889,0.0031685273,-0.04561826,0.054750446,-0.00623037,-0.00057942973,0.023683941,-0.017688276,-0.08773727,0.016034668,0.04090281,-0.0044354047,0.02938089,-0.10122218,0.06832071,0.007537254,-0.021155521,-0.034757785,-0.017773625,-0.061748944,-0.022958487,0.057566915,0.010193696,-0.020579426,0.034501743,0.0039019827,-0.048392054,0.0034405726,-0.030319713,0.02861276,0.021475574,-0.056756113,-0.0026217697,-0.043655265,0.08539021,-0.088249356,-0.0052195354,-0.02417469,0.02129421,0.03970794,0.017496245,0.0067211185,-0.06725386,0.046898473,-0.080994815,-0.0071265195,-0.08756657,-0.03307217,0.034949817,0.0022523748,-0.07053974,-0.047069166,0.016450739,0.03746757,-0.0005997665,-0.06964359,0.018979158,0.048605423,-0.012535419,0.0126527725,-0.048648097,-0.021059504,0.047367882,-0.046130344,-0.029956