INSERT INTO eu_items (reference, kind, url, identifier, title, status, start_date, deadline_date, metadata, embed_text, embedding, triage, triage_score, framework_programme, programme_period, programme_division, programme_part, mission_group, created_at, updated_at) VALUES ('50142731TOPICSen', 'horizon-topic', 'https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL3-2027-02-CS-ECCC-02', '50142731', 'Secure Computing Continuum (IoT, Edge, Cloud, Data spaces)', 'Forthcoming', '2027-03-02T00:00:00.000+0000', '2027-09-15T00:00:00.000+0000', '{"url": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL3-2027-02-CS-ECCC-02", "tags": ["AI-driven anomaly detection", "Fully Homomorphic Encryption", "PQC acceleration solutions", "cross-domain authentication mechanisms", "end-to-end protection", "federated analysis", "interoperability", "post-quantum cryptography", "privacy-preserving protocols", "secure multi-party computation", "security solutions for edge to cloud", "zero-trust architectures"], "title": "Secure Computing Continuum (IoT, Edge, Cloud, Data spaces)", "ccm2Id": "50142731", "status": "31094501", "esST_URL": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL3-2027-02-CS-ECCC-02", "keywords": ["HORIZON-CL3-2027-02-CS-ECCC-02", "HORIZON-CL3-2027-02-CS-ECCC", "Cloud Computing models", "Computing Technologies", "Computing for servers, data centres", "Cybersecurity Domains", "Data Security and Privacy", "Software and Hardware Security Engineering"], "language": "en", "REFERENCE": "50142731TOPICSen", "callTitle": "Indirectly Managed Action by the ECCC (2027)", "startDate": "2027-03-02T00:00:00.000+0000", "DATASOURCE": "SEDIA", "callccm2Id": "50222270", "identifier": "HORIZON-CL3-2027-02-CS-ECCC-02", "es_SortDate": "2027-03-02T00:00:00.000+0000", "deadlineDate": "2027-09-15T00:00:00.000+0000", "deadlineModel": "single-stage", "typesOfAction": "HORIZON Innovation Actions", "budgetOverview": "{\"budgetYearsColumns\":[\"2027\"],\"budgetTopicActionMap\":{\"113425\":[{\"action\":\"HORIZON-CL3-2027-02-CS-ECCC-03 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":3,\"minContribution\":3000000,\"maxContribution\":4000000,\"budgetYearMap\":{\"2027\":\"19000000\"},\"plannedOpeningDate\":\"2027-03-02\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-09-15\"]}],\"113424\":[{\"action\":\"HORIZON-CL3-2027-02-CS-ECCC-02 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":5,\"minContribution\":3000000,\"maxContribution\":4000000,\"budgetYearMap\":{\"2027\":\"24000000\"},\"plannedOpeningDate\":\"2027-03-02\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-09-15\"]}],\"113423\":[{\"action\":\"HORIZON-CL3-2027-02-CS-ECCC-01 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":5,\"minContribution\":4000000,\"maxContribution\":5000000,\"budgetYearMap\":{\"2027\":\"24800000\"},\"plannedOpeningDate\":\"2027-03-02\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-09-15\"]}],\"113422\":[{\"action\":\"HORIZON-CL3-2027-02-CS-ECCC-04 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":1,\"minContribution\":4000000,\"maxContribution\":4000000,\"budgetYearMap\":{\"2027\":\"4000000\"},\"plannedOpeningDate\":\"2027-03-02\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-09-15\"]}]}}", "es_ContentType": "text/plain", "descriptionByte": "Expected Outcome: Proposals are expected to contribute to one or more of the following: Enhanced resilience against distributed cyber threats and adversarial attacks targeting interconnected systems, while preserving data privacy in highly dynamic and heterogeneous environments; Security solutions tailored to distributed computing systems including for example IoT and edge computing environments, integrating privacy-preserving mechanisms; Improved interoperability of security measures and cross-layer security, including the compatibility of privacy-enhancing technologies across different layers of the computing continuum and data spaces, and across providers in the multi-provider edge cloud continuum. Scope: This topic aims to advance security across the entire computing continuum, spanning IoT devices, edge computing, cloud infrastructures, AI computing environments, and data spaces. Proposals should address critical challenges such as ensuring data integrity in highly distributed and dynamic environments, implementing robust zero-trust architectures to secure interconnected and heterogeneous systems, and enabling comprehensive protection for sensitive data and processes. Privacy should be considered a core element of these approaches, ensuring that data confidentiality is preserved throughout its lifecycle, in compliance with relevant data protection frameworks, such as GDPR. Solutions are expected to deliver tangible and measurable security improvements across all layers of the continuum, prioritizing scalability, interoperability, trustworthiness, security and resilience against emerging threats. Proposals are expected to address one or more of the following: Develop advanced security solutions for edge to cloud. For example, investigating lightweight cryptographic techniques, including in combination with or based on post-quantum cryptography, incorporated in zero-trust architectures, and decentralized security models to ensure end-to-end protection from edge to cloud, while maintaining privacy during data transmission and processing. Enhance interoperability of security measures across different computing layers. Exploring security protocols, identity and access management solutions, and cross-domain authentication mechanisms to seamlessly integrate security controls across diverse computing ecosystems, including privacy-preserving protocols that enable the secure and compliant data exchange. Develop portable, deployable PQC acceleration solutions through SW/HW secure co-design to secure user data and computing tasks across heterogeneous platforms and applications in all layers of the continuum. Improve resilience against distributed cyber threats. Exploring anomaly detection, including AI-driven anomaly detection, intrusion prevention techniques, and automated response mechanisms to counter emerging threats targeting interconnected infrastructures and data spaces, while upholding privacy through techniques such as federated analysis, secure multi-party computation, Fully Homomorphic Encryption or other.", "programmePeriod": "2021 - 2027", "programmeDivision": ["43108390", "43108541", "43118971", "43120185"], "frameworkProgramme": "43108390"}', 'Expected Outcome: Proposals are expected to contribute to one or more of the following: Enhanced resilience against distributed cyber threats and adversarial attacks targeting interconnected systems, while preserving data privacy in highly dynamic and heterogeneous environments; Security solutions tailored to distributed computing systems including for example IoT and edge computing environments, integrating privacy-preserving mechanisms; Improved interoperability of security measures and cross-layer security, including the compatibility of privacy-enhancing technologies across different layers of the computing continuum and data spaces, and across providers in the multi-provider edge cloud continuum. Scope: This topic aims to advance security across the entire computing continuum, spanning IoT devices, edge computing, cloud infrastructures, AI computing environments, and data spaces. Proposals should address critical challenges such as ensuring data integrity in highly distributed and dynamic environments, implementing robust zero-trust architectures to secure interconnected and heterogeneous systems, and enabling comprehensive protection for sensitive data and processes. Privacy should be considered a core element of these approaches, ensuring that data confidentiality is preserved throughout its lifecycle, in compliance with relevant data protection frameworks, such as GDPR. Solutions are expected to deliver tangible and measurable security improvements across all layers of the continuum, prioritizing scalability, interoperability, trustworthiness, security and resilience against emerging threats. Proposals are expected to address one or more of the following: Develop advanced security solutions for edge to cloud. For example, investigating lightweight cryptographic techniques, including in combination with or based on post-quantum cryptography, incorporated in zero-trust architectures, and decentralized security models to ensure end-to-end protection from edge to cloud, while maintaining privacy during data transmission and processing. Enhance interoperability of security measures across different computing layers. Exploring security protocols, identity and access management solutions, and cross-domain authentication mechanisms to seamlessly integrate security controls across diverse computing ecosystems, including privacy-preserving protocols that enable the secure and compliant data exchange. Develop portable, deployable PQC acceleration solutions through SW/HW secure co-design to secure user data and computing tasks across heterogeneous platforms and applications in all layers of the continuum. Improve resilience against distributed cyber threats. Exploring anomaly detection, including AI-driven anomaly detection, intrusion prevention techniques, and automated response mechanisms to counter emerging threats targeting interconnected infrastructures and data spaces, while upholding privacy through techniques such as federated analysis, secure multi-party computation, Fully Homomorphic Encryption or other.', '[0.009180614,0.0019817643,0.005183276,0.053512838,-0.01692562,-0.0012789142,0.06549705,-0.04129976,-0.02054585,0.015604443,0.09645627,-0.021159625,0.012067436