INSERT INTO eu_items (reference, kind, url, identifier, title, status, start_date, deadline_date, metadata, embed_text, embedding, triage, triage_score, framework_programme, programme_period, programme_division, programme_part, mission_group, created_at, updated_at) VALUES ('50131280TOPICSen', 'horizon-topic', 'https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL4-2027-02-DIGITAL-EMERGING-52-two-stage', '50131280', 'New approaches for Human/AI collaboration for the workforce of the future (RIA) (Made in Europe and AI, Data and Robotics partnerships)', 'Forthcoming', '2026-09-22T00:00:00.000+0000', '2027-02-02T00:00:00.000+0000', '{"url": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL4-2027-02-DIGITAL-EMERGING-52-two-stage", "tags": null, "title": "New approaches for Human/AI collaboration for the workforce of the future (RIA) (Made in Europe and AI, Data and Robotics partnerships)", "ccm2Id": "50131280", "status": "31094501", "esST_URL": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL4-2027-02-DIGITAL-EMERGING-52-two-stage", "keywords": ["HORIZON-CL4-2027-02-DIGITAL-EMERGING-52-two-stage", "HORIZON-CL4-2027-02-two-stage"], "language": "en", "REFERENCE": "50131280TOPICSen", "callTitle": "INDUSTRY-two-stage", "startDate": "2026-09-22T00:00:00.000+0000", "DATASOURCE": "SEDIA", "callccm2Id": "50131302", "identifier": "HORIZON-CL4-2027-02-DIGITAL-EMERGING-52-two-stage", "es_SortDate": "2026-09-22T00:00:00.000+0000", "deadlineDate": ["2027-02-02T00:00:00.000+0000", "2027-09-02T00:00:00.000+0000"], "deadlineModel": "two-stage", "typesOfAction": "HORIZON  Research and Innovation Actions", "budgetOverview": "{\"budgetYearsColumns\":[\"2027\"],\"budgetTopicActionMap\":{\"112901\":[{\"action\":\"HORIZON-CL4-2027-02-DIGITAL-EMERGING-52-two-stage - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":5,\"minContribution\":4000000,\"maxContribution\":6000000,\"budgetYearMap\":{\"2027\":\"30000000\"},\"plannedOpeningDate\":\"2026-09-22\",\"deadlineModel\":\"two-stage\",\"deadlineDates\":[\"2027-02-02\",\"2027-09-02\"]}],\"112902\":[{\"action\":\"HORIZON-CL4-2027-02-MAT-PROD-32-two-stage - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":6,\"minContribution\":7000000,\"maxContribution\":9000000,\"budgetYearMap\":{\"2027\":\"52500000\"},\"plannedOpeningDate\":\"2026-09-22\",\"deadlineModel\":\"two-stage\",\"deadlineDates\":[\"2027-02-02\",\"2027-09-02\"]}]}}", "es_ContentType": "text/plain", "descriptionByte": "Expected Outcome: Industrial jobs are transformed through AI-based human-machine interactions (and skills linked to them) which enhance flexibility, inclusion, well-being, up-skilling, career evolution and knowledge sharing; Increased competitiveness and sustainability of advanced manufacturing industries by means of knowledge formalization and adaptability of the machines to workers and markets based on different cultures. Scope: Innovative AI approaches are poised to revolutionise human-machine collaboration in factories by fostering an environment where technology and human expertise synergistically enhance each other. AI can enhance the value of the companies by capturing and formalising the knowledge which is dispersed and not explicit. This allows companies to really own the knowledge and use it to reduce the onboarding time of new employees and support personnel upskilling to adapt to the evolving technological landscape. AI has a great potential to make task simpler by reducing the complexity offering intuitive interfaces and real-time feedback allowing workforce to be more efficient and effective while facilitating access to more complex tasks including those involving various forms of planning. AI can also adapt the interaction of automation with the worker taking into account particular needs of the human, including adaptation to the different abilities of the workers and facilitating inclusion. Finally, AI can be used to allow easier export of automation produced in EU by facilitating its interaction with workforce having different cultures adapting the interaction of the machines to the different needs. Proposals should produce dedicated innovative AI approaches for human-machine collaboration in advanced manufacturing to be applied in at least two of following fields: Human-AI Co-Learning and knowledge capture to share competences, capture expert knowledge, provide interactive mentoring to up-skill the workforce, and support re-qualification and continuous training – leading to increased knowledge at factory level and avoiding loss of know-how. Human-AI teamwork thanks to innovative natural interaction models (considering the e.g. related hardware interfaces and/or collaborative machine tools), enabling to control complexity in cognitive cooperating production systems, including planning activities at shop floor level. Interfaces with automation which automatically adapt to the need of the humans including different abilities and different cultural needs. Proposals should integrate a gender perspective and avoid any type of discrimination in the design and deployment of AI systems and human-machine interaction models, including addressing differences in user needs, such as needs of persons with disabilities, physical and cognitive ergonomics and training pathways. Proposals are also expected to identify and address other potential biases in AI systems to promote inclusive design that ensures safe and effective use by all workers. Human/AI collaboration requires utmost sensitivity to and consideration of human values and consideration of ethical principles as represented in Digital Humanism, therefore, appropriate consideration must also be given to the contribution of SSH. This topic is linked to the Apply AI Strategy, therefore proposals should seek collaboration with relevant initiatives. In addition, proposals are invited to build on the results of past projects on Extended Reality Technologies (XR), such as HORIZON-CL4-2021-HUMAN-01-13, HORIZON-CL4-2021-HUMAN-01-14, HORIZON-CL4-2021-HUMAN-01-25, HORIZON-CL4-2021-HUMAN-01-06, HORIZON-CL4-2021-HUMAN-01-28. Proposals should include a business case and exploitation strategy, as outlined in the introduction to Destination ‘Leadership in materials and production for Europe’. This topic implements the co-programmed European Partnerships Made in Europe and AI, Data and Robotics. null Activities are expected to start at TRL 4-5 and achieve TRL 6 by the end of the project – see General Annex B.", "programmePeriod": "2021 - 2027", "programmeDivision": ["43108390", "43108541", "43120193"], "destinationDetails": "Leadership in frontier technologies such as Artificial Intelligence, Quantum, Photonics and Semiconductors is essential to Europe’s economic security and global competitiveness. Building on the ambition of becoming the “AI Continent” and in line with the concrete actions devised in the Apply AI Strategy[1], the EU will consolidate its world-class research ecosystem through initiatives like the RAISE network of AI science labs, the development of safe and efficient frontier AI models, and the deployment of next-generation AI agents and robotics in strategic sectors. In parallel, a long-term quantum strategy will reinforce Europe’s excellence across quantum computing, sensing and communication, supported by new infrastructures and standardisation to secure technological sovereignty. Photonics and semiconductor technologies will remain critical enablers for the digital and green transitions, with investments in advanced integrated photonic devices and resilient semiconductor ecosystems ensuring Europe’s capacity to innovate, scale and compete globally. Foresight and support to emerging materials and technologies will further strengthen Europe’s position at the cutting edge to make sure Europe’s does not miss the emergence of new disruptive technologies, aligning with the Draghi report and the Competitiveness Compass to secure a cohesive, sovereign and future-proof European industrial base. Legal entities established in China are not eligible to participate in both Research and Innovation Actions (RIAs) and Innovation Actions (IAs) falling under this destination. For additional information please see “Restrictions on the participation of legal entities established in China” found in General Annex B of the General Annexes. [1] COM(2025)723 Apply AI Strategy", "frameworkProgramme": "43108390", "destinationDescription": "Achieving open strategic autonomy in digital and emerging enabling technologies (2026-27)"}', 'Expected Outcome: Industrial jobs are transformed through AI-based human-machine interactions (and skills linked to them) which enhance flexibility, inclusion, well-being, up-skilling, career evolution and knowledge sharing; Increased competitiveness and sustainability of advanced manufacturing industries by means of knowledge formalization and adaptability of the machines to workers and markets based on different cultures. Scope: Innovative AI approaches are poised to revolutionise human-machine collaboration in factories by fostering an environment where technology and human expertise synergistically enhance each other. AI can enhance the value of the companies by capturing and formalising the knowledge which is dispersed and not explicit. This allows companies to really own the knowledge and use it to reduce the onboarding time of new employees and support personnel upskilling to adapt to the evolving technological landscape. AI has a great potential to make task simpler by reducing the complexity offering intuitive interfaces and real-time feedback allowing workforce to be more efficient and effective while facilitating access to more complex tasks including those involving various forms of planning. AI can also adapt the interaction of automation with the worker taking into account particular needs of the human, including adaptation to the different abilities of the workers and facilitating inclusion. Finally, AI can be used to allow easier export of automation produced in EU by facilitating its interaction with workforce having different cultures adapting the interaction of the machines to the different needs. Proposals should produce dedicated innovative AI approaches for human-machine collaboration in advanced manufacturing to be applied in at least two of following fields: Human-AI Co-Learning and knowledge capture to share competences, capture expert knowledge, provide interactive mentoring to up-skill the workforce, and support re-qualification and continuous training – leading to increased knowledge at factory level and avoiding loss of know-how. Human-AI teamwork thanks to innovative natural interaction models (considering the e.g. related hardware interfaces and/or collaborative machine tools), enabling to control complexity in cognitive cooperating production systems, including planning activities at shop floor level. Interfaces with automation which automatically adapt to the need of the humans including different abilities and different cultural needs. Proposals should integrate a gender perspective and avoid any type of discrimination in the design and deployment of AI systems and human-machine interaction models, including addressing differences in user needs, such as needs of persons with disabilities, physical and cognitive ergonomics and training pathways. Proposals are also expected to identify and address other potential biases in AI systems to promote inclusive design that ensures safe and effective use by all workers. Human/AI collaboration requires utmost sensitivity to and consideration of human values and consideration of ethical principles as represented in Digital Humanism, therefore, appropriate consideration must also be given to the contribution of SSH. This topic is linked to the Apply AI Strategy, therefore proposals should seek collaboration with relevant initiatives. In addition, proposals are invited to build on the results of past projects on Extended Reality Technologies (XR), such as HORIZON-CL4-2021-HUMAN-01-13, HORIZON-CL4-2021-HUMAN-01-14, HORIZON-CL4-2021-HUMAN-01-25, HORIZON-CL4-2021-HUMAN-01-06, HORIZON-CL4-2021-HUMAN-01-28. Proposals should include a business case and exploitation strategy, as outlined in the introduction to Destination ‘Leadership in materials and production for Europe’. This topic implements the co-programmed European Partnerships Made in Europe and AI, Data and Robotics. null Activities are expected to start at TRL 4-5 and achieve TRL 6 by the end of the project – see General Annex B.', '[0.017172126,0.022696698,0.036053985,0.06877399,-0.074886285,0.09754024,0.008933352,0.021168625,-0.020655707,-0.023957627,0.021489201,-0.016156971,0.12224587,0.03900327,0.059541434,0.013111511,0.019811526,-0.013058082,0.009665332,-0.006903045,0.007581595,0.0952321,0.003237806,-0.0006932431,-0.01774916,0.0048834234,0.01697978,0.015494451,0.04659021,0.073475756,-0.06992806,0.024320945,-0.026180279,0.048684634,0.012160473,-0.0578317,0.056592144,-0.0049475385,-0.09617245,0.036075357,-0.08689716,-0.023316476,0.0039537563,-0.034386996,0.06313188,0.00012539151,-0.038789555,0.045863573,-0.0020316432,-0.0441111,-0.0008969417,0.05706232,-0.046889413,0.028894478,-0.0012128415,0.0065450696,-0.06001161,0.02968523,-0.040948093,0.05740427,-0.073646724,0.00068289123,0.01857197,-0.044239327,0.06642311,-0.08685441,-0.024983466,0.05304445,0.008644835,-0.016937038,0.03199337,0.026821429,-0.056079227,0.04684667,-0.06501258,0.024983466,-0.07715168,-0.09044485,0.013004653,0.052830733,-0.08356318,-0.048470918,0.035113633,0.014051864,0.074373364,-0.020452674,0.0054150433,0.052702505,-0.018230023,-0.04325623,-0.0035503665,-0.036588274,0.026436739,-0.068090096,0.0012796279,-0.015665423,-0.01826208,-0.01934135,-0.072150715,0.04