INSERT INTO eu_items (reference, kind, url, identifier, title, status, start_date, deadline_date, metadata, embed_text, embedding, triage, triage_score, framework_programme, programme_period, programme_division, programme_part, mission_group, created_at, updated_at) VALUES ('50139206TOPICSen', 'horizon-topic', 'https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-MISS-2027-01-CLIMA-02', '50139206', 'Researching and applying the potential of Artificial Intelligence to foster climate resilience at the regional and local levels', 'Forthcoming', '2027-02-09T00:00:00.000+0000', '2027-09-21T00:00:00.000+0000', '{"url": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-MISS-2027-01-CLIMA-02", "tags": null, "title": "Researching and applying the potential of Artificial Intelligence to foster climate resilience at the regional and local levels", "ccm2Id": "50139206", "status": "31094501", "esST_URL": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-MISS-2027-01-CLIMA-02", "keywords": ["HORIZON-MISS-2027-01-CLIMA-02", "HORIZON-MISS-2027-01"], "language": "en", "REFERENCE": "50139206TOPICSen", "callTitle": "Supporting the implementation of the Adaptation to Climate Change Mission", "startDate": "2027-02-09T00:00:00.000+0000", "DATASOURCE": "SEDIA", "callccm2Id": "50139260", "identifier": "HORIZON-MISS-2027-01-CLIMA-02", "es_SortDate": "2027-02-09T00:00:00.000+0000", "deadlineDate": "2027-09-21T00:00:00.000+0000", "deadlineModel": "single-stage", "typesOfAction": "HORIZON  Research and Innovation Actions", "budgetOverview": "{\"budgetYearsColumns\":[\"2027\"],\"budgetTopicActionMap\":{\"113091\":[{\"action\":\"HORIZON-MISS-2027-01-CLIMA-01 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":5,\"minContribution\":10000000,\"maxContribution\":15000000,\"budgetYearMap\":{\"2027\":\"72323812.37\"},\"plannedOpeningDate\":\"2027-02-09\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-09-21\"]}],\"113092\":[{\"action\":\"HORIZON-MISS-2027-01-CLIMA-02 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":4,\"minContribution\":3000000,\"maxContribution\":3000000,\"budgetYearMap\":{\"2027\":\"12000000\"},\"plannedOpeningDate\":\"2027-02-09\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-09-21\"]}]}}", "es_ContentType": "text/plain", "descriptionByte": "Expected Outcome: AI has the potential to support or facilitate virtually every aspect of regions’ climate adaptation efforts. From risk assessment to climate forecasting, from infrastructure planning to resource management, and more. Contributing to the objectives of the AI Continent Action Plan and the EU Mission on Adaptation to Climate Change, projects are expected to contribute one of the following: AI is used to improve actionable climate adaptation knowledge for European regions and local authorities by integrating climate data into decision-making processes. Specific sectors in the selected regions become more resilient to climate change thanks to the use of AI to improve their processes or technologies, while simultaneously advancing their digital transformation. Scope: Rationale Over the past few years, a rapid and disruptive acceleration of progress in Artificial Intelligence has occurred, driven by significant advances in widespread data availability, computing power and machine learning[1]. While the potential of Artificial Intelligence is being uncovered each day and its possibilities are expanding exponentially, such technological revolution can significantly accelerate Europe’s efforts towards climate resilience and contribute to the objectives of the Adaptation Mission. Considering the ever-changing nature of AI growth, proposals should demonstrate that they go beyond state of the art, they should identify a specific gap that can be addressed by an AI-powered tool, and explain why it would improve existing models, tools or applications or, alternatively, justify the need to develop entirely new solutions. In particular, the proposal should address one of the following two objectives: Objective 1: “AI for more accessible data” AI can quickly process and identify patterns from big datasets that would otherwise be too complex. Proposals should explore how AI can be further integrated, including via AI techniques such as deep learning, to make data more accessible and understandable, to facilitate informed decision-making by regions and local authorities. Improvements should be tested with at least 3 regional and local authorities to ensure that they provide a concrete added value to end-users (i.e. decision-makers). Moreover, proposals are expected to apply such analysis to concretely improve data integrity and accessibility[2]. Objective 2: “AI for sectoral adaptation” Use and application of machine learning and AI tools to help regions and local authorities optimize their management of resources and improve adaptation technologies in key sector(s). Proposals should develop and test the tools in the territory of at least 5 regional or local authorities. The work should engage private sector actors with relevant expertise in the sector chosen (e.g. smart agriculture, construction and buildings sector, water management, waste management, transports, resilience of energy systems, etc.), to ensure that such AI-powered tools are designed for scalability and uptake. Regardless of the objective addressed, all proposals should provide training and dissemination material for different target groups, including regions and local authorities, on how to best take advantage of the AI-powered improvements. Attention should be given to avoiding biases and ensuring that the data is representative of diverse populations, as well as taking into account possible limitations and potential misinformation when using generative AI tools. To ensure a balanced portfolio covering both objectives, grants will be awarded to proposals not only in order of ranking but at least also to one proposal that is the highest ranked within each objective, provided that the applications attain all thresholds. To this purpose, the objective addressed by each proposal should also be specified in the free keywords section of the proposal (e.g. ‘objective 1’ or ‘objective 2’). Links to the Mission and to other projects and initiatives Proposals should include a mechanism and the resources to establish operational links and collaboration with the Mission Implementation Platform (including on monitoring), and other relevant knowledge platforms. Projects funded under this topic will be expected to participate in the Mission Community of Practice and to share relevant knowledge to feed the work of the project stemming from HORIZON-MISS-2026-01-CLIMA-02. Proposals are encouraged to (dedicate resources to) 1) link their monitoring to the framework developed by the project UNDERPIN; 2) to rely on the (updated) CLIMAAX framework for their climate risk assessments, where relevant. Applicants should acknowledge these elements and already account for them in their proposal, making adequate provisions in terms of resources and budget to engage and collaborate with the Mission. [1] COM(2024) 28 final [2] This could include, where relevant, the use or enhancement of Destination Earth (DestinE) data, tools and/or services, to be identified in the proposal.", "programmePeriod": "2021 - 2027", "programmeDivision": ["43108390", "43108541", "43108557", "43118846", "43118971", "43120193", "43120821", "43121563"], "frameworkProgramme": "43108390"}', 'Expected Outcome: AI has the potential to support or facilitate virtually every aspect of regions’ climate adaptation efforts. From risk assessment to climate forecasting, from infrastructure planning to resource management, and more. Contributing to the objectives of the AI Continent Action Plan and the EU Mission on Adaptation to Climate Change, projects are expected to contribute one of the following: AI is used to improve actionable climate adaptation knowledge for European regions and local authorities by integrating climate data into decision-making processes. Specific sectors in the selected regions become more resilient to climate change thanks to the use of AI to improve their processes or technologies, while simultaneously advancing their digital transformation. Scope: Rationale Over the past few years, a rapid and disruptive acceleration of progress in Artificial Intelligence has occurred, driven by significant advances in widespread data availability, computing power and machine learning[1]. While the potential of Artificial Intelligence is being uncovered each day and its possibilities are expanding exponentially, such technological revolution can significantly accelerate Europe’s efforts towards climate resilience and contribute to the objectives of the Adaptation Mission. Considering the ever-changing nature of AI growth, proposals should demonstrate that they go beyond state of the art, they should identify a specific gap that can be addressed by an AI-powered tool, and explain why it would improve existing models, tools or applications or, alternatively, justify the need to develop entirely new solutions. In particular, the proposal should address one of the following two objectives: Objective 1: “AI for more accessible data” AI can quickly process and identify patterns from big datasets that would otherwise be too complex. Proposals should explore how AI can be further integrated, including via AI techniques such as deep learning, to make data more accessible and understandable, to facilitate informed decision-making by regions and local authorities. Improvements should be tested with at least 3 regional and local authorities to ensure that they provide a concrete added value to end-users (i.e. decision-makers). Moreover, proposals are expected to apply such analysis to concretely improve data integrity and accessibility[2]. Objective 2: “AI for sectoral adaptation” Use and application of machine learning and AI tools to help regions and local authorities optimize their management of resources and improve adaptation technologies in key sector(s). Proposals should develop and test the tools in the territory of at least 5 regional or local authorities. The work should engage private sector actors with relevant expertise in the sector chosen (e.g. smart agriculture, construction and buildings sector, water management, waste management, transports, resilience of energy systems, etc.), to ensure that such AI-powered tools are designed for scalability and uptake. Regardless of the objective addressed, all proposals should provide training and dissemination material for different target groups, including regions and local authorities, on how to best take advantage of the AI-powered improvements. Attention should be given to avoiding biases and ensuring that the data is representative of diverse populations, as well as taking into account possible limitations and potential misinformation when using generative AI tools. To ensure a balanced portfolio covering both objectives, grants will be awarded to proposals not only in order of ranking but at least also to one proposal that is the highest ranked within each objective, provided that the applications attain all thresholds. To this purpose, the objective addressed by each proposal should also be specified in the free keywords section of the proposal (e.g. ‘objective 1’ or ‘objective 2’). Links to the Mission and to other projects and initiatives Proposals should include a mechanism and the resources to establish operational links and collaboration with the Mission Implementation Platform (including on monitoring), and other relevant knowledge platforms. Projects funded under this topic will be expected to participate in the Mission Community of Practice and to share relevant knowledge to feed the work of the project stemming from HORIZON-MISS-2026-01-CLIMA-02. Proposals are encouraged to (dedicate resources to) 1) link their monitoring to the framework developed by the project UNDERPIN; 2) to rely on the (updated) CLIMAAX framework for their climate risk assessments, where relevant. Applicants should acknowledge these elements and already account for them in their proposal, making adequate provisions in terms of resources and budget to engage and collaborate with the Mission. [1] COM(2024) 28 final [2] This could include, where relevant, the use or enhancement of Destination Earth (DestinE) data, tools and/or services, to be identified in the proposal.', '[0.02594779,0.0030928561,0.036792263,-0.0035966462,-0.07300283,-0.008408621,0.022374514,0.00944217,-0.07096689,-0.01194554,0.05447166,0.0031188247,0.09689391,0.080980375,0.029064018,-0.0038095885,0.014272323,0.08983046,0.040261663,-0.0067258584,0.027381254,0.059291426,-0.004071871,-0.02389108,-0.04487368,-0.0046042264,0.015300678,-0.014230774,0.04765751,0.09938689,-0.04059406,0.0011588472,-0.004409462,0.07291973,0.010039447,0.00036550756,0.04022011,-0.03845425,-0.090744555,0.0492364,-0.01593431,-0.022000568,0.032097146,-0.02731893,0.065980926,0.016879568,-0.0076295645,0.044458184,-0.020826789,-0.01965301,-0.055178005,0.03236722,0.011166483,0.022104442,0.020203544,-0.060330167,-0.036335215,0.028066825,-0.041113432,0.020390516,-0.0485716,-0.06585628,-0.008013899,-0.051230785,0.05887593,-0.10736443,0.011488493,-0.0021943436,0.011727404,0.017097702,0.046078622,0.012371425,-0.057961836,-0.0003817379,-0.07304438,0.008491721,-0.08816847,-0.109774314,0.023371708,0.056923095,-0.044333532,-0.02723583,0.0003541463,-0.0068089576,0.038724322,-0.058294233,-0.003562887,0.08122967,0.059665374,-0.01235065,-0.021460421,0.024535099,0.015103317,-0.046868064,-0.03498485,0.022104442,-0.0843459,0.018936276,-0.038038753,0.042110626,-0.0104082,0.028939368,0.030497482,-0.082060665,-0.044042684,0.0196