INSERT INTO eu_items (reference, kind, url, identifier, title, status, start_date, deadline_date, metadata, embed_text, embedding, triage, triage_score, framework_programme, programme_period, programme_division, programme_part, mission_group, created_at, updated_at) VALUES ('50132047TOPICSen', 'horizon-topic', 'https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL4-2027-04-DATA-03', '50132047', 'New approaches for decentralized, federated and sustainable AI data processing (RIA)', 'Forthcoming', '2026-11-17T00:00:00.000+0000', '2027-03-18T00:00:00.000+0000', '{"url": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL4-2027-04-DATA-03", "tags": ["Cloud computing", "Edge computing"], "title": "New approaches for decentralized, federated and sustainable AI data processing (RIA)", "ccm2Id": "50132047", "status": "31094501", "esST_URL": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL4-2027-04-DATA-03", "keywords": ["HORIZON-CL4-2027-04-DATA-03", "HORIZON-CL4-2027-04", "Computer sciences, information science and bioinformatics"], "language": "en", "REFERENCE": "50132047TOPICSen", "callTitle": "DIGITAL", "startDate": "2026-11-17T00:00:00.000+0000", "DATASOURCE": "SEDIA", "callccm2Id": "50132073", "identifier": "HORIZON-CL4-2027-04-DATA-03", "es_SortDate": "2026-11-17T00:00:00.000+0000", "deadlineDate": "2027-03-18T00:00:00.000+0000", "deadlineModel": "single-stage", "typesOfAction": "HORIZON  Research and Innovation Actions", "budgetOverview": "{\"budgetYearsColumns\":[\"2027\"],\"budgetTopicActionMap\":{\"112913\":[{\"action\":\"HORIZON-CL4-2027-04-DIGITAL-EMERGING-04 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":3,\"minContribution\":14000000,\"maxContribution\":14000000,\"budgetYearMap\":{\"2027\":\"42000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112912\":[{\"action\":\"HORIZON-CL4-2027-04-HUMAN-07 - HORIZON-CSA HORIZON Coordination and Support Actions\",\"expectedGrants\":1,\"minContribution\":7000000,\"maxContribution\":7000000,\"budgetYearMap\":{\"2027\":\"7000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112915\":[{\"action\":\"HORIZON-CL4-2027-04-DATA-08 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":2,\"minContribution\":19000000,\"maxContribution\":19000000,\"budgetYearMap\":{\"2027\":\"38000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112914\":[{\"action\":\"HORIZON-CL4-2027-04-DIGITAL-EMERGING-05 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":1,\"minContribution\":18000000,\"maxContribution\":18000000,\"budgetYearMap\":{\"2027\":\"18000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112917\":[{\"action\":\"HORIZON-CL4-2027-04-DIGITAL-EMERGING-10 - HORIZON-CSA HORIZON Coordination and Support Actions\",\"expectedGrants\":1,\"minContribution\":4000000,\"maxContribution\":4000000,\"budgetYearMap\":{\"2027\":\"4000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112916\":[{\"action\":\"HORIZON-CL4-2027-04-DATA-03 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":2,\"minContribution\":17500000,\"maxContribution\":17500000,\"budgetYearMap\":{\"2027\":\"35000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112918\":[{\"action\":\"HORIZON-CL4-2027-04-DIGITAL-EMERGING-11 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":1,\"minContribution\":44000000,\"maxContribution\":44000000,\"budgetYearMap\":{\"2027\":\"44000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112909\":[{\"action\":\"HORIZON-CL4-2027-04-HUMAN-02 - HORIZON-CSA HORIZON Coordination and Support Actions\",\"expectedGrants\":1,\"minContribution\":3000000,\"maxContribution\":3000000,\"budgetYearMap\":{\"2027\":\"3000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112908\":[{\"action\":\"HORIZON-CL4-2027-04-DATA-09 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":3,\"minContribution\":10000000,\"maxContribution\":10000000,\"budgetYearMap\":{\"2027\":\"39000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112911\":[{\"action\":\"HORIZON-CL4-2027-04-HUMAN-01 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":8,\"minContribution\":4800000,\"maxContribution\":5600000,\"budgetYearMap\":{\"2027\":\"39000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112910\":[{\"action\":\"HORIZON-CL4-2027-04-DIGITAL-EMERGING-06 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":2,\"minContribution\":1500000,\"maxContribution\":1500000,\"budgetYearMap\":{\"2027\":\"3000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}]}}", "es_ContentType": "text/plain", "descriptionByte": "Expected Outcome: Project results are expected to contribute to developing new approaches, tools and techniques that overcome the obstacles of today''s centralised AI compute techniques: limits in the availability of energy and AI compute capacity in centralised standalone environments, limited availability of types of AI chips, data quality and security and latency in AI data processing. The ultimate objective is to help overcome EU’s AI compute capacity bottlenecks by offering alternative decentralised and sustainable AI compute models that enable exploitation of diverse hardware processing architectures and scaling approaches. Scope: This topic focusses on technologies and techniques that enable AI data processing to leverage distributed compute resources across the cloud and edge computing continuum throughout the whole AI model lifecycle from data collection, training, fine-tuning, and deployment. To overpass today’s state of the art in the area, the considered research areas include: To research on distributed, decentralised, and federated “compute continuum” enabled AI architectures beyond federated learning and integrating model compression tools and new mechanisms to enable AI data processing to scale across multiple and diverse computing infrastructures. Development, deployment, and operation of AI workflows across heterogeneous and distributed infrastructures along the compute continuum (edge, cloud, HPC), including the possibility of incorporating innovative computing paradigms (neuromorphic and quantum computing) and hardware efficiency enhancements ((e.g., including in-memory computing, and hardware and software approximation). Novel methods and techniques to improve data availability and consistency for decentralised AI data processing. These consider tools to ensure data quality (e.g. prevention of data sets imbalance or inconsistency across distributed data sources), volume optimisation for data transfers across environments, and distributed data management, all while preserving data privacy and preventing data leaks (e.g. via advanced cryptographic protection such as post-quantum cryptography for resistance to emerging quantum threats). New tools and mechanisms to measure, monitor and improve end-to-end energy efficiency and sustainability of AI data processing across the compute continuum, including the exploration of energy and sustainability implications of the heterogeneous AI processing architectures and their impact in the compute infrastructure design and long-term sustainability. Successful project proposals should showcase proposed developments in at least two complementary use cases in different domains. These use cases should demonstrate the value gained and potential impact of project achievements in real-world situations, as well as address key applications and sectors critical to Europe''s competitiveness. Use cases should provide compelling examples and scenarios and cater for the reproducibility of results'' added value and impact in additional economic sectors. null Activities are expected to start at TRL 3 and achieve TRL 6-7 by the end of the project – see General Annex B.", "programmePeriod": "2021 - 2027", "programmeDivision": ["43108541", "43120193", "43120218", "43120231", "43108390"], "destinationDetails": "Developing an agile and secure single market for data and trustworthy AI services is central to Europe’s digital sovereignty and competitiveness. The convergence of the Telco-Edge-Cloud continuum (3C) with open orchestration platforms will unlock the transformative potential of AI across strategic sectors, from mobility and energy to health and manufacturing, fostering new services and business models. Building a sovereign Open Internet Stack, rooted in open-source, interoperable and standard-based solutions, will reinforce trust, resilience and innovation, while ensuring Europe retains control over critical digital infrastructures. At the same time, decentralised and federated approaches to AI data processing, combined with breakthroughs in sustainable data centres, will help overcome Europe’s compute bottlenecks and dependencies, and reduce the environmental footprint of AI. By aligning with the Data Union Strategy and Common European Data Spaces, these efforts will deliver secure, compliant and adaptive data-sharing frameworks that empower citizens, businesses and administrations. Together, they will strengthen Europe’s ability to innovate, scale and lead globally in data and AI, anchoring digital sovereignty in line with EU values and strategic interests. Legal entities established in China are not eligible to participate in both Research and Innovation Actions (RIAs) and Innovation Actions (IAs) falling under this destination. For additional information please see “Restrictions on the participation of legal entities established in China” found in General Annex B of the General Annexes.", "frameworkProgramme": "43108390", "destinationDescription": "Developing an agile and secure single market and infrastructure for data-services and trustworthy artificial intelligence services (2026-27)"}', 'Expected Outcome: Project results are expected to contribute to developing new approaches, tools and techniques that overcome the obstacles of today''s centralised AI compute techniques: limits in the availability of energy and AI compute capacity in centralised standalone environments, limited availability of types of AI chips, data quality and security and latency in AI data processing. The ultimate objective is to help overcome EU’s AI compute capacity bottlenecks by offering alternative decentralised and sustainable AI compute models that enable exploitation of diverse hardware processing architectures and scaling approaches. Scope: This topic focusses on technologies and techniques that enable AI data processing to leverage distributed compute resources across the cloud and edge computing continuum throughout the whole AI model lifecycle from data collection, training, fine-tuning, and deployment. To overpass today’s state of the art in the area, the considered research areas include: To research on distributed, decentralised, and federated “compute continuum” enabled AI architectures beyond federated learning and integrating model compression tools and new mechanisms to enable AI data processing to scale across multiple and diverse computing infrastructures. Development, deployment, and operation of AI workflows across heterogeneous and distributed infrastructures along the compute continuum (edge, cloud, HPC), including the possibility of incorporating innovative computing paradigms (neuromorphic and quantum computing) and hardware efficiency enhancements ((e.g., including in-memory computing, and hardware and software approximation). Novel methods and techniques to improve data availability and consistency for decentralised AI data processing. These consider tools to ensure data quality (e.g. prevention of data sets imbalance or inconsistency across distributed data sources), volume optimisation for data transfers across environments, and distributed data management, all while preserving data privacy and preventing data leaks (e.g. via advanced cryptographic protection such as post-quantum cryptography for resistance to emerging quantum threats). New tools and mechanisms to measure, monitor and improve end-to-end energy efficiency and sustainability of AI data processing across the compute continuum, including the exploration of energy and sustainability implications of the heterogeneous AI processing architectures and their impact in the compute infrastructure design and long-term sustainability. Successful project proposals should showcase proposed developments in at least two complementary use cases in different domains. These use cases should demonstrate the value gained and potential impact of project achievements in real-world situations, as well as address key applications and sectors critical to Europe''s competitiveness. Use cases should provide compelling examples and scenarios and cater for the reproducibility of results'' added value and impact in additional economic sectors. null Activities are expected to start at TRL 3 and achieve TRL 6-7 by the end of the project – see General Annex B.', '[0.06553381,0.029379431,0.07516362,0.071754836,-0.07256442,0.0074354033,-0.010146449,0.029528564,-0.022050552,-0.011536593,0.08913962,-0.019483313,0.05347525,0.050620396,-0.0047483253,-0.0