INSERT INTO eu_items (reference, kind, url, identifier, title, status, start_date, deadline_date, metadata, embed_text, embedding, triage, triage_score, framework_programme, programme_period, programme_division, programme_part, mission_group, created_at, updated_at) VALUES ('50129993TOPICSen', 'horizon-topic', 'https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL5-2026-11-D3-23', '50129993', 'Data sharing to support the training and development of AI foundation models in the energy sector', 'Forthcoming', '2026-08-04T00:00:00.000+0000', '2026-12-01T00:00:00.000+0000', '{"url": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL5-2026-11-D3-23", "tags": null, "title": "Data sharing to support the training and development of AI foundation models in the energy sector", "ccm2Id": "50129993", "status": "31094501", "esST_URL": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL5-2026-11-D3-23", "keywords": ["HORIZON-CL5-2026-11-D3-23", "HORIZON-CL5-2026-11"], "language": "en", "REFERENCE": "50129993TOPICSen", "callTitle": "ENERGY", "startDate": "2026-08-04T00:00:00.000+0000", "DATASOURCE": "SEDIA", "callccm2Id": "50131216", "identifier": "HORIZON-CL5-2026-11-D3-23", "es_SortDate": "2026-08-04T00:00:00.000+0000", "deadlineDate": "2026-12-01T00:00:00.000+0000", "deadlineModel": "single-stage", "typesOfAction": "HORIZON Innovation Actions", "budgetOverview": "{\"budgetYearsColumns\":[\"2026\"],\"budgetTopicActionMap\":{\"112897\":[{\"action\":\"HORIZON-CL5-2026-11-D3-06 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":4,\"minContribution\":4500000,\"maxContribution\":4500000,\"budgetYearMap\":{\"2026\":\"18000000\"},\"plannedOpeningDate\":\"2026-08-04\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2026-12-01\"]}],\"112896\":[{\"action\":\"HORIZON-CL5-2026-11-D3-05 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":2,\"minContribution\":6750000,\"maxContribution\":6750000,\"budgetYearMap\":{\"2026\":\"13500000\"},\"plannedOpeningDate\":\"2026-08-04\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2026-12-01\"]}],\"112899\":[{\"action\":\"HORIZON-CL5-2026-11-D3-14 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":4,\"minContribution\":7500000,\"maxContribution\":7500000,\"budgetYearMap\":{\"2026\":\"30000000\"},\"plannedOpeningDate\":\"2026-08-04\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2026-12-01\"]}],\"112898\":[{\"action\":\"HORIZON-CL5-2026-11-D3-23 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":3,\"minContribution\":10000000,\"maxContribution\":10000000,\"budgetYearMap\":{\"2026\":\"30000000\"},\"plannedOpeningDate\":\"2026-08-04\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2026-12-01\"]}],\"112900\":[{\"action\":\"HORIZON-CL5-2026-11-D3-04 - HORIZON-PCP HORIZON Pre-commercial Procurement\",\"expectedGrants\":1,\"minContribution\":40000000,\"maxContribution\":40000000,\"budgetYearMap\":{\"2026\":\"40000000\"},\"plannedOpeningDate\":\"2026-08-04\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2026-12-01\"]}]}}", "es_ContentType": "text/plain", "descriptionByte": "Expected Outcome: Projects are expected to contribute to all the following expected outcomes: Effective and innovative methods for gathering, sharing and using large data sets in energy applications for the purpose of training AI models while ensuring privacy and security. Advanced and - wherever possible - open-source AI foundation models to support the digitalisation of the energy system, through improved grid observability, forecasting of supply and demand, advanced storage and renewables integration, demand side flexibility and energy efficiency. Enhanced cooperation, knowledge sharing and interoperability among energy system actors for secure and seamless data exchange. Advanced methodologies for AI model development ensuring that the results are FAIR (Findable, Accessible, Interoperable, Reusable) beyond the project ending, open source and accommodating for technology evolution. Scope: The quality of AI models depends strongly on the amount, quality, and representativeness of the data used for their training. Projects are expected to focus on developing, training and testing AI foundation models, using extensive data sets to accelerate the energy transition in key focus areas of the energy sector. Projects are expected to: Building on the results of previously funded projects on the Common European energy data space[1] as well as the ongoing work within the Data 4 Energy expert group, projects are expected to demonstrate innovative methods and data governance strategies for sharing data among various energy actors. Projects are expected to demonstrate that they have access to large relevant datasets at the time of submitting the proposal. Projects are expected to develop innovative strategies for sharing data in an effective, secure and transparent way to support the development of AI foundation models. An indicative non exhaustive list of strategies that can be explored is the use of data space connectors or federated training of models to allow the integration of confidential data; the creation of synthetic data as an intermediate step to fill data gaps or improve the quality of the data could also be explored. Projects could also explore other innovative data sharing strategies, such as an ‘AI gym’. The data governance strategies that will be developed in the project should be designed in a way to be scalable and operational even after the end of the project. Projects are expected to develop foundation models tailored for the energy sector, addressing at least one -or more- of the following use cases: planning and operation of electricity grids (including static power flow modelling and dynamic EMT modelling), forecasting, congestion management, anomaly detection, fault diagnosis, predictive maintenance, flexibility management, demand-side energy efficiency, smart and bidirectional charging of EVs or other use cases that contribute to the objective of digitalisation of the energy system. Projects are expected to perform in-depth testing and validation of developed foundation models in lab demonstrators and real-life pilots, building on the results and using the facilities of previously funded projects on “AI testing and experimentation facilities (TEFs)”[2]. Regulatory sandboxes could also be considered for real-life pilot implementations. Projects are expected to bring together a wide group of stakeholders including data owners (for example energy utilities, grid operators, asset owners), application developers (for example startups, SMEs, hyperscalers) and model deployers (for example industry, grid operators, equipment manufacturers) providing a space of cooperation and collaborative data exchange. To scale up the training and development of the models, projects can benefit from the computing capacity of the AI factories that were recently announced by the European Commission[3], in particular the three AI factories that aim to develop AI applications for the energy sector. AI models are expected to respect ethical, safety and security principles; furthermore, transparency, explainability, and accountability should be embedded by design in the model development. Open-source development practices should be pursued wherever feasible. Efforts should be made to avoid biases, ensuring that the data produced is representative of diverse populations. Selected projects are expected to contribute to the BRIDGE initiative[4] and actively participate in its activities. null Activities are expected to achieve TRL 7-8 by the end of the project – see General Annex B. Activities may start at any TRL. [1] Establish the grounds for a common European energy data space [2] AI Testing and Experimentation Facility (TEF) for the energy sector – bringing technology to the market [3] AI Factories [4] https://bridge-smart-grid-storage-systems-digital-projects.ec.europa.eu/", "programmePeriod": "2021 - 2027", "programmeDivision": ["43108541", "43120821", "43121058", "43108390"], "destinationDetails": "This Destination includes activities targeting a sustainable, secure and competitive energy supply. In line with the scope of cluster 5, this includes activities in the areas of renewable energy; energy system, grids and storage; as well as Carbon Capture, Utilisation and Storage (CCUS). This Destination contributes directly to the Strategic Plan’s Key Strategic Orientations ‘Green transition’, ‘Digital transition’ and ‘A more resilient, competitive, inclusive and democratic Europe’. In line with the Strategic Plan, the overall expected impact of this Destination is to contribute to the ‘Ensuring more sustainable, secure and competitive energy supply through solutions for smart energy systems based on renewable energy solutions’. This destination contributes to the activities of the Strategic Energy Technology Plan (SET Plan) and its implementation working groups. The main impacts to be generated by topics under this Destination are: Renewable energy Energy producers have access to efficient and competitive European renewable energy and renewable fuel technologies with a solid knowledge base and are able to deploy them to enhance the EU’s energy security and reach its climate neutrality objectives, in a sustainable way in environmental (e.g., biodiversity, multiple uses of land and water, natural resources, pollution) and socioeconomic terms, and in line with the Sustainable Development Goals. Technology providers have access to European, competitive, resilient, reliable, sustainable, and affordable value chains of renewable energy and renewable fuel technologies including emerging ones, and with strong export potential to supply both the EU internal and global markets. They benefit also from circular renewable energy technologies that are safe and sustainable by design with reduced and diversified external dependence on critical raw materials[1]. Economic sectors benefit from better integration of renewable energy and renewable fuel-based solutions that are, among others, competitive, cost-effective, efficient, flexible, reliable, and sustainable. Such integration is facilitated through digitalisation and integration of artificial intelligence of renewable energy technologies that provide network stability and reliability. European industries benefit from a reinforced export potential of renewable energy and renewable fuel technologies, also through international partnerships, and become more competitive in innovative renewable energy technologies in Europe and globally. European researchers benefit from a stronger community and from a reinforced scientific basis on renewable energy and renewable fuel technologies including emerging ones, also through international collaborations. European citizens have access to an energy market that is fair and equitable, more resilient, uses all different types of local renewable energy resources, and is less dependent on fossil fuels imports. Citizens experience less fuel and energy poverty, and also benefit from new employment and upskilling opportunities. Local communities benefit from a more decentralized, affordable, and secure energy system and from multiple uses of land and water. Energy systems, grids and storage R&I actions will support the just digital and green transformation of the energy system through advanced solutions for accelerating the energy systems integration and decarbonisation. The developed clean, sustainable solutions will contribute to making the energy system work better for actors and supply more reliable, resilient and secure energy – even under increasingly more frequent extreme climate events. The solutions developed will contribute to increase flexibility and grid hosting capacity for renewables through optimizing cross sector integration and grid scale storage as well as cover off-grid situations. They will improve the preparedness of the electricity system to support the EU''s binding target for 2030 of minimum of 42.5% renewables in the gross final energy consumption (with the aspiration to reach 45%), and full decarbonisation by 2050. They will enable further electrification of demand and will enhance the competitiveness of the European value chain, reduce pressure on resources (also by making technologies ‘circular by design’) and decrease dependencies. Such solutions would also enable a better EU resilience to climate risks. The solutions will improve consumer awareness and engagement in the energy transition, via innovative offers and services (e.g. demand response, energy communities) and will target different types of consumers, including “hard to reach” population groups (such as energy poor or low-income households). This will result in increased trust in, and uptake of the new products and services entering the energy system. Carbon capture, use and storage (CCUS) and carbon dioxide removal (CDR) Accelerated deployment of carbon capture, use and storage (CCUS) as a CO2 emission mitigation option in electricity generation and/or in industry applications, as well as carbon dioxide removal for negative emissions. Legal entities established in China are not eligible to participate in both Research and Innovation Actions (RIAs) and Innovation Actions (IAs) falling under this destination. For additional information please see “Restrictions on the participation of legal entities established in China” found in General Annex B of the General Annexes. [1] For an example of a methodology for the assessment of sustainability, circularity and contribution to EU resilience and technological autonomy of clean energy technology in the R&I pipeline, please see Study on circular approaches for a sustainable and affordable clean energy transition", "frameworkProgramme": "43108390", "destinationDescription": "Ensuring more efficient, sustainable, secure, and competitive renewable and decarbonised energy supply (2026-27)"}', 'Expected Outcome: Projects are expected to contribute to all the following expected outcomes: Effective and innovative methods for gathering, sharing and using large data sets in energy applications for the purpose of training AI models while ensuring privacy and security. Advanced and - wherever possible - open-source AI foundation models to support the digitalisation of the energy system, through improved grid observability, forecasting of supply and demand, advanced storage and renewables integration, demand side flexibility and energy efficiency. Enhanced cooperation, knowledge sharing and interoperability among energy system actors for secure and seamless data exchange. Advanced methodologies for AI model development ensuring that the results are FAIR (Findable, Accessible, Interoperable, Reusable) beyond the project ending, open source and accommodating for technology evolution. Scope: The quality of AI models depends strongly on the amount, quality, and representativeness of the data used for their training. Projects are expected to focus on developing, training and testing AI foundation models, using extensive data sets to accelerate the energy transition in key focus areas of the energy sector. Projects are expected to: Building on the results of previously funded projects on the Common European energy data space[1] as well as the ongoing work within the Data 4 Energy expert group, projects are expected to demonstrate innovative methods and data governance strategies for sharing data among various energy actors. Projects are expected to demonstrate that they have access to large relevant datasets at the time of submitting the proposal. Projects are expected to develop innovative strategies for sharing data in an effective, secure and transparent way to support the development of AI foundation models. An indicative non exhaustive list of strategies that can be explored is the use of data space connectors or federated training of models to allow the integration of confidential data; the creation of synthetic data as an intermediate step to fill data gaps or improve the quality of the data could also be explored. Projects could also explore other innovative data sharing strategies, such as an ‘AI gym’. The data governance strategies that will be developed in the project should be designed in a way to be scalable and operational even after the end of the project. Projects are expected to develop foundation models tailored for the energy sector, addressing at least one -or more- of the following use cases: planning and operation of electricity grids (including static power flow modelling and dynamic EMT modelling), forecasting, congestion management, anomaly detection, fault diagnosis, predictive maintenance, flexibility management, demand-side energy efficiency, smart and bidirectional charging of EVs or other use cases that contribute to the objective of digitalisation of the energy system. Projects are expected to perform in-depth testing and validation of developed foundation models in lab demonstrators and real-life pilots, building on the results and using the facilities of previously funded projects on “AI testing and experimentation facilities (TEFs)”[2]. Regulatory sandboxes could also be considered for real-life pilot implementations. Projects are expected to bring together a wide group of stakeholders including data owners (for example energy utilities, grid operators, asset owners), application developers (for example startups, SMEs, hyperscalers) and model deployers (for example industry, grid operators, equipment manufacturers) providing a space of cooperation and collaborative data exchange. To scale up the training and development of the models, projects can benefit from the computing capacity of the AI factories that were recently announced by the European Commission[3], in particular the three AI factories that aim to develop AI applications for the energy sector. AI models are expected to respect ethical, safety and security principles; furthermore, transparency, explainability, and accountability should be embedded by design in the model development. Open-source development practices should be pursued wherever feasible. Efforts should be made to avoid biases, ensuring that the data produced is representative of diverse populations. Selected projects are expected to contribute to the BRIDGE initiative[4] and actively participate in its activities. null Activities are expected to achieve TRL 7-8 by the end of the project – see General Annex B. Activities may start at any TRL. [1] Establish the grounds for a common European energy data space [2] AI Testing and Experimentation Facility (TEF) for the energy sector – bringing technology to the market [3] AI Factories [4] https://bridge-smart-grid-storage-systems-digital-projects.ec.europa.eu/', '[0.031838365,-0.0027075023,0.068683155,-0.007576869,-0.058877185,-0.032376245,0.0063821543,0.0066769538,-0.02666644,-0.014140041,0.0395135,-0.018132765,0.03007991,0.0069665816,0.012298835,0.0064183576,0.05780142,0.018556863,-0.01674669,-0.008750895,0.019705031,0.10823803,-0.0006571576,-0.023335721,-0.0029660985,0.007695823,0.008497471,0.0067597046,0.044850927,0.07195181,-0.035231147,0.014222791,0.0071062236,0.045843937,-0.028135266,-0.049691845,0.045843937,-0.036886163,-0.10145246,0.02532174,0.00886985,-0.06537312,0.08523331,-0.097480424,0.046216313,-0.015660586,-0.006320091,-0.029769596,-0.03965831,-0.014615857,-0.05978744,0.014626201,-0.010411083,0.057263542,0.029459279,0.004965047,-0.0894536,0.022156524,-0.034072634,0.079689,-0.06404911,-0.023873601,-0.0042849393,-0.07182768,0.060490824,-0.10534175,0.006340779,-0.007628588,-0.0082233595,0.012609151,-0.0086371135,0.01279534,-0.043113157,0.052505374,-0.034320887,0.04696107,-0.055649903,-0.09723217