INSERT INTO eu_items (reference, kind, url, identifier, title, status, start_date, deadline_date, metadata, embed_text, embedding, triage, triage_score, framework_programme, programme_period, programme_division, programme_part, mission_group, created_at, updated_at) VALUES ('50871369TOPICSen', 'non-horizon-topic', 'https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/DIGITAL-2026-AI-PILOTING-10-SCREENING', '50871369', 'Apply AI: Piloting AI-based image screening in medical centres', 'Open', '2026-04-21T00:00:00.000+0000', '2026-10-01T00:00:00.000+0000', '{"url": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/DIGITAL-2026-AI-PILOTING-10-SCREENING", "tags": ["Digital", "Digital Europe", "GenAI", "Medical", "Medical imaging devices"], "title": "Apply AI: Piloting AI-based image screening in medical centres", "ccm2Id": "50871369", "status": "31094502", "esST_URL": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/DIGITAL-2026-AI-PILOTING-10-SCREENING", "keywords": ["DIGITAL-2026-AI-PILOTING-10-SCREENING", "DIGITAL-2026-AI-PILOTING-10", "Artificial Intelligence & Decision support", "Artificial intelligence", "Artificial intelligence, intelligent systems, multi agent systems", "Biomedical software", "Cloud Services", "Cloud, Edge and Virtualisation", "Health and Ecosystem Services", "Health care", "Health data", "Health information", "Health sciences", "Healthy lifestyle", "Technological innovation", "eHealth"], "language": "en", "REFERENCE": "50871369TOPICSen", "callTitle": "AI Continent", "startDate": "2026-04-21T00:00:00.000+0000", "DATASOURCE": "SEDIA", "callccm2Id": "50871398", "identifier": "DIGITAL-2026-AI-PILOTING-10-SCREENING", "es_SortDate": "2026-04-21T00:00:00.000+0000", "deadlineDate": "2026-10-01T00:00:00.000+0000", "deadlineModel": "single-stage", "typesOfAction": "DIGITAL Simple Grants", "budgetOverview": "{\"budgetYearsColumns\":[\"2027\"],\"budgetTopicActionMap\":{\"113940\":[{\"action\":\"DIGITAL-2026-AI-PILOTING-10-SCREENING - DIGITAL-SIMPLE DIGITAL Simple Grants\",\"expectedGrants\":2,\"minContribution\":0,\"maxContribution\":0,\"budgetYearMap\":{\"2027\":\"9000000\"},\"plannedOpeningDate\":\"2026-04-21\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2026-10-01\"]}]}}", "es_ContentType": "text/plain", "descriptionByte": "Expected Impact:na Expected Outcome: Outcomes and deliverables One or more proofs-of-concept of replicable, scalable cloud-based AI/GenAI systems for analysis of medical imaging data in a healthcare setting, with demonstration of the role of the clinicians in validating AI/GenAI findings and reports showcasing seamless integration of the system into clinical workflows. Evidence-based analysis of (cost-)efficiency of the piloted solutions for healthcare systems for regulatory and HTA purposes. Two or more events or workshops organised per year and per project for the European network of AI-powered advanced screening centres. The agenda should include lessons learned from the project activities, as well as other items relevant to the network. Participant satisfaction rates should be measured for the events and workshops. Medical centres in the consortium joined the European network of AI-powered advanced screening centres under the Apply AI Strategy. A plan for obtaining regulatory approval for application of the AI/GenAI solutions in real life scenarios and clinical settings. This includes the required risk management and compliance activities, as well as clinical evaluation plans and post-market clinical follow-up. Detailed data protection and cybersecurity plan, with measures to secure sensitive health data, mitigate cybersecurity risks, and comply with EU legal and ethical frameworks. Sustainability plan for the uptake of the systems across the EU. Stakeholder engagement and dissemination report with measurable actions (KPIs). Scope: Each project awarded in this action should implement a scalable cloud-based AI/GenAI system running European trustworthy and safe AI/GenAI algorithms that were developed, trained and validated using very large sets of patient data. They should put in place a secure, privacy-preserving cloud environment required for the health data analysis tasks, with appropriate access and identification tools for authorised use only, and implement the whole system as described under this topic, seamlessly integrated in regular clinical workflows of the care settings involved. Interoperability and the need to communicate with the health IT infrastructure (e.g. the electronic health record (EHR) of the patient, Picture archiving and communication systems (PACS), Radiological Information Systems (RIS), etc.) need to be addressed. The projects should demonstrate the integration and large-scale validation of cloud-based AI/GenAI systems, following a thorough assessment and testing over a large number of patient test cases in real healthcare settings. The proposers are expected to choose the types of health data, the AI/GenAI algorithms that are trustworthy and secure, and the medical use cases, with the focus disease areas being cancer and cardiovascular. The projects should perform technical and clinical validation of the systems, generating evidence on AI systems’ performance and usability in different clinical settings. They shall use the AI systems for screening in clinical settings, perform local performance evaluation and post-deployment monitoring of the solutions, including evidence generation on cost-efficiency in view of regulatory requirements and health technology assessment (HTA). Whenever relevant, each project should deploy AI/GenAI solutions already tested and validated within the TEF for Health.", "programmePeriod": "2021 - 2027", "programmeDivision": "43152869", "frameworkProgramme": "43152860"}', 'Expected Impact:na Expected Outcome: Outcomes and deliverables One or more proofs-of-concept of replicable, scalable cloud-based AI/GenAI systems for analysis of medical imaging data in a healthcare setting, with demonstration of the role of the clinicians in validating AI/GenAI findings and reports showcasing seamless integration of the system into clinical workflows. Evidence-based analysis of (cost-)efficiency of the piloted solutions for healthcare systems for regulatory and HTA purposes. Two or more events or workshops organised per year and per project for the European network of AI-powered advanced screening centres. The agenda should include lessons learned from the project activities, as well as other items relevant to the network. Participant satisfaction rates should be measured for the events and workshops. Medical centres in the consortium joined the European network of AI-powered advanced screening centres under the Apply AI Strategy. A plan for obtaining regulatory approval for application of the AI/GenAI solutions in real life scenarios and clinical settings. This includes the required risk management and compliance activities, as well as clinical evaluation plans and post-market clinical follow-up. Detailed data protection and cybersecurity plan, with measures to secure sensitive health data, mitigate cybersecurity risks, and comply with EU legal and ethical frameworks. Sustainability plan for the uptake of the systems across the EU. Stakeholder engagement and dissemination report with measurable actions (KPIs). Scope: Each project awarded in this action should implement a scalable cloud-based AI/GenAI system running European trustworthy and safe AI/GenAI algorithms that were developed, trained and validated using very large sets of patient data. They should put in place a secure, privacy-preserving cloud environment required for the health data analysis tasks, with appropriate access and identification tools for authorised use only, and implement the whole system as described under this topic, seamlessly integrated in regular clinical workflows of the care settings involved. Interoperability and the need to communicate with the health IT infrastructure (e.g. the electronic health record (EHR) of the patient, Picture archiving and communication systems (PACS), Radiological Information Systems (RIS), etc.) need to be addressed. The projects should demonstrate the integration and large-scale validation of cloud-based AI/GenAI systems, following a thorough assessment and testing over a large number of patient test cases in real healthcare settings. The proposers are expected to choose the types of health data, the AI/GenAI algorithms that are trustworthy and secure, and the medical use cases, with the focus disease areas being cancer and cardiovascular. The projects should perform technical and clinical validation of the systems, generating evidence on AI systems’ performance and usability in different clinical settings. They shall use the AI systems for screening in clinical settings, perform local performance evaluation and post-deployment monitoring of the solutions, including evidence generation on cost-efficiency in view of regulatory requirements and health technology assessment (HTA). Whenever relevant, each project should deploy AI/GenAI solutions already tested and validated within the TEF for Health.', '[0.03609364,-0.02040345,0.0043282392,-0.003821771,-0.033116847,0.040579505,-0.012144911,0.031008283,-0.043411598,0.0057675405,0.035266753,0.024145117,0.04456924,0.056062974,-0.01402608,-0.04136505,0.016734136,0.005591827,-0.029354507,-0.028176192,-0.013984735,0.075081386,-0.055856254,-0.03938052,-0.009178451,-0.0011053161,0.01997967,-0.042067904,0.041220345,0.05192854,-0.031256348,-0.028279554,0.006005271,0.040930934,0.030057361,-0.04403176,0.007240434,-0.06834225,-0.0897173,0.067515366,0.076652475,-0.037974812,0.013478267,-0.041158326,0.060197413,-0.09244603,0.025240742,-0.0020465467,0.0065117395,-0.020723868,0.0015865904,0.0463057,-0.051432405,0.027907455,0.082812786,-0.000955