INSERT INTO eu_items (reference, kind, url, identifier, title, status, start_date, deadline_date, metadata, embed_text, embedding, triage, triage_score, framework_programme, programme_period, programme_division, programme_part, mission_group, created_at, updated_at) VALUES ('50131847TOPICSen', 'horizon-topic', 'https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL4-2027-04-DIGITAL-EMERGING-11', '50131847', 'EU Frontier AI Initiative:  Developing frontier AI solutions that are safe and computationally efficient within Apply AI (RIA)', 'Forthcoming', '2026-11-17T00:00:00.000+0000', '2027-03-18T00:00:00.000+0000', '{"url": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL4-2027-04-DIGITAL-EMERGING-11", "tags": ["Frugal AI", "Generative AI", "Safe AI"], "title": "EU Frontier AI Initiative:  Developing frontier AI solutions that are safe and computationally efficient within Apply AI (RIA)", "ccm2Id": "50131847", "status": "31094501", "esST_URL": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL4-2027-04-DIGITAL-EMERGING-11", "keywords": ["HORIZON-CL4-2027-04-DIGITAL-EMERGING-11", "HORIZON-CL4-2027-04", "Artificial intelligence, intelligent systems, multi agent systems"], "language": "en", "REFERENCE": "50131847TOPICSen", "callTitle": "DIGITAL", "startDate": "2026-11-17T00:00:00.000+0000", "DATASOURCE": "SEDIA", "callccm2Id": "50132073", "identifier": "HORIZON-CL4-2027-04-DIGITAL-EMERGING-11", "es_SortDate": "2026-11-17T00:00:00.000+0000", "deadlineDate": "2027-03-18T00:00:00.000+0000", "deadlineModel": "single-stage", "typesOfAction": "HORIZON  Research and Innovation Actions", "budgetOverview": "{\"budgetYearsColumns\":[\"2027\"],\"budgetTopicActionMap\":{\"112913\":[{\"action\":\"HORIZON-CL4-2027-04-DIGITAL-EMERGING-04 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":3,\"minContribution\":14000000,\"maxContribution\":14000000,\"budgetYearMap\":{\"2027\":\"42000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112912\":[{\"action\":\"HORIZON-CL4-2027-04-HUMAN-07 - HORIZON-CSA HORIZON Coordination and Support Actions\",\"expectedGrants\":1,\"minContribution\":7000000,\"maxContribution\":7000000,\"budgetYearMap\":{\"2027\":\"7000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112915\":[{\"action\":\"HORIZON-CL4-2027-04-DATA-08 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":2,\"minContribution\":19000000,\"maxContribution\":19000000,\"budgetYearMap\":{\"2027\":\"38000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112914\":[{\"action\":\"HORIZON-CL4-2027-04-DIGITAL-EMERGING-05 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":1,\"minContribution\":18000000,\"maxContribution\":18000000,\"budgetYearMap\":{\"2027\":\"18000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112917\":[{\"action\":\"HORIZON-CL4-2027-04-DIGITAL-EMERGING-10 - HORIZON-CSA HORIZON Coordination and Support Actions\",\"expectedGrants\":1,\"minContribution\":4000000,\"maxContribution\":4000000,\"budgetYearMap\":{\"2027\":\"4000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112916\":[{\"action\":\"HORIZON-CL4-2027-04-DATA-03 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":2,\"minContribution\":17500000,\"maxContribution\":17500000,\"budgetYearMap\":{\"2027\":\"35000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112918\":[{\"action\":\"HORIZON-CL4-2027-04-DIGITAL-EMERGING-11 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":1,\"minContribution\":44000000,\"maxContribution\":44000000,\"budgetYearMap\":{\"2027\":\"44000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112909\":[{\"action\":\"HORIZON-CL4-2027-04-HUMAN-02 - HORIZON-CSA HORIZON Coordination and Support Actions\",\"expectedGrants\":1,\"minContribution\":3000000,\"maxContribution\":3000000,\"budgetYearMap\":{\"2027\":\"3000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112908\":[{\"action\":\"HORIZON-CL4-2027-04-DATA-09 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":3,\"minContribution\":10000000,\"maxContribution\":10000000,\"budgetYearMap\":{\"2027\":\"39000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112911\":[{\"action\":\"HORIZON-CL4-2027-04-HUMAN-01 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":8,\"minContribution\":4800000,\"maxContribution\":5600000,\"budgetYearMap\":{\"2027\":\"39000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112910\":[{\"action\":\"HORIZON-CL4-2027-04-DIGITAL-EMERGING-06 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":2,\"minContribution\":1500000,\"maxContribution\":1500000,\"budgetYearMap\":{\"2027\":\"3000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}]}}", "es_ContentType": "text/plain", "descriptionByte": "Expected Outcome: The Apply AI Strategy[1] also seeks to bolster EU capabilities and achieve excellence in AI to support the development of European frontier models. As part of the Frontier AI Initiative, which brings together Europe’s leading actors in the field, this topic will support the development of sovereign frontier AI ensuring safety by design. This topic directly contributes to the Apply AI Strategy. Project results are expected to contribute to all of the following expected outcomes: Strengthened European capabilities in the development of frontier AI models. Improved computational efficiency of frontier AI models, resulting in reduced computational costs. Enhanced safety of advanced AI systems based on frontier AI models through the development and implementation of safe-by-design principles and/or AI agents acting as safety evaluators. Scope: To advance developments of frontier AI models towards highest-level performance, while ensuring energy efficiency, addressing computational constraints, and strengthening safety. The approach of this topic is twofold. First, it aims to advance the AI field through the development and training of a frontier AI model. The AI model should demonstrate state-of-the-art performance, have multimodal capabilities, and be optimized for agentic AI capabilities such as tool use, reasoning, and autonomous problem-solving. Second, this topic supports research on comprehensive methods to reduce the computational demands of frontier AI models and to ensure their safety, including technical methodologies such as automated testing and interpretability. The primary drivers behind computational efficient AI systems are the urgent challenges posed by the growing energy footprint of AI and current computational limitations. Modern AI models, especially frontier AI models, require substantial computational resources, with a significant impact in the environment. Additionally, they create barriers to entry to those interested in advancing the AI field. Key research areas include compression and distillation techniques aimed at reducing the complexity of large AI models. Innovations in AI architectures are also relevant, with a focus on innovative models that significantly lower computational demands for training and inference. Further, algorithmic approaches aimed at minimizing computational load during pre-training, post-training, and inference can also be considered. Ensuring the safety of AI systems is essential, especially as AI models become increasingly sophisticated and pervasive. Potential research areas to be considered include addressing misalignment, particularly the unintentional misalignment of large AI models. Work in this area could explore methods to detect and mitigate sophisticated misbehaviour, such as alignment faking, reward hacking of human oversight, and encoded reasoning in chain-of-thought (CoT). Additionally, research could focus on enhancing robustness against adversarial attacks, jailbreaks, and backdoors. Further potential areas for innovation include advancing AI models transparency and interpretability. Safety research could also consider risks that may arise when embedding frontier models within agentic AI frameworks, significantly contributing to the trust and safe adoption of powerful AI solutions. This topic contributes to the EU Frontier AI initiative. The project should establish strong links with the Resource for AI Science in Europe (RAISE), ensuring that its priorities inform the research topics addressed. Activities are expected to involve the European AI research community and attract and retain top AI talent working on frontier models and related areas. All proposals are expected to incorporate mechanisms for assessing and demonstrating progress, including qualitative and quantitative KPIs, benchmarking, and progress monitoring. When possible, proposals should build on and reuse public results from relevant previous funded actions. Communicable results should be shared with the European R&D community through the AI-on-demand platform. The project selected in this topic should link to the resources offered by the AI Factories and the Data Labs. Where relevant, it could also establish links with European companies developing frontier AI models. All proposals are expected to allocate tasks for cohesion activities with the European Partnership on AI, data, and robotics (ADRA) and the CSA HORIZON-CL4-2025-03-HUMAN-18: GenAI4EU central Hub. null Activities are expected to start at TRL 2 and achieve TRL 4 by the end of the project – see General Annex B. [1] COM(2025)723 Apply AI Strategy", "programmePeriod": "2021 - 2027", "programmeDivision": ["43108541", "43120193", "43120203", "43120218", "43108390"], "destinationDetails": "Leadership in frontier technologies such as Artificial Intelligence, Quantum, Photonics and Semiconductors is essential to Europe’s economic security and global competitiveness. Building on the ambition of becoming the “AI Continent” and in line with the concrete actions devised in the Apply AI Strategy[1], the EU will consolidate its world-class research ecosystem through initiatives like the RAISE network of AI science labs, the development of safe and efficient frontier AI models, and the deployment of next-generation AI agents and robotics in strategic sectors. In parallel, a long-term quantum strategy will reinforce Europe’s excellence across quantum computing, sensing and communication, supported by new infrastructures and standardisation to secure technological sovereignty. Photonics and semiconductor technologies will remain critical enablers for the digital and green transitions, with investments in advanced integrated photonic devices and resilient semiconductor ecosystems ensuring Europe’s capacity to innovate, scale and compete globally. Foresight and support to emerging materials and technologies will further strengthen Europe’s position at the cutting edge to make sure Europe’s does not miss the emergence of new disruptive technologies, aligning with the Draghi report and the Competitiveness Compass to secure a cohesive, sovereign and future-proof European industrial base. Legal entities established in China are not eligible to participate in both Research and Innovation Actions (RIAs) and Innovation Actions (IAs) falling under this destination. For additional information please see “Restrictions on the participation of legal entities established in China” found in General Annex B of the General Annexes. [1] COM(2025)723 Apply AI Strategy", "frameworkProgramme": "43108390", "destinationDescription": "Achieving open strategic autonomy in digital and emerging enabling technologies (2026-27)"}', 'Expected Outcome: The Apply AI Strategy[1] also seeks to bolster EU capabilities and achieve excellence in AI to support the development of European frontier models. As part of the Frontier AI Initiative, which brings together Europe’s leading actors in the field, this topic will support the development of sovereign frontier AI ensuring safety by design. This topic directly contributes to the Apply AI Strategy. Project results are expected to contribute to all of the following expected outcomes: Strengthened European capabilities in the development of frontier AI models. Improved computational efficiency of frontier AI models, resulting in reduced computational costs. Enhanced safety of advanced AI systems based on frontier AI models through the development and implementation of safe-by-design principles and/or AI agents acting as safety evaluators. Scope: To advance developments of frontier AI models towards highest-level performance, while ensuring energy efficiency, addressing computational constraints, and strengthening safety. The approach of this topic is twofold. First, it aims to advance the AI field through the development and training of a frontier AI model. The AI model should demonstrate state-of-the-art performance, have multimodal capabilities, and be optimized for agentic AI capabilities such as tool use, reasoning, and autonomous problem-solving. Second, this topic supports research on comprehensive methods to reduce the computational demands of frontier AI models and to ensure their safety, including technical methodologies such as automated testing and interpretability. The primary drivers behind computational efficient AI systems are the urgent challenges posed by the growing energy footprint of AI and current computational limitations. Modern AI models, especially frontier AI models, require substantial computational resources, with a significant impact in the environment. Additionally, they create barriers to entry to those interested in advancing the AI field. Key research areas include compression and distillation techniques aimed at reducing the complexity of large AI models. Innovations in AI architectures are also relevant, with a focus on innovative models that significantly lower computational demands for training and inference. Further, algorithmic approaches aimed at minimizing computational load during pre-training, post-training, and inference can also be considered. Ensuring the safety of AI systems is essential, especially as AI models become increasingly sophisticated and pervasive. Potential research areas to be considered include addressing misalignment, particularly the unintentional misalignment of large AI models. Work in this area could explore methods to detect and mitigate sophisticated misbehaviour, such as alignment faking, reward hacking of human oversight, and encoded reasoning in chain-of-thought (CoT). Additionally, research could focus on enhancing robustness against adversarial attacks, jailbreaks, and backdoors. Further potential areas for innovation include advancing AI models transparency and interpretability. Safety research could also consider risks that may arise when embedding frontier models within agentic AI frameworks, significantly contributing to the trust and safe adoption of powerful AI solutions. This topic contributes to the EU Frontier AI initiative. The project should establish strong links with the Resource for AI Science in Europe (RAISE), ensuring that its priorities inform the research topics addressed. Activities are expected to involve the European AI research community and attract and retain top AI talent working on frontier models and related areas. All proposals are expected to incorporate mechanisms for assessing and demonstrating progress, including qualitative and quantitative KPIs, benchmarking, and progress monitoring. When possible, proposals should build on and reuse public results from relevant previous funded actions. Communicable results should be shared with the European R&D community through the AI-on-demand platform. The project selected in this topic should link to the resources offered by the AI Factories and the Data Labs. Where relevant, it could also establish links with European companies developing frontier AI models. All proposals are expected to allocate tasks for cohesion activities with the European Partnership on AI, data, and robotics (ADRA) and the CSA HORIZON-CL4-2025-03-HUMAN-18: GenAI4EU central Hub. null Activities are expected to start at TRL 2 and achieve TRL 4 by the end of the project – see General Annex B. [1] COM(2025)723 Apply AI Strategy', '[0.054251783,0.0018247225,0.05702602,0.048086807,-0.09758275,0.04804277,0.005928284,0.008741054,-0.03540457,0.00893371,0.020212311,0.0025595655,0.08771879,0.018263739,0.03247621,0.024703937,0.05803884,-0.025914913,-0.038487058,-0.036747657,0.030648734,0.071954064,-0.026707552,-0.001854997,-0.009247463,0.012186835,-0.0044255713,0.0010279545,0.014972082,0.10401194,-0.0047998736,0.024263581,-0.031199178,0.093179196,0.027191944,-0.06019658,0.054119676,-0.017416054,-0.089039855,0.067066126,-0.016711487,-0.05011244,0.027500194,-0.045532744,0.070324756,-0.026267197,-0.025078239,-0.0075410856,0.02278839,-0.036065105,0.0076676877,0.014906029,-0.048174877,-0.0070897215,0.010601556,0.0103923865,0.006115435,0.050861046,-0.009605251,0.06821105,-0.0075135636,-0.051961932,-0.012252888,-0.07204214,0.050949115,-0.10163402,-0.021137057,0.049055588,0.008658487,-0.03423763,0.017228903,-0.016887628,-0.05561688,0.034083504,-0.08076117,0.054912314,-0.07296689,-0.102426656,0.06794684