INSERT INTO eu_items (reference, kind, url, identifier, title, status, start_date, deadline_date, metadata, embed_text, embedding, triage, triage_score, framework_programme, programme_period, programme_division, programme_part, mission_group, created_at, updated_at) VALUES ('50131779TOPICSen', 'horizon-topic', 'https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL4-2027-04-DIGITAL-EMERGING-06', '50131779', 'International cooperation in AI (IA)', 'Forthcoming', '2026-11-17T00:00:00.000+0000', '2027-03-18T00:00:00.000+0000', '{"url": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL4-2027-04-DIGITAL-EMERGING-06", "tags": ["GenAI", "international cooperation"], "title": "International cooperation in AI (IA)", "ccm2Id": "50131779", "status": "31094501", "esST_URL": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL4-2027-04-DIGITAL-EMERGING-06", "keywords": ["HORIZON-CL4-2027-04-DIGITAL-EMERGING-06", "HORIZON-CL4-2027-04", "Artificial intelligence, intelligent systems, multi agent systems"], "language": "en", "REFERENCE": "50131779TOPICSen", "callTitle": "DIGITAL", "startDate": "2026-11-17T00:00:00.000+0000", "DATASOURCE": "SEDIA", "callccm2Id": "50132073", "identifier": "HORIZON-CL4-2027-04-DIGITAL-EMERGING-06", "es_SortDate": "2026-11-17T00:00:00.000+0000", "deadlineDate": "2027-03-18T00:00:00.000+0000", "deadlineModel": "single-stage", "typesOfAction": "HORIZON Innovation Actions", "budgetOverview": "{\"budgetYearsColumns\":[\"2027\"],\"budgetTopicActionMap\":{\"112913\":[{\"action\":\"HORIZON-CL4-2027-04-DIGITAL-EMERGING-04 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":3,\"minContribution\":14000000,\"maxContribution\":14000000,\"budgetYearMap\":{\"2027\":\"42000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112912\":[{\"action\":\"HORIZON-CL4-2027-04-HUMAN-07 - HORIZON-CSA HORIZON Coordination and Support Actions\",\"expectedGrants\":1,\"minContribution\":7000000,\"maxContribution\":7000000,\"budgetYearMap\":{\"2027\":\"7000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112915\":[{\"action\":\"HORIZON-CL4-2027-04-DATA-08 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":2,\"minContribution\":19000000,\"maxContribution\":19000000,\"budgetYearMap\":{\"2027\":\"38000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112914\":[{\"action\":\"HORIZON-CL4-2027-04-DIGITAL-EMERGING-05 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":1,\"minContribution\":18000000,\"maxContribution\":18000000,\"budgetYearMap\":{\"2027\":\"18000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112917\":[{\"action\":\"HORIZON-CL4-2027-04-DIGITAL-EMERGING-10 - HORIZON-CSA HORIZON Coordination and Support Actions\",\"expectedGrants\":1,\"minContribution\":4000000,\"maxContribution\":4000000,\"budgetYearMap\":{\"2027\":\"4000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112916\":[{\"action\":\"HORIZON-CL4-2027-04-DATA-03 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":2,\"minContribution\":17500000,\"maxContribution\":17500000,\"budgetYearMap\":{\"2027\":\"35000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112918\":[{\"action\":\"HORIZON-CL4-2027-04-DIGITAL-EMERGING-11 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":1,\"minContribution\":44000000,\"maxContribution\":44000000,\"budgetYearMap\":{\"2027\":\"44000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112909\":[{\"action\":\"HORIZON-CL4-2027-04-HUMAN-02 - HORIZON-CSA HORIZON Coordination and Support Actions\",\"expectedGrants\":1,\"minContribution\":3000000,\"maxContribution\":3000000,\"budgetYearMap\":{\"2027\":\"3000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112908\":[{\"action\":\"HORIZON-CL4-2027-04-DATA-09 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":3,\"minContribution\":10000000,\"maxContribution\":10000000,\"budgetYearMap\":{\"2027\":\"39000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112911\":[{\"action\":\"HORIZON-CL4-2027-04-HUMAN-01 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":8,\"minContribution\":4800000,\"maxContribution\":5600000,\"budgetYearMap\":{\"2027\":\"39000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}],\"112910\":[{\"action\":\"HORIZON-CL4-2027-04-DIGITAL-EMERGING-06 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":2,\"minContribution\":1500000,\"maxContribution\":1500000,\"budgetYearMap\":{\"2027\":\"3000000\"},\"plannedOpeningDate\":\"2026-11-17\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-03-18\"]}]}}", "es_ContentType": "text/plain", "descriptionByte": "Expected Outcome: Project results are expected to contribute to one of the following outcomes: Faster uptake of tailored and enhanced AI solutions at innovation hubs in low- and middle-income countries by training and optimising them with local data and applied research. Easier large-scale deployment of local AI solutions in low and middle-income countries by increasing the efficiency of system demonstration in relevant, operational environments. Strengthened local innovation ecosystems that foster sustainable socio-economic impact by addressing key societal challenges in areas such as education, healthcare, agriculture, and environmental sustainability. Scope: System prototype, testing, validation, and demonstration in operational environment aligned to EU initiatives, such as the International Digital Strategy for the EU[1] and the AI Continent Action Plan[2], to strengthen local AI ecosystems in African countries fostering responsible AI development, north-south digital cooperation on AI, and sustainable AI innovation. The main goal is to support the digital transition and foster inclusive economic and social transformation of partners globally by adapting and applying innovative solutions, research areas and capabilities developed in Europe to low- and middle-income countries. This Innovation Action will focus on accelerating the uptake of and access to AI solutions by local innovation hubs in these countries, better enabling their practical implementation and future market deployment in operational environments. Proposals should consider synergies and complementarity of ongoing research and innovation activities in the policy areas of international partnerships, digital and infrastructure like the Digital for Development Hub[3] and AI for Public Good[4], and may follow an approach like Living Labs. Proposals should also support the European Union’s Global Gateway strategy to boost smart, clean, and secure connections in digital, energy and transport sectors, and to strengthen health, education and research systems across the world. Proposals should enable AI technologies that are locally relevant and sustainable, empower local communities and platforms, and reflect the EU’s emphasis on sustainable and resilient global partnerships. The proposals must support digital partnerships and international digital cooperation to promote an approach to AI that enhances human well-being and societal progress through: Support for gathering of and access to local data in line with EU’s data strategy for the training and optimisation of existing AI algorithms developed in initiatives like AI for Public Good and GenAI for Africa. Establishment and support of Living Labs within local innovation hubs in low-income countries, fostering co-creation spaces where community members, researchers, entrepreneurs, and policymakers can collaboratively tailor, enhance, test, and iterate AI-driven solutions. These Living Labs will serve as platforms for experiential learning, inclusive participation, and sustainable technology adoption. Tailored and contextualized AI-based solutions developed through a bottom-up approach, driven by the specific needs of low-income communities. These solutions will be trained and adapted using local data sources, enabling meaningful knowledge transfer and empowering local stakeholders with relevant and actionable technologies. Contribution, where possible, to solving global sustainable development challenges, especially climate and agriculture, biodiversity, health and humanitarian needs, education. Fostering an enabling innovation environment with reinforced talent pipelines and technological transfer of AI algorithms and solutions to local innovation hub. Full testing and validation of the solutions in real-life with scenarios and initial support to large-scale deployment in low and middle-income countries. Capitalise from existing EU initiatives like the call GenAI for Africa from HE WP25, the Global Gateway, and Smart Africa to up-scale the deployment of solutions in low-income countries. Beneficiaries that intend to transfer ownership or grant an exclusive licence must formally notify the granting authority (i.e. DG-CNECT and HaDEA) before the intended transfer or licensing takes place and the granting authority may up to four years after the end of the action object to a transfer of ownership or the exclusive licensing of results. null Activities are expected to start at TRL 5 and achieve TRL 7 by the end of the project – see General Annex B. [1] https://eur-lex.europa.eu/legal-content/EN/TXT/?uri=celex:52025JC0140 [2] https://eur-lex.europa.eu/legal-content/EN/TXT/?uri=CELEX:52025DC0165 [3] https://d4dhub.eu/ [4] https://digital-strategy.ec.europa.eu/en/factpages/ai-public-good", "programmePeriod": "2021 - 2027", "programmeDivision": ["43108390", "43108541", "43120193", "43120203"], "destinationDetails": "Leadership in frontier technologies such as Artificial Intelligence, Quantum, Photonics and Semiconductors is essential to Europe’s economic security and global competitiveness. Building on the ambition of becoming the “AI Continent” and in line with the concrete actions devised in the Apply AI Strategy[1], the EU will consolidate its world-class research ecosystem through initiatives like the RAISE network of AI science labs, the development of safe and efficient frontier AI models, and the deployment of next-generation AI agents and robotics in strategic sectors. In parallel, a long-term quantum strategy will reinforce Europe’s excellence across quantum computing, sensing and communication, supported by new infrastructures and standardisation to secure technological sovereignty. Photonics and semiconductor technologies will remain critical enablers for the digital and green transitions, with investments in advanced integrated photonic devices and resilient semiconductor ecosystems ensuring Europe’s capacity to innovate, scale and compete globally. Foresight and support to emerging materials and technologies will further strengthen Europe’s position at the cutting edge to make sure Europe’s does not miss the emergence of new disruptive technologies, aligning with the Draghi report and the Competitiveness Compass to secure a cohesive, sovereign and future-proof European industrial base. Legal entities established in China are not eligible to participate in both Research and Innovation Actions (RIAs) and Innovation Actions (IAs) falling under this destination. For additional information please see “Restrictions on the participation of legal entities established in China” found in General Annex B of the General Annexes. [1] COM(2025)723 Apply AI Strategy", "frameworkProgramme": "43108390", "destinationDescription": "Achieving open strategic autonomy in digital and emerging enabling technologies (2026-27)"}', 'Expected Outcome: Project results are expected to contribute to one of the following outcomes: Faster uptake of tailored and enhanced AI solutions at innovation hubs in low- and middle-income countries by training and optimising them with local data and applied research. Easier large-scale deployment of local AI solutions in low and middle-income countries by increasing the efficiency of system demonstration in relevant, operational environments. Strengthened local innovation ecosystems that foster sustainable socio-economic impact by addressing key societal challenges in areas such as education, healthcare, agriculture, and environmental sustainability. Scope: System prototype, testing, validation, and demonstration in operational environment aligned to EU initiatives, such as the International Digital Strategy for the EU[1] and the AI Continent Action Plan[2], to strengthen local AI ecosystems in African countries fostering responsible AI development, north-south digital cooperation on AI, and sustainable AI innovation. The main goal is to support the digital transition and foster inclusive economic and social transformation of partners globally by adapting and applying innovative solutions, research areas and capabilities developed in Europe to low- and middle-income countries. This Innovation Action will focus on accelerating the uptake of and access to AI solutions by local innovation hubs in these countries, better enabling their practical implementation and future market deployment in operational environments. Proposals should consider synergies and complementarity of ongoing research and innovation activities in the policy areas of international partnerships, digital and infrastructure like the Digital for Development Hub[3] and AI for Public Good[4], and may follow an approach like Living Labs. Proposals should also support the European Union’s Global Gateway strategy to boost smart, clean, and secure connections in digital, energy and transport sectors, and to strengthen health, education and research systems across the world. Proposals should enable AI technologies that are locally relevant and sustainable, empower local communities and platforms, and reflect the EU’s emphasis on sustainable and resilient global partnerships. The proposals must support digital partnerships and international digital cooperation to promote an approach to AI that enhances human well-being and societal progress through: Support for gathering of and access to local data in line with EU’s data strategy for the training and optimisation of existing AI algorithms developed in initiatives like AI for Public Good and GenAI for Africa. Establishment and support of Living Labs within local innovation hubs in low-income countries, fostering co-creation spaces where community members, researchers, entrepreneurs, and policymakers can collaboratively tailor, enhance, test, and iterate AI-driven solutions. These Living Labs will serve as platforms for experiential learning, inclusive participation, and sustainable technology adoption. Tailored and contextualized AI-based solutions developed through a bottom-up approach, driven by the specific needs of low-income communities. These solutions will be trained and adapted using local data sources, enabling meaningful knowledge transfer and empowering local stakeholders with relevant and actionable technologies. Contribution, where possible, to solving global sustainable development challenges, especially climate and agriculture, biodiversity, health and humanitarian needs, education. Fostering an enabling innovation environment with reinforced talent pipelines and technological transfer of AI algorithms and solutions to local innovation hub. Full testing and validation of the solutions in real-life with scenarios and initial support to large-scale deployment in low and middle-income countries. Capitalise from existing EU initiatives like the call GenAI for Africa from HE WP25, the Global Gateway, and Smart Africa to up-scale the deployment of solutions in low-income countries. Beneficiaries that intend to transfer ownership or grant an exclusive licence must formally notify the granting authority (i.e. DG-CNECT and HaDEA) before the intended transfer or licensing takes place and the granting authority may up to four years after the end of the action object to a transfer of ownership or the exclusive licensing of results. null Activities are expected to start at TRL 5 and achieve TRL 7 by the end of the project – see General Annex B. [1] https://eur-lex.europa.eu/legal-content/EN/TXT/?uri=celex:52025JC0140 [2] https://eur-lex.europa.eu/legal-content/EN/TXT/?uri=CELEX:52025DC0165 [3] https://d4dhub.eu/ [4] https://digital-strategy.ec.europa.eu/en/factpages/ai-public-good', '[0.021659078,-0.019390944,0.04078381,0.0065914304,-0.086252965,0.06938572,-0.01705892,0.008603999,-0.08033239,0.023746187,0.014950515,0.0081993565,0.0250879,0.041380126,0.003061448,0.0014708261,0.009535745,0.020274771,0.00777874,-0.012405519,0.004078381,0.07253768,-0.019731697,0.010861484,-0.010206602,-0.021531297,-0.0037163317,-0.043552425,0.018602954,0.031242741,-0.076754496,0.031732574,-0.04953689,0.058652017,-0.079395324,-0.012362925,-0.0179108,-0.040634733,-0.081823185,0.03784482,-0.023852672,-0.018826574,-0.010659163,-0.057587165,0.100607164,-0.011638827,-0.012437465,0.03959118,0.0057342253,-0.038100384,-0.012746272,0.062868826,-0.010781621,0.051879562,0.03230759,-0.04796091,-0.046768274,0.021605836,-0.045490455,0.026749069,-0.066574514,-0.0032158515,0.048046097,-0.032563157,0.044042256,-0.08178059,-0.03388357,-0.015216727,-0.036375325,0.005284325,-0.015152836,0.01956132,-0.0711