INSERT INTO eu_items (reference, kind, url, identifier, title, status, start_date, deadline_date, metadata, embed_text, embedding, triage, triage_score, framework_programme, programme_period, programme_division, programme_part, mission_group, created_at, updated_at) VALUES ('13409COMPETITIVE_CALLen', 'horizon-call', 'https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/competitive-calls-cs/13409', '13409', 'European Network of AI Excellence Centres: Expanding the European AI lighthouse (RIA)', 'Open', '2026-02-27T00:00:00.000+0000', '2026-05-31T23:59:00.000+0000', '{"url": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/competitive-calls-cs/44129190", "title": "European Network of AI Excellence Centres: Expanding the European AI lighthouse (RIA)", "budget": "240000", "caName": "ELIAS - European Lighthouse of AI for Sustainability - 2nd Open Call", "status": "31094502", "esST_URL": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/competitive-calls-cs/44129190", "language": "en", "REFERENCE": "13409COMPETITIVE_CALLen", "startDate": "2026-02-27T00:00:00.000+0000", "DATASOURCE": "SEDIA", "callccm2Id": "13409", "identifier": "HORIZON-CL4-2022-HUMAN-02-02", "description": "ELIAS is looking for projects based on AI applications that engage with the network in the categories “Methodology”, “Software/Tools”, “Benchmarks” relevant but not limited to the use cases of ELIAS (see list below) in the scope of AI for Sustainability. ELIAS is focused on 3 research spheres but applications are not limited to them as long as the proposals will address high-impact societal and economic challenges using machine learning. Use Cases: - AI for Building Optimization - AI for Monitoring the Virtual Infrastructure - Responsible, User-centric Advertising - Mitigating misinformed migrant perception in EU - AI for Forecasting of Vegetation State - Materials Discovery - Personalized co-piloting systems Your project will be evaluated within the following awarding criteria: EXCELLENCE: Ambition: Proposal goes beyond the state-of-the-art and leverages the results and expertise of ELIAS. Innovation: Level of innovation within the market. Technical soundness and feasibility: Is the overall approach appropriate, technically correct? IMPACT and SCOPE: Scope: How is the proposal addressing challenges that hamper deployment of sustainable AI? Market opportunity & competition: How is the proposal increasing the competitiveness of the company, also in comparison to the competition? IMPLEMENTATION: Team: Capability of the application and its team to manage, perform and succeed with the project. Resources: Sufficient resources (requested and owned) to perform the project.", "es_SortDate": "2026-02-27T00:00:00.000+0000", "deadlineDate": "2026-05-31T23:59:00.000+0000", "deadlineModel": "single-stage", "es_ContentType": "text/plain", "furtherInformation": "We are looking for SMEs, startups and NGO’s. Applicants, at the moment of applying, must be officially registered legal entities established in: Member States (MS) of the European Union (EU), including their overseas departments, or in The Horizon Europe Associated Countries. The EU Associated Countries participate in Horizon Europe under the same conditions as the EU Member States. A list with all eligible associated Countries can be found here. Legal entities established in any other country or region cannot receive funding in this open Call. The ELIAS partners, or their affiliates or employees, are NOT considered as eligible applicants and can NOT apply for funding. All the information regarding the call is available on our website: https://elias-ai.eu/opportunities/elias-2nd-open-call/ .", "esDA_FirstIngestDate": "2026-05-04T22:30:06.788+0200"}', 'ELIAS is looking for projects based on AI applications that engage with the network in the categories “Methodology”, “Software/Tools”, “Benchmarks” relevant but not limited to the use cases of ELIAS (see list below) in the scope of AI for Sustainability. ELIAS is focused on 3 research spheres but applications are not limited to them as long as the proposals will address high-impact societal and economic challenges using machine learning. Use Cases: - AI for Building Optimization - AI for Monitoring the Virtual Infrastructure - Responsible, User-centric Advertising - Mitigating misinformed migrant perception in EU - AI for Forecasting of Vegetation State - Materials Discovery - Personalized co-piloting systems Your project will be evaluated within the following awarding criteria: EXCELLENCE: Ambition: Proposal goes beyond the state-of-the-art and leverages the results and expertise of ELIAS. Innovation: Level of innovation within the market. Technical soundness and feasibility: Is the overall approach appropriate, technically correct? IMPACT and SCOPE: Scope: How is the proposal addressing challenges that hamper deployment of sustainable AI? Market opportunity & competition: How is the proposal increasing the competitiveness of the company, also in comparison to the competition? IMPLEMENTATION: Team: Capability of the application and its team to manage, perform and succeed with the project. Resources: Sufficient resources (requested and owned) to perform the project.

We are looking for SMEs, startups and NGO’s. Applicants, at the moment of applying, must be officially registered legal entities established in: Member States (MS) of the European Union (EU), including their overseas departments, or in The Horizon Europe Associated Countries. The EU Associated Countries participate in Horizon Europe under the same conditions as the EU Member States. A list with all eligible associated Countries can be found here. Legal entities established in any other country or region cannot receive funding in this open Call. The ELIAS partners, or their affiliates or employees, are NOT considered as eligible applicants and can NOT apply for funding. All the information regarding the call is available on our website: https://elias-ai.eu/opportunities/elias-2nd-open-call/ .', '[-0.016358372,0.07956679,0.07672365,0.007499304,-0.08273958,0.024166714,-0.013226795,-0.0035230247,-0.094936244,0.012165767,0.004527396,0.025238043,0.11553873,0.029853,0.0048827888,0.025856119,0.0373317,0.05682165,0.0015438987,-0.026845036,-0.0053875498,0.07977282,-0.030841919,-0.073756896,0.0056038755,-0.003242316,-0.014874994,-0.05298959,0.08916755,-0.00953895,-0.05051729,0.023775266,0.032963976,0.017491508,0.037846763,-0.009193858,0.03176903,-0.0315218,-0.07322123,0.068194225,-0.022786347,-0.0030156886,0.04553149,-0.04775656,0.036033746,-0.012989867,0.019088201,0.031212764,-0.06568072,-0.052701153,0.0003653722,-0.0018774014,-0.016770422,0.03516844,0.033685062,-0.0068709287,-0.036260374,0.033664457,-0.10260037,0.011465282,-0.04693246,-0.06840025,-0.02165321,-0.02579431,0.08644802,-0.09304082,0.01302077,0.04136979,0.0069533386,-0.006891531,-0.04054569,-0.043718472,-0.052289106,0.00049800065,-0.027401304,-0.033437833,-0.08154463,-0.06563952,0.014359931,-0.008580934,-0.06563952,-0.023177795,-0.03413832,0.038567852,0.02935854,-0.022539118,0.006278607,0.026721422,0.024022497,-0.034735788,-0.016564397,0.032963976,0.0042157834,-0.01434963,-0.003283521,0.050682113,-0.032902166,-0.0