INSERT INTO eu_items (reference, kind, url, identifier, title, status, start_date, deadline_date, metadata, embed_text, embedding, triage, triage_score, framework_programme, programme_period, programme_division, programme_part, mission_group, created_at, updated_at) VALUES ('50138610TOPICSen', 'horizon-topic', 'https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL6-2027-03-GOVERNANCE-04', '50138610', 'AI supporting informed advice for farmers and foresters to improve competitiveness and sustainability', 'Forthcoming', '2027-02-04T00:00:00.000+0000', '2027-05-11T00:00:00.000+0000', '{"url": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL6-2027-03-GOVERNANCE-04", "tags": ["Advice", "Advisors", "Advisory services", "Artificial intelligence", "Biomass", "Climate", "Data Retrieval", "Datasets", "Digital", "Environment", "Food Security", "Forestry", "Multimodal", "Zero Pollution"], "title": "AI supporting informed advice for farmers and foresters to improve competitiveness and sustainability", "ccm2Id": "50138610", "status": "31094501", "esST_URL": "https://ec.europa.eu/info/funding-tenders/opportunities/portal/screen/opportunities/topic-details/HORIZON-CL6-2027-03-GOVERNANCE-04", "keywords": ["HORIZON-CL6-2027-03-GOVERNANCE-04", "HORIZON-CL6-2027-03", "Agriculture related to crop production, soil biology and cultivation, applied plant biology", "Agriculture, Rural Development, Fisheries", "Artificial Intelligence & Decision support", "Artificial intelligence, intelligent systems, multi agent systems", "Digital data", "Digital skills", "Forestry", "Interaction, Multimodal, Brain-Computer-Interfaces, Assistive Technologies", "Start-up companies"], "language": "en", "REFERENCE": "50138610TOPICSen", "callTitle": "Call 03 - single stage (2027)", "startDate": "2027-02-04T00:00:00.000+0000", "DATASOURCE": "SEDIA", "callccm2Id": "50138823", "identifier": "HORIZON-CL6-2027-03-GOVERNANCE-04", "es_SortDate": "2027-02-04T00:00:00.000+0000", "deadlineDate": "2027-05-11T00:00:00.000+0000", "deadlineModel": "single-stage", "typesOfAction": "HORIZON Innovation Actions", "budgetOverview": "{\"budgetYearsColumns\":[\"2027\"],\"budgetTopicActionMap\":{\"113077\":[{\"action\":\"HORIZON-CL6-2027-03-GOVERNANCE-06 - HORIZON-CSA HORIZON Coordination and Support Actions\",\"expectedGrants\":1,\"minContribution\":4500000,\"maxContribution\":4500000,\"budgetYearMap\":{\"2027\":\"4500000\"},\"plannedOpeningDate\":\"2027-02-04\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-05-11\"]}],\"113079\":[{\"action\":\"HORIZON-CL6-2027-03-GOVERNANCE-05 - HORIZON-CSA HORIZON Coordination and Support Actions\",\"expectedGrants\":2,\"minContribution\":3500000,\"maxContribution\":3500000,\"budgetYearMap\":{\"2027\":\"7000000\"},\"plannedOpeningDate\":\"2027-02-04\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-05-11\"]}],\"113078\":[{\"action\":\"HORIZON-CL6-2027-03-GOVERNANCE-02 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":1,\"minContribution\":6000000,\"maxContribution\":6000000,\"budgetYearMap\":{\"2027\":\"6000000\"},\"plannedOpeningDate\":\"2027-02-04\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-05-11\"]}],\"113081\":[{\"action\":\"HORIZON-CL6-2027-03-GOVERNANCE-07 - HORIZON-CSA HORIZON Coordination and Support Actions\",\"expectedGrants\":1,\"minContribution\":4750000,\"maxContribution\":4750000,\"budgetYearMap\":{\"2027\":\"4750000\"},\"plannedOpeningDate\":\"2027-02-04\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-05-11\"]}],\"113080\":[{\"action\":\"HORIZON-CL6-2027-03-GOVERNANCE-03 - HORIZON-CSA HORIZON Coordination and Support Actions\",\"expectedGrants\":1,\"minContribution\":3000000,\"maxContribution\":3000000,\"budgetYearMap\":{\"2027\":\"3000000\"},\"plannedOpeningDate\":\"2027-02-04\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-05-11\"]}],\"113083\":[{\"action\":\"HORIZON-CL6-2027-03-GOVERNANCE-01 - HORIZON-RIA HORIZON  Research and Innovation Actions\",\"expectedGrants\":2,\"minContribution\":6000000,\"maxContribution\":6000000,\"budgetYearMap\":{\"2027\":\"12000000\"},\"plannedOpeningDate\":\"2027-02-04\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-05-11\"]}],\"113082\":[{\"action\":\"HORIZON-CL6-2027-03-GOVERNANCE-04 - HORIZON-IA HORIZON Innovation Actions\",\"expectedGrants\":2,\"minContribution\":5000000,\"maxContribution\":6000000,\"budgetYearMap\":{\"2027\":\"11800000\"},\"plannedOpeningDate\":\"2027-02-04\",\"deadlineModel\":\"single-stage\",\"deadlineDates\":[\"2027-05-11\"]}]}}", "es_ContentType": "text/plain", "descriptionByte": "Expected Outcome: Project results are expected to contribute to all of the following expected outcomes: innovative AI-based solutions provide advisors, farmers and foresters with comprehensive, tailored and impartial advice to farmers and foresters to support them in their decisions as well as on the selection of innovative solutions, boosting the competitiveness, sustainability and resilience of the EU agriculture and forestry sectors; capacity and skills of advisors, farmers, and foresters related to the effective use of AI solutions are improved; use of existing and new data relevant for the decision-making for the optimized management of operations and the selection of innovative solutions on farms and in forests is increased. Scope: Digital technologies hold the potential to revolutionise farming and forestry, offering new opportunities to meet the rising demand for food, as well as biomass, while taking care of the environment, climate and people. With the growing availability of datasets relevant for both the agricultural and forestry sector, artificial intelligence technologies offer significant opportunities to harness data, enhance access to tailored information, and develop effective tools to support advisors, farmers and foresters in their operations. Successful proposals should contribute to build a competitive and resilient agriculture and forestry sectors. Proposals should: develop, test, validate and pilot cost-effective AI-based solutions that make use of the various existing reliable and trustable knowledge reservoirs and provide contextual, effective and impartial advice for advisors, farmers and foresters; capitalise on standardised and comprehensive data collected from different sources (e.g. public and private databases, in-situ data generated during the project implementation) for the development of AI-based solutions capable of providing advice based on the interpretation of multimodal inputs (e.g. text, images, audio, video etc…) provided by the end user. By doing so, successful proposals should ensure the availability of curated datasets by connecting to and harvesting data from existing public and private data sources, making use of privacy-preserving techniques when needed. The curated datasets, to be released as outputs, should be interoperable to maximise reuse, in order to support information fusion and third-party usage of the data; involve advisors, farmers and foresters from across Europe in the co-development, testing, validation and piloting of the AI-based solutions; and improve end users’ awareness, understanding, competences and skills on the use, benefits, and risks of the developed AI-based solutions in view of improving the competitiveness and sustainability of EU agriculture and forestry; build on results and ensure synergies with other Horizon 2020/ Europe as well as other relevant EU-funded initiatives and projects (e.g. EU Missions, project that may follow from the topic HORIZON-CL6-2024-GOVERNANCE-02-01: European Partnership of Agriculture of Data, and the Common European Agriculture Data Space) and demonstrate adequate planning and use of resources for this purpose; ensure wide dissemination and uptake including by demonstrating tangible benefits and added value compared to existing solutions for farmers, forester and their advisors.​ Proposals must implement the multi-actor approach, with a consortium based on a balanced mix of relevant actors with complementary knowledge to achieve the objectives of the projects, seeking for the involvement of SMEs, start-ups, and including for instance relevant rural actors (in particular end-users of the AI-enabled solution), universities, research and technology organisations. The Joint Research Centre (JRC) may participate as member of the consortium selected for funding. The participation could involve sharing of information and contribution to dissemination of results. Proposals should develop diverse practice-oriented dissemination materials (e.g., audiovisual materials, brochures) presenting the AI-enabled solutions and other R&I results developed within the project and feed them into communication channels most consulted by the potential end-users. Proposals are encouraged to explore the application of data retrieval techniques (e.g., RAG) for the retrieval of up-to-date and context-specific information from external knowledge sources (e.g., market information, evolving regulation/legislative requirements). This topic should involve the effective contribution of social sciences and humanities (SSH) disciplines. By integrating relevant SSH expertise (e.g., legal expertise, gender expertise, education and behavioural sciences), the successful proposal aims to produce meaningful results that enhance the societal impact of related research activities, engaging advisors (e.g., including Advisory Networks), farmers, foresters, and other rural actors. The projects under this topic are relevant to the EU policies related to the policy ambition ''Sustaining our quality of life: Food security, water and nature'', the Vision for Agriculture and Food, as well as the objectives set out in the common agricultural policy, and the zero pollution action plan. null Activities are expected to achieve TRL 8 by the end of the project – see General Annex B.", "programmePeriod": "2021 - 2027", "programmeDivision": ["43108390", "43108541", "43121563", "43121578"], "destinationDetails": "This destination will support the EU Commission priorities ‘Sustaining our quality of life: food security, water and nature’ and ‘A new plan for Europe’s sustainable prosperity and competitiveness’, which require innovative and agile governance models and tools to support transformative change within planetary boundaries. R&I supporting decision-making is a key enabler for the Vision for Agriculture and Food that aims to secure the long-term competitiveness and sustainability of the EU''s farming and food systems within the boundaries of our planet, as well as to meet the objectives set out in the Common Agricultural Policy. Besides, the R&I supporting the bioeconomy, with a focus on bio-based solutions and the role of biotechnology, needs to be further strengthened, in line with the new EU Bioeconomy Strategy, the Communication on Biotechnology and Biomanufacturing and the Life Sciences Strategy. There is also a need to unlock the potential of applied digital and data technologies to support sectors covered by this cluster in becoming more competitive, sustainable, resilient and inclusive in line with the evolving EU policies on cyber, data and data technologies and digital services, notably the European Data Strategy, the Europe’s Digital Decade Policy Programme, the AI Continent Action Plan and the upcoming EU digital strategy for agriculture. This destination will contribute to the development, support and take up of digital and data-based solutions to implement the European Green Deal, while fostering innovation and supporting start-ups, thereby supporting the EU Competitiveness Compass. The destination supports the European Ocean Pact, aiming at bringing coherence across all EU policy areas linked to the ocean, supporting a resilient and healthy ocean and coastal areas and promoting the sustainable blue economy. In particular, land-sea connection areas are crucial for addressing the effects of climate change, such as sea level rise, coastal erosion, extreme events, and hydrological crises. When relevant, actions are encouraged to align with the EU Mission ‘Restore our Ocean and Waters’, leveraging its digital infrastructures (such as the Digital Twin Ocean), stakeholder networks, and knowledge systems to enhance governance, environmental observation, and policy-support tools across terrestrial and aquatic systems. This destination implements research actions to address water challenges in the EU and support the European Water Resilience Strategy by advancing the capacity for proper management of water sources. In line with the global approach on R&I, this destination will foster and support regional and international initiatives, encourage international cooperation, contribute substantially to the implementation of key international treaties and to the work of various international bodies, assessments and other initiatives, and help achieve international commitments, notably under the Paris Agreement, the Kunming-Montreal Global Biodiversity Framework (GBF), and the Biodiversity Beyond National Jurisdiction (BBNJ) Agreement. Knowledge and advice are key to improving competitiveness, sustainability and resilience. R&I actions under this destination will support effective Agriculture Knowledge and Innovation Systems (AKIS) that are at the heart of the 2023-2027 CAP’s cross-cutting objective as a key mean to bridge the gap between science and practice. Synergies with the EU-CAP Network, and particularly the EIP-AGRI Operational Groups supported by the CAP, will be further exploited. The European Research Area is further integrated, and the global efforts are well-coordinated for impact-oriented science on food, bioeconomy, natural resources, agriculture-forestry, aquaculture and fisheries, and environment. The Destination supports unlocking the unique assets for research and innovation of the EU outermost regions, in line with the EU strategy for outermost regions[1]. Expected Impact: Proposals for topics under this destination should set out credible pathways to \"developing innovative governance models and tools enabling sustainability and resilience\", and more specifically to one or several of the following expected impacts: improved evidence-based knowledge, tools and science-society-policy interfaces support effective policy mixes and multi-level governance that are capable of anticipating a changing world, enabling a just sustainable transition for all, engaging society at large and balancing economic, social and environmental goals; competitiveness, sustainability and resilience of the economy are supported by more accessible and interoperable environmental observations and improved Earth Intelligence; productivity is boosted and transformative changes required by the European Green Deal are facilitated, leaving no one behind, thanks to enhanced digital and data technologies, flows of existing and new knowledge, solutions and skills among actors and communities, as well as maximised synergies between initiatives. [1] COM(2022) Putting people first, securing sustainable and inclusive growth, unlocking the potential of the EU’s outermost regions.", "frameworkProgramme": "43108390", "destinationDescription": "Innovative governance, environmental observations and digital solutions in support of the Green Deal (2026-27)"}', 'Expected Outcome: Project results are expected to contribute to all of the following expected outcomes: innovative AI-based solutions provide advisors, farmers and foresters with comprehensive, tailored and impartial advice to farmers and foresters to support them in their decisions as well as on the selection of innovative solutions, boosting the competitiveness, sustainability and resilience of the EU agriculture and forestry sectors; capacity and skills of advisors, farmers, and foresters related to the effective use of AI solutions are improved; use of existing and new data relevant for the decision-making for the optimized management of operations and the selection of innovative solutions on farms and in forests is increased. Scope: Digital technologies hold the potential to revolutionise farming and forestry, offering new opportunities to meet the rising demand for food, as well as biomass, while taking care of the environment, climate and people. With the growing availability of datasets relevant for both the agricultural and forestry sector, artificial intelligence technologies offer significant opportunities to harness data, enhance access to tailored information, and develop effective tools to support advisors, farmers and foresters in their operations. Successful proposals should contribute to build a competitive and resilient agriculture and forestry sectors. Proposals should: develop, test, validate and pilot cost-effective AI-based solutions that make use of the various existing reliable and trustable knowledge reservoirs and provide contextual, effective and impartial advice for advisors, farmers and foresters; capitalise on standardised and comprehensive data collected from different sources (e.g. public and private databases, in-situ data generated during the project implementation) for the development of AI-based solutions capable of providing advice based on the interpretation of multimodal inputs (e.g. text, images, audio, video etc…) provided by the end user. By doing so, successful proposals should ensure the availability of curated datasets by connecting to and harvesting data from existing public and private data sources, making use of privacy-preserving techniques when needed. The curated datasets, to be released as outputs, should be interoperable to maximise reuse, in order to support information fusion and third-party usage of the data; involve advisors, farmers and foresters from across Europe in the co-development, testing, validation and piloting of the AI-based solutions; and improve end users’ awareness, understanding, competences and skills on the use, benefits, and risks of the developed AI-based solutions in view of improving the competitiveness and sustainability of EU agriculture and forestry; build on results and ensure synergies with other Horizon 2020/ Europe as well as other relevant EU-funded initiatives and projects (e.g. EU Missions, project that may follow from the topic HORIZON-CL6-2024-GOVERNANCE-02-01: European Partnership of Agriculture of Data, and the Common European Agriculture Data Space) and demonstrate adequate planning and use of resources for this purpose; ensure wide dissemination and uptake including by demonstrating tangible benefits and added value compared to existing solutions for farmers, forester and their advisors.​ Proposals must implement the multi-actor approach, with a consortium based on a balanced mix of relevant actors with complementary knowledge to achieve the objectives of the projects, seeking for the involvement of SMEs, start-ups, and including for instance relevant rural actors (in particular end-users of the AI-enabled solution), universities, research and technology organisations. The Joint Research Centre (JRC) may participate as member of the consortium selected for funding. The participation could involve sharing of information and contribution to dissemination of results. Proposals should develop diverse practice-oriented dissemination materials (e.g., audiovisual materials, brochures) presenting the AI-enabled solutions and other R&I results developed within the project and feed them into communication channels most consulted by the potential end-users. Proposals are encouraged to explore the application of data retrieval techniques (e.g., RAG) for the retrieval of up-to-date and context-specific information from external knowledge sources (e.g., market information, evolving regulation/legislative requirements). This topic should involve the effective contribution of social sciences and humanities (SSH) disciplines. By integrating relevant SSH expertise (e.g., legal expertise, gender expertise, education and behavioural sciences), the successful proposal aims to produce meaningful results that enhance the societal impact of related research activities, engaging advisors (e.g., including Advisory Networks), farmers, foresters, and other rural actors. The projects under this topic are relevant to the EU policies related to the policy ambition ''Sustaining our quality of life: Food security, water and nature'', the Vision for Agriculture and Food, as well as the objectives set out in the common agricultural policy, and the zero pollution action plan. null Activities are expected to achieve TRL 8 by the end of the project – see General Annex B.', '[0.044369604,0.01836818,0.025715454,0.02879515,-0.08521956,0.029961033,0.02897113,0.011559855,-0.031632867,-0.05358669,0.045051537,0.007121795,0.058294225,0.050419006,0.037088327,0.053190734,0.01666335,-0.0072152857,0.0036268907,-0.007182289,-0.022129808,0.06806126,-0.03282075,-0.0046827863,-0.023713652,0.027299296,0.030049024,-0.010971414,0.015431472,0.08161192,-0.04584346,0.029939035,-0.03818822,0.058822174,-0.025935432,0.0019536815,0.0413999,-0.061989862,-0.10118998,0.04181786,-0.04362168,-0.040322006,-0.016212394,-0.10814129,0.078884184,-0.019677052,-0.015387476,0.037814256,-0.032468785,0.017378278,-0.10066203,0.068853185,0.035460487,-0.003109942,0.030181011,-0.013539659,-0.03070896,0.031192912,-0.028553173,0.059526104,-0.026617365,-0.042741768,-0.05314674,-0.014661548,0.033876646,-0.06308975,-0.025231501,0.004152089,0.007809227,0.08068801,-0.010470963,-0.026771348,-0.08257982,0.01837918,-0.09230286,0.011878824,-0.085483536,-0.112452865,0.014584555,0.065993465,-0.034294605,-0.04725132,-0.002737354,0.002162661,0.018412177,-0.040607978,-0.016608356,0.077432334,0.0014202343,-0.013352677,-0.015915424,-0.0010414594,0.0034096